import type { AgentGuideCopy } from './info-page-i18n';

// Agent-guide copy extracted out of info-page-i18n.ts to keep that file
// under the 1 MiB changed-file blob guard. Same data, just hoisted here.
export const EN_AGENT_GUIDES: Record<string, AgentGuideCopy> = {
  'claude-code': {"title": "Claude Code for design — Open Design", "description": "How designers use Claude Code for UI and web design, and how Open Design turns it into a real design agent — local-first, BYOK, with a curated skill and design-system library.", "breadcrumb": "Claude Code", "label": "Agent · Claude Code", "heading": "Claude Code for design.", "lead": "Claude Code is Anthropic’s terminal coding agent. People already use it to build UIs, design systems, and landing pages. Open Design plugs it into a real design workflow — bring your Anthropic key or Claude subscription, keep every file local.", "tldrTitle": "TL;DR", "tldrBody": "Claude Code is a strong design generator once you give it taste — a design system, an aesthetic skill, a screenshot loop. Open Design ships exactly that as a local-first, open-source layer. Point Claude Code at it with your own key and start designing.", "toc": ["What is Claude Code", "Designing with Claude Code", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Claude Code into a local-first, open-source design agent — your Anthropic key or Claude subscription, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Claude Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code is widely regarded as the coding agent with the best frontend taste — it reasons about interfaces with unusual specificity, naming exact hex values, spacing, and type scales, and it refactors UI across a large codebase without losing the thread. But out of the box it still drifts toward a generic look unless you hand it a design system, skills, and real references. This is a practical, end-to-end guide to using Claude Code for UI, frontend, and design-system work, and to wiring it into a structured workflow with Open Design.", "It covers what Claude Code actually is, why it is strong at frontend, how to set it up from zero, the CLAUDE.md and Skills workflow, the official Figma round-trip, how it compares to Codex and Cursor, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code design feedback loop: terminal agent making specific design decisions, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Claude Code reasons out specific UI decisions in the terminal, renders and verifies them in a real browser, and converges against your references."}, "tocLabel": "On this page", "toc": [{"id": "what-is-claude-code", "label": "What Claude Code actually is"}, {"id": "why-design", "label": "Why Claude Code is good at design"}, {"id": "setup", "label": "Set up Claude Code for design (from zero)"}, {"id": "skills-workflow", "label": "The CLAUDE.md and Skills workflow"}, {"id": "figma", "label": "Claude Code + Figma round-trip"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "What Claude Code actually is", "blocks": [{"kind": "p", "text": "Claude Code is Anthropic’s agentic coding tool. It reads your codebase, edits files, runs commands, and integrates with your dev tools — planning, writing, and verifying work from natural-language tasks rather than just autocompleting lines."}, {"kind": "p", "text": "It ships across several surfaces that all share the same engine: a terminal CLI, IDE extensions for VS Code, Cursor, and JetBrains, a desktop app with visual diff review, and a web experience for long-running tasks. Your CLAUDE.md files, settings, and MCP servers carry across all of them."}, {"kind": "steps", "items": [{"label": "Instruction file", "body": "Claude Code reads a CLAUDE.md file in your project root at the start of every session — the natural place to encode your design conventions, tokens, and review checklists."}, {"label": "Skills", "body": "Agent Skills package repeatable instructions, scripts, and resources that Claude loads on demand, including Anthropic’s official Frontend Design skill for taste."}, {"label": "Plan and subagents", "body": "It can plan before acting and spawn subagents that work on different parts of a task in parallel, which keeps large UI refactors coherent."}]}, {"kind": "ul", "items": ["Vendor: Anthropic", "Credential: Anthropic API key (BYOK, via the Console) or a Claude subscription (Pro / Max)", "Surfaces: terminal CLI, VS Code / Cursor / JetBrains extensions, desktop app, web"]}]}, {"id": "why-design", "heading": "Why Claude Code is good at design", "blocks": [{"kind": "p", "text": "Among coding agents, Claude Code has a reputation for taste in frontend work. A few things explain it."}, {"kind": "steps", "items": [{"label": "Specific, not vague, decisions", "body": "Claude Code tends to commit to concrete choices — exact hex values, spacing scales, type ramps, and component hierarchy — instead of hand-waving, which is what separates a real interface from a placeholder."}, {"label": "Codebase-aware reasoning", "body": "With a large working context it refactors UI across many files at once, reusing your existing components and tokens rather than reinventing one-off styles."}, {"label": "An official frontend skill", "body": "Anthropic ships a Frontend Design skill that makes Claude write a design direction first and deliberately steers away from generic system fonts and predictable purple gradients."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one Anthropic makes about its own models: Claude does not have taste by default — left alone it converges on the statistical center of web design (Inter, purple gradients, soft shadows). It produces good design when you give it constraints. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Claude Code for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Claude Code that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure CLAUDE.md, add skill, verify", "caption": "The setup sequence: install → authenticate → configure CLAUDE.md → add the Frontend Design skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in CLAUDE.md and point Claude at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or Chrome MCP so Claude renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "skills-workflow", "heading": "The CLAUDE.md and Skills workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Claude Code is feeding it real references plus your design context, then iterating until the UI matches — with CLAUDE.md and Skills carrying the constraints so you do not re-explain them every prompt."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong agent.", "Keep your design system and conventions in CLAUDE.md, and tell Claude where the tokens and canonical primitives live.", "Add the Frontend Design skill so Claude commits to a real aesthetic direction before writing code.", "Wire browser verification so Claude renders, resizes to breakpoints, and compares back to the references — not merely confirms it builds."]}, {"kind": "p", "text": "Drop a reference image into the session and prompt with concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Run a dev server alongside, keep prompts small and focused, and commit good iterations / revert bad ones (telling Claude when you revert) so each pass builds on a clean base. Use plan mode for larger refactors so you can review the approach before any file changes."}]}, {"id": "figma", "heading": "Claude Code + Figma: design ↔ code round-trip", "blocks": [{"kind": "p", "text": "In February 2026 Anthropic and Figma shipped a first-class, bidirectional integration via the Figma MCP server. It works in both directions."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Select a frame in Figma or paste a link into Claude Code, pull the design context, and ask it to implement the design using your existing component library. Code Connect keeps output aligned with your real components."}, {"label": "Code → Design", "body": "Build and preview a feature in the browser, then say “Send this to Figma” to capture the running UI as editable Figma layers — entire screen or a selected element."}]}, {"kind": "p", "text": "Install it once with claude plugin install figma@claude-plugins-official (Dev Mode MCP requires a paid Figma plan). The same Figma MCP is available to Claude Code, Codex, Cursor, and VS Code — exactly the kind of portable, multi-agent capability Open Design is built to orchestrate."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX reasoning", "Frontend reasoning and large-context refactors"], ["Codex", "Strong visual polish and image understanding; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all three default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "Even with Claude Code’s reputation for taste, the most common complaint about AI-generated design is that it looks generic — Inter fonts, purple gradients on white, soft shadows, oversized rounded corners, an aesthetic that “screams an AI made this.” Anthropic itself attributes this to distributional convergence: safe choices dominate web training data. Other reported issues include broken mobile layouts and instructions leaking into UI copy."}, {"kind": "steps", "items": [{"label": "Install the Frontend Design skill", "body": "It forces Claude to commit to a real direction and explicitly avoids fonts and gradients overused by AI."}, {"label": "Enable browser verification", "body": "Make Claude render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in CLAUDE.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Claude Code inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Claude Code as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Claude Code good is there from the first run, not assembled by hand each time."}, {"kind": "ol", "items": ["Install Open Design and select Claude Code as your agent.", "Authenticate with your Anthropic API key (BYOK) or Claude subscription — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Claude Code agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Is Claude Code good for design work?", "text": "Yes — it is widely regarded as the coding agent with the best frontend taste, making specific, codebase-aware decisions about hex values, spacing, and type scales. With the Frontend Design skill, a design system, and real reference images in context it produces production-quality, responsive UI and can verify it in a browser. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need a Claude subscription to design with Claude Code?", "text": "You can use either an Anthropic API key (BYOK, via the Console) or a Claude subscription (Pro / Max). Either way Open Design never proxies your credentials — they are used directly by your agent on your machine."}, {"name": "Claude Code or Codex for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions and frontend reasoning; Codex has strong visual polish and excels at delegated, sandboxed builds. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Claude Code to Figma?", "text": "Install the official Figma plugin with claude plugin install figma@claude-plugins-official. You can then implement Figma frames in code using the design context, and push a running UI back to editable Figma frames with “Send this to Figma.” Dev Mode MCP requires a paid Figma plan."}, {"name": "What are Skills and CLAUDE.md?", "text": "CLAUDE.md is a markdown file in your project root that Claude Code reads at the start of every session — the place to encode your design conventions. Skills package repeatable instructions and resources Claude loads on demand, including Anthropic’s official Frontend Design skill. Open Design ships a curated library of both so you skip the per-project setup."}, {"name": "How do I avoid the generic “AI slop” aesthetic?", "text": "Install the Frontend Design skill, supply real design tokens and reference screenshots, encode brand rules in CLAUDE.md, and enable browser verification. Open Design ships these as a curated library so you skip the per-project setup."}, {"name": "Is Open Design affiliated with Anthropic?", "text": "No. Claude Code is a product of Anthropic; Open Design is an independent open-source project that supports it as a first-party adapter. Claude and Claude Code are trademarks of Anthropic."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Anthropic credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Claude Code, the open way.", "ctaBody": "Bring your own Anthropic key or Claude subscription, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Claude Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Claude Code", "aboutBody": ["Claude Code is Anthropic’s agentic command-line tool: you describe a task in natural language and it reads, writes, and runs code in your project until the task is done.", "It is a coding agent, not a design tool — but design is one of its strongest emergent uses. With the right skills and a design system in context, it generates production HTML/CSS/React, iterates on screenshots, and maintains design tokens.", "Open Design treats Claude Code as a first-party adapter, so the same agent you code with becomes the engine behind a structured design workflow."], "vendorLabel": "Vendor", "vendor": "Anthropic", "credentialLabel": "Credential", "credential": "Anthropic API key (BYOK) or Claude subscription", "designTitle": "Designing with Claude Code", "designLead": "The community has converged on a few patterns that turn Claude Code from a generic code generator into something with real design judgment:", "designPoints": [{"label": "Design system first", "body": "Drop a DESIGN.md / tokens / Tailwind config into the project so output matches a brand instead of defaulting to “AI slop”."}, {"label": "Aesthetic skills", "body": "Skills like Anthropic’s frontend-design make Claude Code commit to a typography/color/motion direction before writing any markup."}, {"label": "Figma → code", "body": "Wire the Figma MCP server in and Claude Code turns frames into production components with real tokens."}, {"label": "Screenshot loop", "body": "Let it screenshot its own UI, compare to a reference, and iterate — the agentic design feedback loop."}], "linksTitle": "Real-world resources", "linksLead": "Tutorials, skills, and walkthroughs people are actually using to design with Claude Code:", "links": [{"label": "Designing with Claude Code (Steve Schoger, Tailwind Labs)", "href": "https://www.youtube.com/watch?v=lkKGQVHrXzE", "source": "YouTube · Steve Schoger"}, {"label": "Claude Code for Designers in 10 Minutes", "href": "https://www.youtube.com/watch?v=NMi2LnFrUxw", "source": "YouTube · Adrien"}, {"label": "anthropics/skills — frontend-design skill", "href": "https://github.com/anthropics/skills/blob/main/skills/frontend-design/SKILL.md", "source": "GitHub · Anthropic"}, {"label": "Claude Code for designers — full tutorial", "href": "https://www.builder.io/blog/claude-code-for-designers", "source": "Blog · Builder.io"}, {"label": "The web design workflow that actually works", "href": "https://tutorialsdojo.com/claude-code-the-web-design-workflow-that-actually-works/", "source": "Blog · Tutorials Dojo"}], "withOdTitle": "Claude Code + Open Design", "withOdLead": "Open Design is the design layer Claude Code is missing: a curated skill and design-system library, a structured render pipeline, and a desktop UI — all open-source and local-first.", "withOdSteps": ["Install Open Design and select Claude Code as your agent.", "Authenticate with your Anthropic API key (BYOK) or Claude subscription — nothing is proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file stays in your own repo."], "withOdClosing": "Same agent, same key — plus a real design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Can Claude Code really do design work?", "text": "Yes — with a design system and aesthetic skills in context it generates production-quality UI. Open Design provides both out of the box so you skip the setup."}, {"name": "Do I need a Claude subscription?", "text": "You can use either an Anthropic API key (BYOK) or your Claude subscription. Open Design never proxies your credentials."}, {"name": "Is this an official Anthropic product?", "text": "No. Open Design is an independent open-source project. Claude Code is a trademark of Anthropic; we integrate with it as a first-party adapter."}], "ctaTitle": "Design with Claude Code, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  codex: {"title": "Codex for Design: Build UI with OpenAI Codex — Open Design", "description": "The practical guide to designing UI and frontends with OpenAI Codex — setup, the Figma integration, skills, and how to avoid generic \"AI slop\". Open Design turns Codex into a free, local-first, open-source design agent.", "breadcrumb": "Codex", "label": "Agent · Codex", "heading": "Codex for design.", "lead": "Codex is OpenAI’s coding agent. With its Product Design plugin and Figma integration it has become a serious design tool. Open Design wires Codex into an open-source design workflow — your OpenAI key or ChatGPT subscription, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Codex turns screenshots and user stories into responsive UI, and round-trips designs to Figma. Open Design gives it a curated design-system and skill library plus a desktop workflow — bring your own key and keep everything local.", "toc": ["What is Codex", "Designing with Codex", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Codex into a local-first, open-source design agent — your OpenAI key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Codex inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex started as a code generator, but in 2026 it became a credible tool for designing real interfaces — once you give it the right references, skills, and verification loop. This is a practical, end-to-end guide to using Codex for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Codex is today, why it is suddenly good at frontend, how to set it up from zero, the screenshot-to-UI loop, the official Figma round-trip, how it compares to Cursor and Claude Code, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex design feedback loop: terminal agent, browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Codex builds UI in the terminal, renders and verifies it in a real browser, and iterates against your references."}, "tocLabel": "On this page", "toc": [{"id": "what-is-codex", "label": "What OpenAI Codex actually is"}, {"id": "why-design", "label": "Why Codex is good at design now"}, {"id": "setup", "label": "Set up Codex for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "figma", "label": "Codex + Figma round-trip"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "What OpenAI Codex actually is (and what it isn’t)", "blocks": [{"kind": "p", "text": "First, a disambiguation that trips up almost everyone searching for “Codex.” The original OpenAI Codex was a 2021 code-completion model that powered early GitHub Copilot and was deprecated in 2023. That is not what this page is about. Today’s Codex is OpenAI’s agentic coding tool — it plans, writes, runs, and verifies code from natural-language tasks."}, {"kind": "p", "text": "Modern Codex ships across four surfaces: a terminal CLI (rewritten in Rust, Apache-2.0 licensed), an IDE extension for VS Code, Cursor, and Windsurf, a cloud/web experience for delegated async tasks, and a desktop app with an in-app browser and Computer Use."}, {"kind": "steps", "items": [{"label": "Default model", "body": "As of mid-2026 the recommended model is gpt-5.5, with gpt-5.4 being the model OpenAI explicitly trained for frontend and computer use."}, {"label": "Instruction file", "body": "Codex reads an AGENTS.md file in your project (a cross-tool standard) for project rules — the natural place to encode your design conventions."}, {"label": "Sandbox", "body": "It runs in a kernel-level sandbox (workspace-write by default), so an agent editing your UI cannot wander outside the project."}]}, {"kind": "ul", "items": ["Vendor: OpenAI", "Credential: OpenAI API key (BYOK) or ChatGPT subscription (Free / Go / Plus / Pro / Business / Enterprise)", "License of the CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Why Codex is good at design now", "blocks": [{"kind": "p", "text": "Three things converged in early 2026 to make Codex a real design tool rather than a generic code generator."}, {"kind": "steps", "items": [{"label": "A frontend-trained model", "body": "OpenAI shipped GPT-5.4, its first mainline model trained for frontend and computer use, with much better image understanding across the design workflow and stronger self-verification. It can even generate mood boards and visual options before committing to final assets."}, {"label": "An official frontend skill", "body": "The openai/skills catalog ships a curated frontend-skill that enforces real taste: cardless layouts, full-bleed heroes, brand-first hierarchy, restrained motion, at most two typefaces and one accent color — and makes Codex write a visual thesis before building."}, {"label": "Browser verification", "body": "With the Playwright skill Codex opens a real browser, resizes to breakpoints, and compares its output back to the reference instead of just checking that the build passes."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson behind all three: Codex does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Codex for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Codex that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure, install skill, verify", "caption": "The setup sequence: install → authenticate → configure AGENTS.md → install the frontend skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in AGENTS.md or a DESIGN.md and point Codex at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Choose the right reasoning level", "body": "OpenAI notes that low-to-medium reasoning levels often produce stronger frontend results than the highest setting."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Codex is turning a reference image into working, responsive UI and iterating until it matches. OpenAI’s own guidance distills to five steps."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI.", "Prepare a design system and tell Codex where the tokens and canonical primitives live.", "Enable the Playwright interactive skill so Codex renders in a real browser and resizes to breakpoints.", "Iterate by having Codex compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Feed images by dragging a screenshot into the terminal or with the image flag, then prompt with concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Run a dev server in a second terminal, keep prompts small and focused, and commit good iterations / revert bad ones (telling Codex when you revert) so each pass builds on a clean base."}]}, {"id": "figma", "heading": "Codex + Figma: design ↔ code round-trip", "blocks": [{"kind": "p", "text": "In February 2026 OpenAI and Figma announced an official partnership, turning the earlier Figma MCP beta into a first-class, bidirectional integration. It works in both directions."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copy a frame’s “link to selection” in Figma, paste it into Codex with get_design_context, and ask it to implement the design using your existing component library."}, {"label": "Code → Design", "body": "The generate_figma_design tool (“Code to Canvas”) turns a live, running UI back into editable Figma frames — entire screen, a selected element, or a whole file."}]}, {"kind": "p", "text": "The Figma MCP runs as a remote server and is exempt from rate limits. Add it once and it is available to Codex, Claude Code, Cursor, VS Code, and more — which is exactly the kind of portable, multi-agent capability Open Design is built to orchestrate."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Codex", "Strong visual polish after GPT-5.4 + frontend-skill; image understanding", "Delegated async builds, sandboxed runs, portable AGENTS.md rules"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all three default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about Codex-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts, instructions leaking into UI copy, and hitting usage limits quickly."}, {"kind": "steps", "items": [{"label": "Install a frontend skill", "body": "A curated aesthetic skill forces Codex to commit to a real direction instead of the default look."}, {"label": "Enable Playwright verification", "body": "Make Codex render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in AGENTS.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Codex inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Codex as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Codex good is there from the first run, not assembled by hand each time."}, {"kind": "ol", "items": ["Install Open Design and select Codex as your agent.", "Authenticate with your OpenAI API key (BYOK) or ChatGPT subscription — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Codex agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can OpenAI Codex really do design work?", "text": "Yes — with a frontend skill, a design system, and real reference images in context, Codex (especially on GPT-5.4) produces production-quality, responsive UI and can verify it in a browser. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Is this the OpenAI Codex Product Design plugin?", "text": "No. Open Design is an independent open-source project that integrates Codex as an agent. It complements OpenAI’s own tooling with a local-first, open skill and design-system library."}, {"name": "Do I need a ChatGPT subscription to design with Codex?", "text": "You can use either an OpenAI API key (BYOK) or your ChatGPT subscription. ChatGPT sign-in generally gives more generous limits; Open Design never proxies your credentials either way."}, {"name": "Codex or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Codex has strong visual polish after GPT-5.4 and excels at delegated, sandboxed builds. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Codex to Figma?", "text": "Add the official Figma MCP server (codex mcp add figma --url https://mcp.figma.com/mcp). You can then implement Figma frames in code with get_design_context and push a running UI back to editable Figma frames with generate_figma_design."}, {"name": "How do I avoid the generic “AI slop” aesthetic?", "text": "Install a frontend skill, supply real design tokens and reference screenshots, encode brand rules in AGENTS.md, and enable Playwright verification. Open Design ships these as a curated library so you skip the per-project setup."}, {"name": "Is Open Design affiliated with OpenAI?", "text": "No. Codex is a product of OpenAI; Open Design is an independent open-source project that supports it as a first-party adapter. OpenAI and Codex are trademarks of OpenAI."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first. Your files, artifacts, and DESIGN.md stay in your own repo, and your OpenAI credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Codex, the open way.", "ctaBody": "Bring your own OpenAI key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Codex inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Codex", "aboutBody": ["Codex is OpenAI’s agentic coding system — a CLI and ChatGPT-integrated agent that plans, writes, and runs code from natural-language tasks.", "OpenAI now ships a role-specific Product Design plugin and a Figma integration, so Codex can explore directions, audit flows, prototype from a live URL, and export to Figma or Canva.", "Open Design treats Codex as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "OpenAI", "credentialLabel": "Credential", "credential": "OpenAI API key (BYOK) or ChatGPT subscription", "designTitle": "Designing with Codex", "designLead": "Codex’s design story moved fast in 2026, clustered around a few official and community capabilities:", "designPoints": [{"label": "Product Design plugin", "body": "OpenAI’s role plugin: explore directions, audit user flows, prototype from a live URL, make screenshots interactive, export to Figma/Canva."}, {"label": "Screenshot → responsive UI", "body": "Codex turns a reference image into responsive markup and visually diffs against it across breakpoints with the Playwright skill."}, {"label": "Codex ↔ Figma", "body": "The Figma MCP server brings design context into code and turns a running UI back into editable Figma frames."}, {"label": "Frontend design skills", "body": "Community and official skills lock an aesthetic direction so output avoids the generic “purple AI slop” look."}], "linksTitle": "Real-world resources", "linksLead": "Official docs, Figma integration, and walkthroughs for designing with Codex:", "links": [{"label": "Build responsive front-end designs (Codex docs)", "href": "https://developers.openai.com/codex/use-cases/frontend-designs", "source": "Docs · OpenAI"}, {"label": "Introducing Codex to Figma", "href": "https://www.figma.com/blog/introducing-codex-to-figma/", "source": "Blog · Figma"}, {"label": "Design with ChatGPT and Codex: The Designer’s Guide", "href": "https://www.youtube.com/watch?v=rW7vVVmKTS8", "source": "YouTube · UI Collective"}, {"label": "openai/skills — frontend design skills", "href": "https://github.com/openai/skills", "source": "GitHub · OpenAI"}, {"label": "New Codex design workflow", "href": "https://www.youtube.com/watch?v=CPg5UYbYLhA", "source": "YouTube · Lukas Margerie"}], "withOdTitle": "Codex + Open Design", "withOdLead": "Open Design is the open-source design layer around Codex: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Codex as your agent.", "Authenticate with your OpenAI API key (BYOK) or ChatGPT subscription — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Codex agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is this the OpenAI Codex Product Design plugin?", "text": "No. Open Design is an independent open-source project that integrates Codex as an agent. It complements OpenAI’s own plugin with a local-first, open library."}, {"name": "Do I need a ChatGPT subscription?", "text": "You can use an OpenAI API key (BYOK) or your ChatGPT subscription. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with OpenAI?", "text": "No. Codex is a product of OpenAI; Open Design is an independent open-source project that supports it as a first-party adapter."}], "ctaTitle": "Design with Codex, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  cursor: {"title": "Cursor for designers — Open Design", "description": "How designers use Cursor for UI and web design — Design Mode, Figma-to-code, the Figma MCP — and how Open Design turns Cursor into a local-first, open-source design agent.", "breadcrumb": "Cursor Agent", "label": "Agent · Cursor", "heading": "Cursor for designers.", "lead": "Cursor is the AI code editor, now with a visual Design Mode. Designers use it to edit UI by pointing and drawing, and to turn Figma into code. Open Design plugs Cursor Agent into an open-source design workflow that keeps your files local.", "tldrTitle": "TL;DR", "tldrBody": "Cursor’s Design Mode lets you edit a live UI by clicking, sketching, or talking; its Figma MCP integrations bring real design context into code. Open Design adds a curated skill and design-system library on top — your provider keys, your repo.", "toc": ["What is Cursor", "Designing with Cursor", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Cursor into a local-first, open-source design agent — your Cursor account or model keys, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Cursor inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor is the AI-first code editor that made “build it and watch it render” the default way to ship UI. With Agent mode, inline edits, an in-editor preview, and Figma over MCP, it has become a genuine design tool — once you give it the right references, rules, and a verification loop. This is a practical, end-to-end guide to using Cursor for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Cursor actually is, why its tight iterate-and-watch loop is good for design, how to set it up from zero, the screenshot-and-preview-to-UI loop, the Figma round-trip over MCP, how it compares to Codex and Claude Code, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor design convergence: editor on the left, a curated skill and design-system hub in the middle with the Cursor mark at center, and a rendered UI on the right", "caption": "The core idea: Cursor edits and renders UI in the editor, while a curated design hub feeds it the system, skills, and references that make output look intentional."}, "tocLabel": "On this page", "toc": [{"id": "what-is-cursor", "label": "What Cursor actually is"}, {"id": "why-design", "label": "Why Cursor is good at design"}, {"id": "setup", "label": "Set up Cursor for design (from zero)"}, {"id": "preview-workflow", "label": "The preview-to-UI workflow"}, {"id": "figma", "label": "Cursor + Figma over MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "What Cursor actually is", "blocks": [{"kind": "p", "text": "Cursor is an AI-first code editor built by Anysphere. It is a fork of VS Code, so it keeps the familiar editor, extensions, and keybindings, but rebuilds the workflow around an AI agent that can read your whole project, edit multiple files, run commands, and iterate with you in the loop."}, {"kind": "p", "text": "For design work the important surfaces are Agent mode (you describe an outcome and Cursor plans and edits across files), inline edits and Tab completions for fast tweaks, an in-editor preview / browser so you can see the running UI without leaving the window, and MCP support that lets it pull in external context like a live Figma file."}, {"kind": "steps", "items": [{"label": "Project rules", "body": "Cursor reads project instruction files — versioned `.mdc` rules under `.cursor/rules`, and a plain `AGENTS.md` — so you can encode your design conventions where the agent reads them every run."}, {"label": "Models", "body": "Cursor is model-flexible: it ships with frontier models through your subscription and also supports bringing your own model keys, so you choose the engine behind the same editor workflow."}, {"label": "MCP", "body": "It speaks the Model Context Protocol, so external servers — most relevantly the Figma MCP server — become first-class context for the agent."}]}, {"kind": "ul", "items": ["Vendor: Anysphere", "Credential: Cursor account / subscription (Hobby / Pro / Business) or your own model keys (BYOK)", "Form: AI-first code editor (VS Code fork) with an in-editor agent and preview"]}]}, {"id": "why-design", "heading": "Why Cursor is good at design", "blocks": [{"kind": "p", "text": "Cursor’s design edge is not a single feature — it is the tightness of the build-and-see loop. Three things make it feel like a design tool rather than a generic code generator."}, {"kind": "steps", "items": [{"label": "A tight iterate-and-watch loop", "body": "You prompt, Cursor edits across files, and the in-editor preview renders the result immediately — so you adjust spacing, hierarchy, and motion in seconds instead of round-tripping through a separate terminal and browser."}, {"label": "Direct visual editing", "body": "Beyond chat, Cursor lets you select elements in the preview and nudge styles, so small visual corrections feel like design edits rather than code archaeology."}, {"label": "Project rules and MCP context", "body": "With `.cursor/rules` (or `AGENTS.md`) and the Figma MCP server, the agent works against your tokens, components, and real design specs instead of guessing."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Cursor does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Cursor for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Cursor that can build, preview, and verify UI against your design system."}, {"kind": "ol", "items": ["Install Cursor from cursor.com and sign in with your Cursor account, or configure your own model keys (BYOK) in Settings.", "Open your project and pick a model in the chat / Agent panel.", "Add project rules: create `.cursor/rules/*.mdc` for structured, glob-scoped conventions, or a plain `AGENTS.md` for simple, readable instructions.", "Connect the Figma MCP server (optional) so the agent can read live design context.", "Run your dev server and use the in-editor preview to see and verify the UI as you iterate."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure rules, add skill, verify", "caption": "The setup sequence: install → authenticate → configure project rules → add a skill → enable preview verification."}, {"kind": "p", "text": "A minimal project-rules file makes the agent design to a brand instead of defaulting to a generic look. Put it where Cursor reads it every run:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in `.cursor/rules` or `AGENTS.md` and point Cursor at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Keep prompts small", "body": "Cursor’s tight loop rewards focused asks — iterate one component or state at a time and watch the preview between passes."}]}]}, {"id": "preview-workflow", "heading": "The preview-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Cursor is turning a reference into working, responsive UI and iterating in the editor until it matches — watching the live preview the whole time instead of guessing."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI.", "Prepare a design system and tell Cursor where the tokens and canonical primitives live.", "Keep the in-editor preview open and your dev server running so each edit renders immediately at the breakpoints you care about.", "Iterate by comparing the rendered UI back to the references — and use direct element selection in the preview for small visual corrections."]}, {"kind": "p", "text": "Feed references by attaching an image to the chat, then prompt with concrete constraints:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit good iterations and revert bad ones (telling Cursor when you revert) so each pass builds on a clean base — the same discipline that keeps any agent loop from drifting."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ code over MCP", "blocks": [{"kind": "p", "text": "Cursor connects to Figma through the official Figma MCP server, which gives the agent structured access to a live Figma file instead of a flat screenshot. That removes the guesswork from handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copy a frame’s link in Figma, paste it into Cursor, and ask it to implement the design. The MCP server exposes real design context — components, variables, layout data, tokens — so the generated code matches the source instead of approximating it."}, {"label": "Stay aligned", "body": "With design tokens, styles, and components used consistently in Figma (and Code Connect where available), Cursor’s output stays mapped to your real design system rather than re-inventing primitives."}]}, {"kind": "p", "text": "Set the remote Figma MCP server up once and it is available to Cursor as first-class context. Because MCP is an open standard, the same server is reusable across Cursor, Claude Code, Codex, and VS Code — exactly the kind of portable, multi-agent capability Open Design is built to orchestrate."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Cursor", "Visual build-and-see loop with live in-editor preview and direct element editing", "Tight iterate-and-watch UI work inside an IDE"], ["Codex", "Strong visual polish with a frontend skill; image understanding and sandboxed runs", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all three default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about Cursor-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include layouts that break on mobile and instructions leaking into UI copy."}, {"kind": "steps", "items": [{"label": "Add a design skill", "body": "A curated aesthetic skill forces Cursor to commit to a real direction instead of the default look."}, {"label": "Use the preview to verify", "body": "Render and self-check across breakpoints in the in-editor preview so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in `.cursor/rules`", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Cursor inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Cursor as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Cursor good is there from the first run, not assembled by hand each time."}, {"kind": "ol", "items": ["Install Open Design and select Cursor as your agent.", "Authenticate with your Cursor account or your own model keys (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Cursor agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Cursor really do design work?", "text": "Yes — with a design skill, a design system, and real reference images in context, Cursor produces production-quality, responsive UI, and its in-editor preview lets you verify and refine it visually. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Is this an official Cursor product?", "text": "No. Open Design is an independent open-source project that integrates Cursor as an agent. It complements Cursor with a local-first, open skill and design-system library."}, {"name": "Do I need a Cursor subscription to design with Cursor?", "text": "You can use a Cursor account / subscription or bring your own model keys (BYOK). Open Design never proxies your credentials either way — they are used directly by your agent."}, {"name": "Cursor or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Cursor’s edge is its tight build-and-see loop with a live preview inside the editor. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Cursor to Figma?", "text": "Add the official Figma MCP server in Cursor, then paste a Figma frame link into the chat and ask Cursor to implement it. The server exposes real components, variables, and layout data so the generated code matches the source design."}, {"name": "How do I avoid the generic “AI slop” aesthetic?", "text": "Add a design skill, supply real design tokens and reference screenshots, encode brand rules in `.cursor/rules` or `AGENTS.md`, and verify across breakpoints in the preview. Open Design ships these as a curated library so you skip the per-project setup."}, {"name": "Is Open Design affiliated with Cursor or Anysphere?", "text": "No. Cursor is a product of Anysphere; Open Design is an independent open-source project that supports it as a first-party adapter. Cursor and Anysphere are trademarks of Anysphere, Inc."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first. Your files, artifacts, and DESIGN.md stay in your own repo, and your Cursor or model credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Cursor, the open way.", "ctaBody": "Bring your own Cursor account or model keys, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Cursor inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Cursor", "aboutBody": ["Cursor is an AI-first code editor built on VS Code, with a built-in agent that edits across your whole project.", "Cursor shipped Design Mode — point at an element, sketch a change, or describe it in words, and Cursor edits the underlying React/Vue/Svelte source. Combined with Figma MCP servers, it has become a credible design-to-code surface.", "Open Design treats Cursor Agent as a first-party adapter so it can drive a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Cursor (Anysphere)", "credentialLabel": "Credential", "credential": "Cursor account (uses your own provider keys)", "designTitle": "Designing with Cursor", "designLead": "Cursor’s design ecosystem centers on visual editing and Figma interop:", "designPoints": [{"label": "Design Mode", "body": "Click, draw, or voice-describe a UI change and Cursor edits the source — visual editing backed by real code."}, {"label": "Figma → code", "body": "Figma MCP servers feed real layout and tokens to Cursor so it builds from the design, not a screenshot."}, {"label": "Bidirectional Figma", "body": "Some MCPs let Cursor read and modify Figma designs programmatically, not just consume them."}, {"label": "Design-to-code loop", "body": "The common pattern: draft in a visual tool, import to Cursor, then refine and extend with the agent."}], "linksTitle": "Real-world resources", "linksLead": "Announcements, tutorials, and tools for designing with Cursor:", "links": [{"label": "Cursor Design Mode announcement", "href": "https://x.com/cursor_ai/status/2062950344687272144", "source": "X · @cursor_ai"}, {"label": "Cursor’s Design Mode (Visual Editing) explained", "href": "https://www.builder.io/blog/cursor-design-mode-visual-editing", "source": "Blog · Builder.io"}, {"label": "Cursor for Designers — Figma to code", "href": "https://www.builder.io/blog/figma-to-cursor-for-designers", "source": "Blog · Builder.io"}, {"label": "Framelink Figma-Context-MCP", "href": "https://github.com/GLips/Figma-Context-MCP", "source": "GitHub · GLips"}, {"label": "cursor-talk-to-figma-mcp", "href": "https://github.com/grab/cursor-talk-to-figma-mcp", "source": "GitHub · Grab"}], "withOdTitle": "Cursor + Open Design", "withOdLead": "Open Design is the open-source design layer around Cursor: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Cursor Agent.", "Cursor uses your own provider keys — nothing is proxied through Open Design.", "Pick a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Everything stays in your repo, local-first."], "withOdClosing": "Cursor’s agent, plus an open and portable design workflow.", "faqTitle": "FAQ", "faq": [{"name": "Is Cursor good for design?", "text": "With Design Mode and Figma MCP it edits and builds UI well; from scratch it benefits from a design system. Open Design supplies one out of the box."}, {"name": "Does Open Design replace Cursor’s Design Mode?", "text": "No — it complements it. Open Design adds an open, curated design-system and skill library and a structured render pipeline on top of the agent."}, {"name": "Is Open Design affiliated with Cursor?", "text": "No. Cursor is a product of Anysphere; Open Design is an independent open-source project that integrates it as a first-party adapter."}], "ctaTitle": "Design with Cursor, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  opencode: {"title": "OpenCode for Design — Build UI with the Open-Source Agent", "description": "How to design UI and frontends with OpenCode — design.md files, UI/UX skills, the Figma MCP — plus how Open Design turns OpenCode into a free, local-first, open-source design agent.", "breadcrumb": "OpenCode", "label": "Agent · OpenCode", "heading": "OpenCode for design.", "lead": "OpenCode is the open-source terminal AI coding agent. Designers bolt design skills and DESIGN.md files onto it to generate real UI. Open Design makes that a structured, open-source workflow — bring your provider keys, keep everything local.", "tldrTitle": "TL;DR", "tldrBody": "OpenCode is a fully open-source coding agent; design is an emergent use via skills, design.md files, and Figma MCP. Open Design packages a curated design-system and skill library plus a desktop workflow around it — your keys, your repo.", "toc": ["What is OpenCode", "Designing with OpenCode", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns OpenCode into a local-first, open-source design agent — any model you choose with your own provider key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use OpenCode inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode is an open-source, terminal-first AI coding agent that is deliberately model-agnostic: you bring your own provider key and run whatever model you want behind the same workflow. That openness makes it a natural base for design work — but like every agent, it only produces good UI when you give it the right references, skills, and a verification loop. This is a practical, end-to-end guide to using OpenCode for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what OpenCode actually is, why a model-agnostic open agent is a good fit for design, how to set it up from zero, the screenshot-to-UI loop, how AGENTS.md and MCP extend it, how it compares to Codex, Claude Code, and Cursor, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both projects are open-source and run on your own machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode design feedback loop: a terminal TUI agent, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: OpenCode builds UI in the terminal, renders and verifies it in a real browser, and iterates against your references — on whatever model you choose."}, "tocLabel": "On this page", "toc": [{"id": "what-is-opencode", "label": "What OpenCode actually is"}, {"id": "why-design", "label": "Why an open, any-model agent fits design"}, {"id": "setup", "label": "Set up OpenCode for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "AGENTS.md, MCP, and shareable sessions"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "What OpenCode actually is", "blocks": [{"kind": "p", "text": "OpenCode is an open-source AI coding agent built for the terminal, maintained by the team behind SST (Anomaly Innovations). It reads your repository, runs commands, edits files, and talks to a large language model — but unlike vendor-bound agents, it does not ship its own model. You point it at whatever provider and model you want and bring your own key."}, {"kind": "p", "text": "It runs as a terminal UI (TUI), with a desktop app and IDE extensions on top of the same engine. Under the hood it uses a client/server architecture, so the agent that does the work is decoupled from the surface you drive it from. Two built-in agents — build and plan — toggle with the Tab key."}, {"kind": "steps", "items": [{"label": "Model-agnostic", "body": "Models and providers come from models.dev, an open catalog. You configure them in opencode.json with a provider/model-id string and can disable providers you do not want loaded — so the same design workflow runs on Anthropic, OpenAI, Google, OpenRouter, local models, and more."}, {"label": "Instruction file", "body": "OpenCode reads an AGENTS.md file in your project (the cross-tool standard, also compatible with CLAUDE.md) for project rules — the natural place to encode your design conventions. Run /init to generate one."}, {"label": "Extensible", "body": "It supports LSP integration, MCP servers, themes, keybinds, and custom commands, plus shareable session links for collaboration."}]}, {"kind": "ul", "items": ["Maintainer: SST / Anomaly Innovations (open-source project)", "Credential: your own model-provider API key(s) — BYOK, no vendor lock-in", "License: MIT, open source"]}]}, {"id": "why-design", "heading": "Why an open, any-model agent fits design work", "blocks": [{"kind": "p", "text": "OpenCode does not have a single “design model” the way a vendor agent does — and that is the point. Because it is model-agnostic and open, you can run the same design workflow on whichever model is currently best at frontend, swap it later, or fall back to a local model, all without changing your setup."}, {"kind": "p", "text": "But model choice alone does not buy taste. Like every coding agent, OpenCode produces generic UI unless you give it constraints. Good design output comes from three inputs you provide."}, {"kind": "steps", "items": [{"label": "A design system", "body": "Real tokens, primitives, and conventions the agent reuses, so output matches a brand instead of defaulting to a generic look."}, {"label": "An aesthetic skill", "body": "A curated skill that enforces real taste — restrained motion, brand-first hierarchy, at most two typefaces and one accent color — and makes the agent commit to a direction before building."}, {"label": "Concrete references", "body": "Actual reference images and multiple states (desktop and mobile, hover, empty, loading), not a single hero shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images — independent of which model you run."}, {"kind": "p", "text": "The lesson: OpenCode gives you model freedom, but taste still comes from a curated design context. Open Design packages exactly those inputs, which is why the two fit together — both are open-source and local-first (more below)."}]}, {"id": "setup", "heading": "Set up OpenCode for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to an OpenCode that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate with your provider key, configure AGENTS.md, add a skill, verify", "caption": "The setup sequence: install → authenticate (your provider key) → configure AGENTS.md → add a skill → verify in a real browser."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in AGENTS.md (or a DESIGN.md referenced from it) so output matches a brand instead of defaulting to a generic look. The instructions option in opencode.json can point at additional rule files via globs."}, {"label": "Choose a capable model", "body": "Because OpenCode is model-agnostic, pick whichever provider/model is currently strongest at frontend for the design pass — and keep the rest of your workflow unchanged."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with any agent is turning a reference image into working, responsive UI and iterating until it matches. The same five-step shape applies in OpenCode."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI.", "Prepare a design system and tell OpenCode where the tokens and canonical primitives live (in AGENTS.md).", "Run a dev server and have the agent render in a real browser, resizing to breakpoints to check the result.", "Iterate by having OpenCode compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Reference files with @ in the TUI for a fuzzy search of your working directory, run shell commands inline with a leading !, and drive actions with / commands. Then prompt with concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling OpenCode when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, and shareable sessions", "blocks": [{"kind": "p", "text": "Three extension points make OpenCode practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md rules", "body": "Project rules live in an AGENTS.md at the repo root (or global rules in ~/.config/opencode/AGENTS.md). It is the durable home for your design conventions, read on every run, and it is compatible with the CLAUDE.md files other agents use."}, {"label": "MCP servers", "body": "OpenCode supports both local (command) and remote (URL) MCP servers, configured under the mcp key — the portable way to bring in design context and external tools that work across agents, not just OpenCode."}, {"label": "Shareable sessions", "body": "The /share command creates a public link to a conversation for collaboration or review, and /unshare revokes it — useful for getting feedback on a design pass."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["OpenCode", "Open-source and model-agnostic; run any provider behind one terminal workflow", "BYOK freedom, model-switching, fully open and local-first setups"], ["Codex", "Strong visual polish with a frontend skill; image understanding", "Delegated async, sandboxed builds, portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped, which is precisely why an open agent like OpenCode pairs so well with an open design layer."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to OpenCode; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in AGENTS.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context — regardless of which model you run. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with OpenCode inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats OpenCode as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes any agent good is there from the first run, not assembled by hand each time. Both projects are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select OpenCode as your agent.", "Authenticate with your own model-provider API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick any provider and model, plus a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same OpenCode agent, same model freedom — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can OpenCode really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, OpenCode produces production-quality, responsive UI and can verify it in a browser. Because it is model-agnostic, you run whichever model is currently best at frontend. Without that curated context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Which model should I use with OpenCode for design?", "text": "Whichever you like — OpenCode is provider-agnostic via models.dev, so you can run Anthropic, OpenAI, Google, OpenRouter, or local models behind the same workflow and switch at any time. The quality of the design output depends far more on your skill, design system, and references than on the model alone."}, {"name": "Is Open Design made by the OpenCode (SST) team?", "text": "No. Open Design is an independent open-source project that integrates OpenCode as an agent. It complements OpenCode with a local-first, open skill and design-system library."}, {"name": "Do I need a special subscription to design with OpenCode?", "text": "No — OpenCode is BYOK. You bring your own model-provider API key, and Open Design never proxies your credentials. There is no vendor lock-in."}, {"name": "OpenCode or Codex or Claude Code for frontend design?", "text": "All are strong, and many teams stack them. OpenCode’s edge is being fully open-source and model-agnostic; Codex excels at delegated, sandboxed builds; Claude Code is known for specific, codebase-aware design decisions. Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I extend OpenCode for design context?", "text": "Encode rules in AGENTS.md, add MCP servers under the mcp key for portable tools and design context, and use shareable sessions for review. Open Design ships a curated skill and design-system library so you skip the per-project setup."}, {"name": "Is Open Design affiliated with OpenCode or SST?", "text": "No. OpenCode is an open-source project maintained by SST (Anomaly Innovations); Open Design is an independent open-source project that supports it as a first-party adapter."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first. Your files, artifacts, and DESIGN.md stay in your own repo, and your model-provider credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with OpenCode, the open way.", "ctaBody": "Bring your own model-provider key, keep every file local, and get a curated design library around the open agent you already use.", "ctaActions": [{"label": "Use OpenCode inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is OpenCode", "aboutBody": ["OpenCode is an open-source (MIT) terminal AI coding agent — a TUI plus desktop and IDE surfaces — maintained by Anomaly (the SST team) at github.com/anomalyco/opencode.", "It is a coding agent, not a dedicated design tool. Design happens by adding skills, DESIGN.md system files, and Figma/visual-canvas MCPs to control its visual output.", "Open Design treats OpenCode as a first-party adapter, turning those ad-hoc patterns into a structured, open design pipeline."], "vendorLabel": "Vendor", "vendor": "Anomaly (open-source, MIT)", "credentialLabel": "Credential", "credential": "Provider keys via OpenCode config (BYOK)", "designTitle": "Designing with OpenCode", "designLead": "The OpenCode community designs by giving the agent taste through configuration and skills:", "designPoints": [{"label": "design.md systems", "body": "Drop a brand DESIGN.md (Stripe/Linear/Airbnb-style rules) into the project so OpenCode generates a matching UI."}, {"label": "UI/UX skills", "body": "Design-intelligence skills add dozens of UI styles and palettes, generating a design system before coding."}, {"label": "Figma & visual canvas MCP", "body": "Connect Figma or a visual canvas via MCP for a design-to-code loop."}, {"label": "Model taste", "body": "Because OpenCode is BYOK, you pick the model that designs best for your taste and budget."}], "linksTitle": "Real-world resources", "linksLead": "Skills, design.md collections, and tutorials for designing with OpenCode:", "links": [{"label": "OpenCode UI/UX skill: build better modern designs", "href": "https://www.youtube.com/watch?v=Pc27ThkuBPQ", "source": "YouTube · AI Stack Engineer"}, {"label": "OpenCode + design.md: stunning designs for free", "href": "https://www.youtube.com/watch?v=sCu34s8zb4o", "source": "YouTube · AI Stack Engineer"}, {"label": "VoltAgent/awesome-design-md", "href": "https://github.com/VoltAgent/awesome-design-md", "source": "GitHub · VoltAgent"}, {"label": "anomalyco/opencode (canonical repo)", "href": "https://github.com/anomalyco/opencode", "source": "GitHub · Anomaly"}, {"label": "OpenCode tutorial: setup, agents, skills & MCP", "href": "https://www.youtube.com/watch?v=uZGDO0L-Dr4", "source": "YouTube · Leon van Zyl"}], "withOdTitle": "OpenCode + Open Design", "withOdLead": "Open Design is the open-source design layer around OpenCode: a curated skill and design-system library, a structured render pipeline, and a local desktop UI — no more hand-assembling design.md files and skills.", "withOdSteps": ["Install Open Design and select OpenCode as your agent.", "OpenCode uses your provider keys via its own config (BYOK) — nothing is proxied.", "Pick a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Both projects are open-source and local-first — your files never leave your machine."], "withOdClosing": "Two open-source agents, one local-first design workflow.", "faqTitle": "FAQ", "faq": [{"name": "Which OpenCode is this?", "text": "The open-source terminal agent at github.com/anomalyco/opencode (formerly sst/opencode), maintained by Anomaly. Not to be confused with similarly named tools."}, {"name": "Can OpenCode design UIs?", "text": "Yes, with design.md files and UI/UX skills in context. Open Design provides a curated library of both so you skip the manual setup."}, {"name": "Is Open Design the same project as OpenCode?", "text": "No. Both are open-source, but they are separate projects. Open Design integrates OpenCode as a first-party agent adapter."}], "ctaTitle": "Design with OpenCode, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  gemini: {"title": "Gemini CLI for design — Open Design", "description": "How people use Google’s Gemini CLI for UI and web design — its multimodal image understanding, the 1M-token context, GEMINI.md and MCP — and how Open Design turns Gemini CLI into a local-first, open-source design agent.", "breadcrumb": "Gemini CLI", "label": "Agent · Gemini CLI", "heading": "Gemini CLI for design.", "lead": "Gemini CLI is Google’s open-source terminal agent. Its multimodal models read screenshots and its 1M-token context holds a whole design system, which makes it a real design tool — once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your Google account or API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Gemini CLI turns reference images into responsive UI with strong multimodal understanding and a huge context window, free to start with a Google account. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Gemini CLI", "Designing with Gemini CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Gemini CLI into a local-first, open-source design agent — your Google account or Gemini API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Gemini CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI is Google’s open-source AI agent for the terminal. Two things make it interesting for design specifically: its models are strongly multimodal, so it reads a screenshot and reasons about layout, spacing, and hierarchy; and its 1M-token context window can hold an entire design system and codebase at once. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and it is free to start with a Google account. This is a practical, end-to-end guide to using Gemini CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Gemini CLI actually is, why its multimodal models and huge context fit design, how to set it up from zero, the screenshot-to-UI loop, how GEMINI.md and MCP extend it, how it compares to Codex, Claude Code, and Cursor, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Gemini CLI design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Gemini CLI reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — with a whole design system in context."}, "tocLabel": "On this page", "toc": [{"id": "what-is-gemini-cli", "label": "What Gemini CLI actually is"}, {"id": "why-design", "label": "Why multimodal + huge context fit design"}, {"id": "setup", "label": "Set up Gemini CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "GEMINI.md, MCP, and extensions"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Gemini CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-gemini-cli", "heading": "What Gemini CLI actually is", "blocks": [{"kind": "p", "text": "Gemini CLI is an open-source (Apache-2.0) AI agent that Google ships for the terminal. It reads your repository, edits files, runs shell commands, fetches the web, and can ground answers with Google Search — planning and verifying work from natural-language tasks rather than just completing lines. The same engine also powers the Gemini Code Assist agent inside VS Code."}, {"kind": "p", "text": "For design work, two properties stand out. Its models are natively multimodal, so you can hand it a screenshot and it reasons about the actual layout. And its context window reaches up to 1M tokens, large enough to hold your whole design system, component library, and reference set at once instead of summarizing them away."}, {"kind": "steps", "items": [{"label": "Context files", "body": "Gemini CLI reads a GEMINI.md file for persistent project context — the natural place to encode your design conventions, tokens, and review checklists. Personal and team settings layer on top."}, {"label": "Built-in tools + MCP", "body": "It ships file, shell, web-fetch, and Google Search tools out of the box, and supports MCP servers (configured in ~/.gemini/settings.json) to add external context like a live Figma file."}, {"label": "Free to start", "body": "Signing in with a personal Google account gives a generous free tier of Gemini requests; you can also bring a Gemini API key or use Vertex AI."}]}, {"kind": "ul", "items": ["Vendor: Google", "Credential: Google account (free tier) or Gemini API key from AI Studio (BYOK) or Vertex AI", "License: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Why multimodal models and a huge context fit design", "blocks": [{"kind": "p", "text": "Gemini CLI’s design edge comes from two model properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Strong multimodal understanding", "body": "Because Gemini models are natively multimodal, the agent reads reference screenshots well — comparing its rendered output back to an image instead of guessing from a prose description."}, {"label": "A 1M-token context window", "body": "A large context means the whole design system, tokens, and many reference states fit at once, so the agent reuses your real primitives rather than inventing one-off styles."}, {"label": "Conventions in GEMINI.md", "body": "A GEMINI.md (plus the Figma MCP server) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Gemini CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Gemini CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Gemini CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure GEMINI.md, add a skill, verify", "caption": "The setup sequence: install → authenticate → configure GEMINI.md → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in GEMINI.md and point Gemini at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Gemini renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Gemini CLI is turning a reference image into working, responsive UI and iterating until it matches — leaning on the multimodal model to compare output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in GEMINI.md, and tell Gemini where the tokens and canonical primitives live.", "Run a dev server and have Gemini render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Gemini compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Reference an image with @ to attach it to the prompt, then give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Gemini when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "GEMINI.md, MCP, and extensions", "blocks": [{"kind": "p", "text": "Three extension points make Gemini CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "GEMINI.md context", "body": "Project rules live in a GEMINI.md at the repo root (with global and team layers). It is the durable home for your design conventions, read on every run."}, {"label": "MCP servers", "body": "Configure MCP servers under ~/.gemini/settings.json — the portable way to bring in design context and external tools, most relevantly the Figma MCP server, that work across agents, not just Gemini."}, {"label": "Extensions and built-in tools", "body": "Gemini CLI extensions and its built-in Google Search, file, shell, and web-fetch tools let it gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Gemini CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Use the multimodal model to render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in GEMINI.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Gemini CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Gemini CLI as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Gemini good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Gemini CLI as your agent.", "Authenticate with your Google account or Gemini API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Gemini CLI agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Gemini CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Gemini CLI produces production-quality, responsive UI, and its strong multimodal models verify output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Gemini CLI?", "text": "No — signing in with a Google account gives a generous free tier, and you can also bring a Gemini API key (BYOK) or use Vertex AI. Open Design never proxies your credentials either way."}, {"name": "What makes Gemini CLI good for design specifically?", "text": "Two things: its models are strongly multimodal, so it reads reference screenshots well, and its 1M-token context can hold an entire design system and reference set at once. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Gemini CLI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Gemini CLI’s edge is multimodal understanding plus a huge context and a free tier. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Gemini CLI to Figma?", "text": "Add the Figma MCP server under mcpServers in ~/.gemini/settings.json. Gemini can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Google?", "text": "No. Gemini CLI is a product of Google; Open Design is an independent open-source project that supports it as a first-party adapter. Gemini is a trademark of Google."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Google credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Gemini CLI, the open way.", "ctaBody": "Bring your own Google account or Gemini API key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Gemini CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Gemini CLI", "aboutBody": ["Gemini CLI is Google’s open-source (Apache-2.0) terminal AI agent. It reads your codebase, edits files, runs commands, fetches the web, and grounds answers with Google Search.", "Its models are natively multimodal and its context window reaches 1M tokens, so it reads reference screenshots and holds a whole design system at once.", "Open Design treats Gemini CLI as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Google", "credentialLabel": "Credential", "credential": "Google account (free tier) or Gemini API key (BYOK)", "designTitle": "Designing with Gemini CLI", "designLead": "Gemini CLI’s design strengths cluster around its model and context:", "designPoints": [{"label": "Multimodal screenshot → UI", "body": "Strong image understanding turns a reference image into responsive markup and checks the result against it."}, {"label": "1M-token context", "body": "A whole design system, component library, and reference set fit at once, so output reuses your real primitives."}, {"label": "GEMINI.md + MCP", "body": "Context files carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Open and free to start", "body": "Apache-2.0 and a generous free tier via a Google account, with BYOK via the Gemini API."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for Gemini CLI:", "links": [{"label": "google-gemini/gemini-cli (GitHub)", "href": "https://github.com/google-gemini/gemini-cli", "source": "GitHub · Google"}, {"label": "Introducing Gemini CLI", "href": "https://blog.google/innovation-and-ai/technology/developers-tools/introducing-gemini-cli-open-source-ai-agent/", "source": "Blog · Google"}, {"label": "Gemini CLI documentation", "href": "https://google-gemini.github.io/gemini-cli/", "source": "Docs · Google"}], "withOdTitle": "Gemini CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Gemini CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Gemini CLI as your agent.", "Authenticate with your Google account or Gemini API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Gemini CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Google?", "text": "No. Gemini CLI is a Google product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "No — a Google account gives a free tier, or bring a Gemini API key (BYOK). Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Google?", "text": "No. Open Design is independent; Gemini is a trademark of Google."}], "ctaTitle": "Design with Gemini CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  copilot: {"title": "GitHub Copilot CLI for design — Open Design", "description": "How people use GitHub Copilot CLI for UI and web design — its terminal-native coding agent, custom instruction files, MCP support, and multi-model choice — and how Open Design turns Copilot CLI into a local-first, open-source design agent.", "breadcrumb": "GitHub Copilot CLI", "label": "Agent · GitHub Copilot CLI", "heading": "GitHub Copilot CLI for design.", "lead": "GitHub Copilot CLI is GitHub's terminal-native coding agent. It plans and edits across your repo, picks from frontier models like Claude and GPT, and reads your repository instructions — which makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your GitHub Copilot subscription, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Copilot CLI turns reference images and natural-language tasks into responsive UI from the terminal, with model choice and deep GitHub integration — available on your existing Copilot subscription. Open Design gives it a curated design-system and skill library plus a desktop workflow, and keeps everything local.", "toc": ["What is GitHub Copilot CLI", "Designing with Copilot CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns GitHub Copilot CLI into a local-first, open-source design agent — your GitHub Copilot subscription, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Copilot CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI is GitHub's terminal-native coding agent — the same agentic harness that powers Copilot coding agent, brought to your command line. Two things make it interesting for design specifically: it reads your repository instructions and AGENTS.md, so your design conventions travel with the agent on every run; and it lets you choose among frontier models from Anthropic, OpenAI, and Google per task, so you can pick the one that reasons best about a given UI. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and it runs on the Copilot subscription you may already have. This is a practical, end-to-end guide to using Copilot CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Copilot CLI actually is, why repository instructions and model choice fit design, how to set it up from zero, the screenshot-to-UI loop, how custom instructions and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — your subscription and credentials stay on your machine, your artifacts stay in your own repo."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "GitHub Copilot CLI design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Copilot CLI reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — with your design conventions in repository instructions."}, "tocLabel": "On this page", "toc": [{"id": "what-is-copilot", "label": "What GitHub Copilot CLI actually is"}, {"id": "why-design", "label": "Why instructions + model choice fit design"}, {"id": "setup", "label": "Set up Copilot CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Custom instructions, MCP, and extensions"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Copilot CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-copilot", "heading": "What GitHub Copilot CLI actually is", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI is GitHub's terminal-native coding agent. It reads your repository, edits files, runs shell commands, and works directly with your GitHub context — issues, pull requests, and repositories — authenticated with your existing GitHub account. It is powered by the same agentic harness as GitHub's Copilot coding agent, so it plans complex tasks and iterates rather than just completing lines. It reached general availability in February 2026 after a public preview that opened in September 2025."}, {"kind": "p", "text": "For design work, two properties stand out. It reads custom instruction files — repository-wide rules in .github/copilot-instructions.md plus AGENTS.md — so your design conventions are included automatically on every run. And it supports multiple foundation-model providers, so you can switch the model per task with the /model command to whichever reasons best about a given UI."}, {"kind": "steps", "items": [{"label": "Instruction files", "body": "Copilot CLI reads repository instructions in .github/copilot-instructions.md, path-specific files under .github/instructions, and AGENTS.md — the natural place to encode your design conventions, tokens, and review checklists."}, {"label": "Built-in tools + MCP", "body": "It ships with GitHub's MCP server built in and runs file and shell tools, and you can add custom MCP servers with /mcp add (stored in mcp-config.json under ~/.copilot) for external context like a live Figma file."}, {"label": "Model choice", "body": "Use the /model command to pick among frontier models from Anthropic, OpenAI, and Google — switching per task, all on your existing Copilot subscription."}]}, {"kind": "ul", "items": ["Vendor: GitHub", "Credential: an active GitHub Copilot subscription (Pro, Pro+, Business, or Enterprise)", "Install: npm install -g @github/copilot, then run copilot"]}]}, {"id": "why-design", "heading": "Why repository instructions and model choice fit design", "blocks": [{"kind": "p", "text": "Copilot CLI's design edge comes from two properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Conventions that travel with the repo", "body": "Because Copilot CLI reads .github/copilot-instructions.md and AGENTS.md automatically, your tokens, primitives, and review rules are in context on every run — the agent works against a brand instead of a default look."}, {"label": "Pick the right model per task", "body": "Model choice across Anthropic, OpenAI, and Google means you can reach for the model that reasons best about a given layout, then switch for the next task — without changing your workflow."}, {"label": "Real specs via MCP", "body": "The built-in GitHub MCP server plus a Figma MCP server point the agent at your tokens, components, and real specs, so it builds from source instead of approximating."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Copilot CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Copilot CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Copilot CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, choose a model, configure instructions, verify", "caption": "The setup sequence: install → authenticate → choose a model → write instructions → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in .github/copilot-instructions.md or AGENTS.md, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Copilot renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Copilot CLI is turning a reference image into working, responsive UI and iterating until it matches — leaning on a strong multimodal model to compare output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in .github/copilot-instructions.md or AGENTS.md, and tell Copilot where the tokens and canonical primitives live.", "Run a dev server and have Copilot render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Copilot compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Point Copilot at your reference images and give concrete constraints; it previews each file edit or command for your approval before it runs:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Copilot when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Custom instructions, MCP, and extensions", "blocks": [{"kind": "p", "text": "Three extension points make Copilot CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Custom instructions", "body": "Repository rules live in .github/copilot-instructions.md (with path-specific files under .github/instructions and AGENTS.md). They are the durable home for your design conventions, included automatically on every run."}, {"label": "MCP servers", "body": "Copilot CLI ships with GitHub's MCP server built in and lets you add custom servers via /mcp add (stored in mcp-config.json under ~/.copilot) — the portable way to bring in design context, most relevantly the Figma MCP server, that works across agents, not just Copilot."}, {"label": "Specialized agents and built-in tools", "body": "Copilot CLI's specialized modes — for codebase exploration, running builds and tests, change review, and planning — plus its file and shell tools let it gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Copilot CLI", "Multi-model choice (Anthropic, OpenAI, Google) and deep GitHub integration on your Copilot subscription", "Picking the best model per task and instruction-driven work tied to your GitHub repo"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Copilot CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints with a browser MCP so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in custom instructions", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules in .github/copilot-instructions.md or AGENTS.md, where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Copilot CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats GitHub Copilot CLI as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Copilot good is there from the first run, not assembled by hand each time. Open Design is independent, open-source (Apache-2.0), and local-first, which is why the pairing fits: the agent does the work, your files and credentials stay yours."}, {"kind": "ol", "items": ["Install Open Design and select GitHub Copilot CLI as your agent.", "Authenticate with your GitHub Copilot subscription — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Copilot CLI agent, same subscription — plus a real, portable, open-source design workflow around it. Open Design is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can GitHub Copilot CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Copilot CLI produces production-quality, responsive UI, and you can pick the model that verifies output best against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need a subscription to design with Copilot CLI?", "text": "Yes — Copilot CLI runs on an active GitHub Copilot subscription (Pro, Pro+, Business, or Enterprise); it is not bring-your-own-key. You authenticate with your GitHub account. Open Design never proxies your credentials — your subscription is used directly by your agent."}, {"name": "What makes Copilot CLI good for design specifically?", "text": "Two things: it reads repository instructions and AGENTS.md automatically, so your design conventions travel with the repo; and it lets you switch among frontier models from Anthropic, OpenAI, and Google per task. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Copilot CLI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Copilot CLI's edge is model choice across providers and deep GitHub integration on a subscription you may already have. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Copilot CLI to Figma?", "text": "Add the Figma MCP server with the /mcp add command; settings are stored in mcp-config.json under ~/.copilot. Copilot can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with GitHub or Microsoft?", "text": "No. GitHub Copilot CLI is a product of GitHub; Open Design is an independent open-source project that supports it as a first-party adapter. GitHub Copilot is a trademark of GitHub, Inc. and Microsoft."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your GitHub Copilot credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with GitHub Copilot CLI, the open way.", "ctaBody": "Bring your GitHub Copilot subscription, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Copilot CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is GitHub Copilot CLI", "aboutBody": ["GitHub Copilot CLI is GitHub's terminal-native coding agent, powered by the same agentic harness as Copilot coding agent. It reads your codebase, edits files, runs commands, and works with your GitHub issues, PRs, and repositories.", "It reads custom instruction files and AGENTS.md automatically, and lets you switch among frontier models from Anthropic, OpenAI, and Google per task.", "Open Design treats Copilot CLI as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "GitHub", "credentialLabel": "Credential", "credential": "GitHub Copilot subscription", "designTitle": "Designing with Copilot CLI", "designLead": "Copilot CLI's design strengths cluster around instructions and model choice:", "designPoints": [{"label": "Screenshot → UI", "body": "Pick a strong multimodal model and turn a reference image into responsive markup, then check the result against it."}, {"label": "Multi-model choice", "body": "Switch among frontier models from Anthropic, OpenAI, and Google per task with /model, all on your Copilot subscription."}, {"label": "Instructions + MCP", "body": "Custom instructions and AGENTS.md carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Deep GitHub integration", "body": "Built-in GitHub MCP server and access to your repos, issues, and PRs, authenticated with your existing GitHub account."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for GitHub Copilot CLI:", "links": [{"label": "github/copilot-cli (GitHub)", "href": "https://github.com/github/copilot-cli", "source": "GitHub · GitHub"}, {"label": "Using GitHub Copilot CLI", "href": "https://docs.github.com/en/copilot/how-tos/copilot-cli/use-copilot-cli/overview", "source": "Docs · GitHub"}, {"label": "GitHub Copilot CLI is now generally available", "href": "https://github.blog/changelog/2026-02-25-github-copilot-cli-is-now-generally-available/", "source": "Changelog · GitHub"}], "withOdTitle": "Copilot CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Copilot CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select GitHub Copilot CLI as your agent.", "Authenticate with your GitHub Copilot subscription — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Copilot CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by GitHub?", "text": "No. GitHub Copilot CLI is a GitHub product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need a subscription?", "text": "Yes — Copilot CLI runs on an active GitHub Copilot subscription (Pro, Pro+, Business, or Enterprise). Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with GitHub or Microsoft?", "text": "No. Open Design is independent; GitHub Copilot is a trademark of GitHub, Inc. and Microsoft."}], "ctaTitle": "Design with GitHub Copilot CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  qwen: {"title": "Qwen Code for design — Open Design", "description": "How people use Alibaba’s open-source Qwen Code CLI for UI and web design — its Qwen3-Coder models, large context window, QWEN.md and MCP — and how Open Design turns Qwen Code into a local-first, open-source design agent.", "breadcrumb": "Qwen Code", "label": "Agent · Qwen Code", "heading": "Qwen Code for design.", "lead": "Qwen Code is Alibaba’s open-source terminal agent, adapted from Gemini CLI and tuned for the Qwen3-Coder models. Its large context window holds a whole design system at once, which makes it a real design tool — once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your DashScope or Qwen API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Qwen Code turns clear references into responsive UI with capable agentic coding and a big context window, BYOK with a DashScope or OpenAI-compatible key. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Qwen Code", "Designing with Qwen Code", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Qwen Code into a local-first, open-source design agent — your DashScope or Qwen API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Qwen Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code is Alibaba’s open-source AI agent for the terminal. It is adapted from Google’s Gemini CLI, with parser-level and prompt adaptations that let it get the most out of the Qwen3-Coder models. Two things make it interesting for design specifically: it is a strong agentic coding model, so it plans, edits files, and runs the build and verification loop from a natural-language task; and its large context window can hold an entire design system and codebase at once. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and it is open-source and BYOK, so you bring your own key. This is a practical, end-to-end guide to using Qwen Code for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Qwen Code actually is, why a strong coder model plus a big context fit design, how to set it up from zero, the reference-to-UI loop, how QWEN.md and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Qwen Code design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Qwen Code reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — with a whole design system in context."}, "tocLabel": "On this page", "toc": [{"id": "what-is-qwen", "label": "What Qwen Code actually is"}, {"id": "why-design", "label": "Why a strong coder model + big context fit design"}, {"id": "setup", "label": "Set up Qwen Code for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "QWEN.md, MCP, and extensions"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Qwen Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qwen", "heading": "What Qwen Code actually is", "blocks": [{"kind": "p", "text": "Qwen Code is an open-source (Apache-2.0) AI agent that Alibaba ships for the terminal. It reads your repository, edits files, runs shell commands, and works the web — planning and verifying work from natural-language tasks rather than just completing lines. It is adapted from Google’s Gemini CLI, with parser-level and prompt adaptations tuned to unlock the Qwen3-Coder models on agentic coding tasks."}, {"kind": "p", "text": "For design work, two properties stand out. It is a capable agentic coder, so it can take a reference and a clear brief and build, run, and self-correct responsive UI. And the Qwen3-Coder models carry a large context window, big enough to hold your whole design system, component library, and reference set at once instead of summarizing them away."}, {"kind": "steps", "items": [{"label": "Context files", "body": "Qwen Code reads a QWEN.md file for persistent project context — the natural place to encode your design conventions, tokens, and review checklists. Personal and project settings layer on top."}, {"label": "Built-in tools + MCP", "body": "It ships file, shell, and web tools out of the box, and supports MCP servers (configured under mcpServers in ~/.qwen/settings.json) to add external context like a live Figma file."}, {"label": "BYOK to start", "body": "You bring your own key — a DashScope (Alibaba Cloud Model Studio) API key, or any OpenAI-compatible endpoint or ModelScope — and configure it in settings.json."}]}, {"kind": "ul", "items": ["Vendor: Alibaba", "Credential: DashScope / Qwen API key (BYOK), or OpenAI-compatible endpoint / ModelScope", "License: Apache-2.0, open source (adapted from Gemini CLI)"]}]}, {"id": "why-design", "heading": "Why a strong coder model and a big context fit design", "blocks": [{"kind": "p", "text": "Qwen Code’s design edge comes from two properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Strong agentic coding", "body": "The Qwen3-Coder models are tuned for agentic tasks, so the agent plans, edits, runs the build, and self-corrects — turning a clear reference and brief into responsive markup rather than a one-shot guess."}, {"label": "A large context window", "body": "Qwen3-Coder’s big context means the whole design system, tokens, and many reference states fit at once, so the agent reuses your real primitives rather than inventing one-off styles."}, {"label": "Conventions in QWEN.md", "body": "A QWEN.md (plus the Figma MCP server) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Qwen Code does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Qwen Code for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Qwen Code that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure QWEN.md, add a skill, verify", "caption": "The setup sequence: install → authenticate → configure QWEN.md → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in QWEN.md and point Qwen Code at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Qwen Code renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Qwen Code is turning a reference into working, responsive UI and iterating until it matches — leaning on the agent to build, render, and compare its output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and describe multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in QWEN.md, and tell Qwen Code where the tokens and canonical primitives live.", "Run a dev server and have Qwen Code render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Qwen Code compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Reference a file with @ to attach it to the prompt, then give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Qwen Code when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "QWEN.md, MCP, and extensions", "blocks": [{"kind": "p", "text": "Three extension points make Qwen Code practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "QWEN.md context", "body": "Project rules live in a QWEN.md at the repo root (with global and project layers). It is the durable home for your design conventions, read on every run."}, {"label": "MCP servers", "body": "Configure MCP servers under mcpServers in ~/.qwen/settings.json — the portable way to bring in design context and external tools, most relevantly the Figma MCP server, that work across agents, not just Qwen Code."}, {"label": "Skills and built-in tools", "body": "Qwen Code skills and its built-in file, shell, and web tools let it gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Qwen Code", "Strong agentic coding on the open Qwen3-Coder models with a large context; open-source and BYOK", "Open-source, key-flexible builds that hold a whole design system in context"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; the agent Qwen Code is adapted from", "Screenshot-heavy work and very large context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Qwen Code; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have the agent render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in QWEN.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Qwen Code inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Qwen Code as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Qwen Code good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Qwen Code as your agent.", "Authenticate with your DashScope or Qwen API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Qwen Code agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Qwen Code really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Qwen Code produces production-quality, responsive UI, and its agentic loop builds, renders, and verifies output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Qwen Code?", "text": "Qwen Code is free and open-source, but it is BYOK — you bring a DashScope (Alibaba Cloud Model Studio) API key, an OpenAI-compatible endpoint, or ModelScope. Alibaba also offers a fixed-fee coding plan. Open Design never proxies your credentials either way."}, {"name": "What makes Qwen Code good for design specifically?", "text": "Two things: the Qwen3-Coder models are tuned for agentic coding, so the agent builds and self-corrects responsive UI, and their large context can hold an entire design system and reference set at once. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Is Qwen Code the same as Gemini CLI?", "text": "No. Qwen Code is adapted from Google’s Gemini CLI — same open-source lineage — with parser-level and prompt adaptations that tune it for the Qwen3-Coder models. Open Design supports both, so you can switch agents without changing your design workflow."}, {"name": "How do I connect Qwen Code to Figma?", "text": "Add the Figma MCP server under mcpServers in ~/.qwen/settings.json. Qwen Code can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Alibaba or Qwen?", "text": "No. Qwen Code is a product of Alibaba; Open Design is an independent open-source project that supports it as a first-party adapter. Qwen is a trademark of Alibaba."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your DashScope or Qwen credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Qwen Code, the open way.", "ctaBody": "Bring your own DashScope or Qwen API key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Qwen Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Qwen Code", "aboutBody": ["Qwen Code is Alibaba’s open-source (Apache-2.0) terminal AI agent, adapted from Google’s Gemini CLI. It reads your codebase, edits files, runs commands, and works the web.", "It is tuned for the Qwen3-Coder models, whose large context window lets it hold a whole design system and reference set at once.", "Open Design treats Qwen Code as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Alibaba", "credentialLabel": "Credential", "credential": "DashScope / Qwen API key (BYOK)", "designTitle": "Designing with Qwen Code", "designLead": "Qwen Code’s design strengths cluster around its model and context:", "designPoints": [{"label": "Reference → UI", "body": "Strong agentic coding turns a clear reference and brief into responsive markup and self-checks the result against it."}, {"label": "Large context", "body": "A whole design system, component library, and reference set fit at once, so output reuses your real primitives."}, {"label": "QWEN.md + MCP", "body": "Context files carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Open and BYOK", "body": "Apache-2.0 and key-flexible — a DashScope or Qwen API key, an OpenAI-compatible endpoint, or ModelScope."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for Qwen Code:", "links": [{"label": "QwenLM/qwen-code (GitHub)", "href": "https://github.com/QwenLM/qwen-code", "source": "GitHub · Alibaba / Qwen"}, {"label": "Qwen Code documentation", "href": "https://qwenlm.github.io/qwen-code-docs/en/", "source": "Docs · Qwen"}, {"label": "Qwen3-Coder: Agentic Coding in the World", "href": "https://qwen.ai/blog?id=qwen3-coder", "source": "Blog · Qwen"}], "withOdTitle": "Qwen Code + Open Design", "withOdLead": "Open Design is the open-source design layer around Qwen Code: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Qwen Code as your agent.", "Authenticate with your DashScope or Qwen API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Qwen Code agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Alibaba?", "text": "No. Qwen Code is an Alibaba product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "Qwen Code is open-source but BYOK — bring a DashScope or Qwen API key, an OpenAI-compatible endpoint, or ModelScope. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Alibaba or Qwen?", "text": "No. Open Design is independent; Qwen is a trademark of Alibaba."}], "ctaTitle": "Design with Qwen Code, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  grok: {"title": "Grok Build for design — Open Design", "description": "How people use xAI's Grok Build (Grok Build) for UI and web design — its plan mode, AGENTS.md and MCP, image-aware Grok models and large context — and how Open Design turns Grok Build into a local-first, open-source design agent.", "breadcrumb": "Grok Build", "label": "Agent · Grok Build", "heading": "Grok Build for design.", "lead": "Grok Build is xAI's terminal coding agent. It plans multi-step work before it touches your files, reads images alongside code, and runs the build-and-verify loop in your repo — which makes it a real design tool once you give it references, conventions, and a verification step. Open Design wires it into an open-source design workflow: your SuperGrok login or xAI API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Grok Build turns reference images into responsive UI with plan-mode review, parallel subagents, and image-aware Grok models, authenticated through your SuperGrok or X Premium+ account. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Grok Build", "Designing with Grok Build", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Grok Build into a local-first, open-source design agent — your SuperGrok login or xAI API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Grok Build inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — xAI's terminal coding agent, shipped as Grok Build — is an agentic tool that lives in your terminal. Two things make it interesting for design specifically: it plans risky work before it acts, so you can review a proposed approach before any files change; and its Grok models accept image input, so it can reason about a reference screenshot alongside the code it is writing. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — authenticated straight through your SuperGrok or X Premium+ account, no API-key juggling required. This is a practical, end-to-end guide to using Grok Build for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Grok Build actually is, why plan mode and image-aware models fit design, how to set it up from zero, the screenshot-to-UI loop, how AGENTS.md and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — your credentials and artifacts never leaving your machine."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Grok Build design feedback loop: a terminal agent planning from a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Grok Build plans from your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — with your conventions in AGENTS.md."}, "tocLabel": "On this page", "toc": [{"id": "what-is-grok", "label": "What Grok Build actually is"}, {"id": "why-design", "label": "Why plan mode + image input fit design"}, {"id": "setup", "label": "Set up Grok Build for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "AGENTS.md, MCP, and subagents"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Grok Build in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-grok", "heading": "What Grok Build actually is", "blocks": [{"kind": "p", "text": "Grok Build is xAI's terminal coding agent, shipped under the name Grok Build. It reads your repository, edits files, runs shell commands, and plans multi-step engineering work from natural-language tasks rather than just completing lines. It is built around xAI's Grok models — exposed on the xAI API as the grok-build model family — and authenticates through your xAI account, so the agent and the models come from the same vendor."}, {"kind": "p", "text": "For design work, two properties stand out. It has a plan mode that drafts a structured approach you can approve, comment on, or rewrite before any change lands — a useful gate when you are iterating on UI. And its Grok models accept image input, so you can hand it a reference screenshot and it reasons about the actual layout instead of guessing from a prose description."}, {"kind": "steps", "items": [{"label": "Context files", "body": "Grok Build reads an AGENTS.md file for persistent project context — the natural place to encode your design conventions, tokens, and review checklists. It follows the same open AGENTS.md convention that Codex and other agents use."}, {"label": "Tools, MCP + subagents", "body": "It edits files, runs shell commands, and supports MCP servers to add external context like a live Figma file; for larger tasks it can delegate to parallel subagents that research, build, and review at once."}, {"label": "Sign in with your account", "body": "You authenticate by signing in through your browser with a SuperGrok or X Premium+ subscription; you can also bring an xAI API key for headless and CI use."}]}, {"kind": "ul", "items": ["Vendor: xAI", "Credential: xAI SuperGrok OAuth (`grok login`), or an xAI API key (BYOK) for headless use", "Models: xAI Grok models (the grok-build family on the xAI API), with image input"]}]}, {"id": "why-design", "heading": "Why plan mode and image-aware models fit design", "blocks": [{"kind": "p", "text": "Grok Build's design edge comes from two properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Image-aware reasoning", "body": "Because Grok models accept image input, the agent reads reference screenshots — comparing its rendered output back to an image instead of guessing from a prose description."}, {"label": "Plan mode before changes land", "body": "Plan mode drafts a structured approach you approve before files change, so design intent is reviewed up front instead of discovered after the diff."}, {"label": "Conventions in AGENTS.md", "body": "An AGENTS.md (plus the Figma MCP server) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Grok Build does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Grok Build for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Grok Build that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure AGENTS.md, add a skill, verify", "caption": "The setup sequence: install → authenticate → configure AGENTS.md → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in AGENTS.md and point Grok at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Grok renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Grok Build is turning a reference image into working, responsive UI and iterating until it matches — leaning on plan mode to agree on the approach and the image-aware model to compare output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in AGENTS.md, and tell Grok where the tokens and canonical primitives live.", "Use plan mode to review the approach, then run a dev server and have Grok render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Grok compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Attach your reference images and give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Grok when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, and subagents", "blocks": [{"kind": "p", "text": "Three extension points make Grok Build practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md context", "body": "Project rules live in an AGENTS.md at the repo root. It is the durable home for your design conventions, read on every run — and it is the same open format other agents understand, so the rules travel with you."}, {"label": "MCP servers", "body": "Configure MCP servers to bring in design context and external tools, most relevantly the Figma MCP server — the portable way to feed real specs into code, that works across agents, not just Grok."}, {"label": "Subagents and built-in tools", "body": "Grok Build can spawn parallel subagents to research, build, and review at once, and its file, shell, and search tools let it gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Grok Build", "Plan-mode review before changes land, image-aware Grok models, and parallel subagents; signs in with your SuperGrok account", "Reviewed, plan-first UI builds with xAI models in the loop"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a very large context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Grok Build; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in AGENTS.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Grok Build inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Grok Build as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Grok good is there from the first run, not assembled by hand each time. Open Design is independent and Apache-2.0, and it runs on your own machine, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Grok Build as your agent.", "Authenticate with your SuperGrok account or an xAI API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Grok Build agent, same credentials — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Grok Build really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Grok Build produces production-quality, responsive UI, and its image-aware Grok models help verify output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "How do I authenticate Grok Build?", "text": "You sign in through your browser with a SuperGrok or X Premium+ subscription (`grok login`), so there is no API key to manage. For headless or CI use you can bring an xAI API key instead. Open Design never proxies your credentials either way."}, {"name": "What makes Grok Build good for design specifically?", "text": "Two things: its plan mode lets you review the approach before any change lands, and its Grok models accept image input, so it reads reference screenshots well. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Grok Build or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Grok Build's edge is plan-mode review and image-aware xAI models. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Grok Build to Figma?", "text": "Add the Figma MCP server to your MCP configuration. Grok can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with xAI?", "text": "No. Grok Build is a product of xAI; Open Design is an independent open-source project that supports it as a first-party adapter. Grok is a trademark of xAI."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your xAI credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Grok Build, the open way.", "ctaBody": "Bring your own SuperGrok account or xAI API key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Grok Build inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Grok Build", "aboutBody": ["Grok Build is xAI's terminal coding agent, shipped as Grok Build. It reads your codebase, edits files, runs shell commands, and plans multi-step engineering work before it acts.", "It is built on xAI's Grok models, which accept image input, so it can reason about a reference screenshot alongside the code it writes, and it reads an AGENTS.md for project conventions.", "Open Design treats Grok Build as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "xAI", "credentialLabel": "Credential", "credential": "xAI SuperGrok OAuth (`grok login`)", "designTitle": "Designing with Grok Build", "designLead": "Grok Build's design strengths cluster around its workflow and models:", "designPoints": [{"label": "Image-aware screenshot → UI", "body": "Grok models accept image input, turning a reference image into responsive markup and checking the result against it."}, {"label": "Plan mode before changes", "body": "A structured plan you approve before files change, so design intent is reviewed up front instead of after the diff."}, {"label": "AGENTS.md + MCP", "body": "Context files carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Sign in with your account", "body": "Authenticate through SuperGrok or X Premium+ with OAuth, or bring an xAI API key (BYOK) for headless use."}], "linksTitle": "Real-world resources", "linksLead": "Official pages and docs for Grok Build (Grok Build):", "links": [{"label": "Grok Build (Grok Build)", "href": "https://x.ai/cli", "source": "xAI"}, {"label": "Introducing Grok Build", "href": "https://x.ai/news/grok-build-cli", "source": "News · xAI"}, {"label": "xAI models documentation", "href": "https://docs.x.ai/docs/models", "source": "Docs · xAI"}], "withOdTitle": "Grok Build + Open Design", "withOdLead": "Open Design is the open-source design layer around Grok Build: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Grok Build as your agent.", "Authenticate with your SuperGrok account or an xAI API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Grok Build agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by xAI?", "text": "No. Grok Build is an xAI product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "How do I sign in?", "text": "Grok Build signs in through your browser with a SuperGrok or X Premium+ subscription, or you can bring an xAI API key (BYOK). Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with xAI?", "text": "No. Open Design is independent; Grok is a trademark of xAI."}], "ctaTitle": "Design with Grok Build, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  kimi: {"title": "Kimi CLI for design — Open Design", "description": "How people use Moonshot AI’s Kimi CLI for UI and web design — its Kimi K2 agentic models, large context, AGENTS.md and MCP — and how Open Design turns Kimi CLI into a local-first, open-source design agent.", "breadcrumb": "Kimi CLI", "label": "Agent · Kimi CLI", "heading": "Kimi CLI for design.", "lead": "Kimi CLI is Moonshot AI’s open-source terminal agent, powered by the Kimi K2 model series. Its strong agentic coding and large context window let it hold a whole design system and iterate against references — once you give it conventions and a verification loop, it becomes a real design tool. Open Design wires it into an open-source design workflow: your Moonshot API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Kimi CLI turns references and conventions into responsive UI with the agentic Kimi K2 models and a large context window, with BYOK or an OAuth login. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Kimi CLI", "Designing with Kimi CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Kimi CLI into a local-first, open-source design agent — your Moonshot API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Kimi CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI is Moonshot AI’s open-source AI agent for the terminal. Two things make it interesting for design specifically: it is powered by the Kimi K2 series — a trillion-parameter mixture-of-experts model meticulously optimized for agentic coding and tool use; and that model carries a large context window (256k tokens on recent K2 releases), big enough to hold an entire design system and codebase at once. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and you can start with an OAuth login or your own Moonshot API key. This is a practical, end-to-end guide to using Kimi CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Kimi CLI actually is, why its agentic Kimi K2 models and large context fit design, how to set it up from zero, the reference-to-UI loop, how AGENTS.md, MCP, and subagents extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Kimi CLI design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Kimi CLI reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — with a whole design system in context."}, "tocLabel": "On this page", "toc": [{"id": "what-is-kimi", "label": "What Kimi CLI actually is"}, {"id": "why-design", "label": "Why agentic K2 + large context fit design"}, {"id": "setup", "label": "Set up Kimi CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "AGENTS.md, MCP, and subagents"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Kimi CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kimi", "heading": "What Kimi CLI actually is", "blocks": [{"kind": "p", "text": "Kimi CLI is an open-source (Apache-2.0) AI agent that Moonshot AI ships for the terminal. It reads your repository, edits files, runs shell commands, searches files, fetches web pages, and chooses its next step from the feedback it gets — planning and verifying work from natural-language tasks rather than just completing lines. It is a Python tool, installed with uv, and it drives the Kimi K2 model family behind the scenes."}, {"kind": "p", "text": "For design work, two properties stand out. The Kimi K2 models are explicitly tuned for agentic, long-horizon coding and tool use, so the agent can carry a multi-step build through to a working result. And the context window reaches up to 256k tokens on recent K2 releases, large enough to hold your whole design system, component library, and reference set at once instead of summarizing them away."}, {"kind": "steps", "items": [{"label": "Context files", "body": "Kimi CLI reads an AGENTS.md file for persistent project context — the natural place to encode your design conventions, tokens, and review checklists. Run /init to scaffold one for a project that does not have it."}, {"label": "MCP, ACP + subagents", "body": "It manages MCP servers conversationally with /mcp-config, exposes a session over the Agent Client Protocol (kimi acp) to Zed and JetBrains, and can dispatch built-in coder, explore, and plan subagents in isolated contexts."}, {"label": "Login or BYOK", "body": "On first launch, /login lets you authorize via OAuth (Kimi Code) or enter your own Moonshot API key; Kimi’s platform also exposes OpenAI- and Anthropic-compatible endpoints."}]}, {"kind": "ul", "items": ["Vendor: Moonshot AI", "Credential: Moonshot API key (BYOK), or OAuth login via Kimi Code", "License: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Why agentic K2 models and a large context fit design", "blocks": [{"kind": "p", "text": "Kimi CLI’s design edge comes from two model properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Agentic, long-horizon coding", "body": "The Kimi K2 models are optimized for tool use and multi-step work, so the agent can take a reference and a brief and actually build, run, and refine the UI rather than stopping at a first draft."}, {"label": "A large context window", "body": "Up to 256k tokens on recent K2 releases means the whole design system, tokens, and many reference states fit at once, so the agent reuses your real primitives rather than inventing one-off styles."}, {"label": "Conventions in AGENTS.md", "body": "An AGENTS.md (plus an MCP server like Figma) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Kimi CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Kimi CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Kimi CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure AGENTS.md, add a skill, verify", "caption": "The setup sequence: install → authenticate → configure AGENTS.md → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in AGENTS.md and point Kimi at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Kimi renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Kimi CLI is turning reference material into working, responsive UI and iterating until it matches — feeding the agent your references and having it compare its rendered output back to them in a real browser."}, {"kind": "ol", "items": ["Start from the clearest references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong agent.", "Keep your design system and conventions in AGENTS.md, and tell Kimi where the tokens and canonical primitives live.", "Run a dev server and have Kimi render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Kimi compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Point Kimi at your references and the dev server, then give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Kimi when you revert), so each pass builds on a clean base. Kimi CLI can also take a short screen recording or demo clip when a flow is hard to describe in words."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, and subagents", "blocks": [{"kind": "p", "text": "Three extension points make Kimi CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md context", "body": "Project rules live in an AGENTS.md at the repo root. It is the durable home for your design conventions, read on every run — and it is the same portable format other agents use."}, {"label": "MCP servers", "body": "Add MCP servers conversationally with /mcp-config — the portable way to bring in design context and external tools, most relevantly the Figma MCP server, that work across agents, not just Kimi."}, {"label": "Subagents and the plugin marketplace", "body": "Dispatch built-in coder, explore, and plan subagents in isolated contexts, and install skills, MCP servers, and data sources from the marketplace or any GitHub repo to gather references and run the verification loop."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Kimi CLI", "Agentic Kimi K2 models tuned for long-horizon coding and tool use, with a large context; open-source and BYOK", "Multi-step builds and holding a whole design system in context affordably"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; free tier", "Screenshot-heavy work and very large context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Kimi CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have Kimi render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in AGENTS.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Kimi CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Kimi CLI as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Kimi good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Kimi CLI as your agent.", "Authenticate with your Moonshot API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Kimi CLI agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Kimi CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Kimi CLI produces production-quality, responsive UI, and its agentic Kimi K2 models can render and verify output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Kimi CLI?", "text": "You bring your own credentials: authorize via the Kimi Code OAuth login or paste a Moonshot API key (BYOK), billed by Moonshot’s platform. Open Design never proxies your credentials either way."}, {"name": "What makes Kimi CLI good for design specifically?", "text": "Two things: the Kimi K2 models are tuned for agentic, long-horizon coding and tool use, so the agent can build and refine through to a working result, and the context window reaches up to 256k tokens, enough to hold a whole design system and reference set at once. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Kimi CLI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Kimi CLI’s edge is its agentic Kimi K2 models and a large context with BYOK economics. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Kimi CLI to Figma?", "text": "Run /mcp-config inside Kimi CLI to add and authenticate the Figma MCP server. Kimi can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Moonshot AI?", "text": "No. Kimi CLI is a product of Moonshot AI; Open Design is an independent open-source project that supports it as a first-party adapter. Kimi is a trademark of Moonshot AI."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Moonshot credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Kimi CLI, the open way.", "ctaBody": "Bring your own Moonshot API key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Kimi CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Kimi CLI", "aboutBody": ["Kimi CLI is Moonshot AI’s open-source (Apache-2.0) terminal AI agent, powered by the Kimi K2 model series. It reads your codebase, edits files, runs commands, searches files, and fetches the web.", "The Kimi K2 models are tuned for agentic, long-horizon coding, and the context window reaches up to 256k tokens, so it holds a whole design system at once.", "Open Design treats Kimi CLI as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Moonshot", "credentialLabel": "Credential", "credential": "Moonshot API key (BYOK)", "designTitle": "Designing with Kimi CLI", "designLead": "Kimi CLI’s design strengths cluster around its model and context:", "designPoints": [{"label": "Agentic reference → UI", "body": "Long-horizon Kimi K2 coding turns references into responsive markup and checks the result against them in a real browser."}, {"label": "256k-token context", "body": "A whole design system, component library, and reference set fit at once, so output reuses your real primitives."}, {"label": "AGENTS.md + MCP", "body": "Context files carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Open and BYOK", "body": "Apache-2.0 with an OAuth login or your own Moonshot API key, plus OpenAI- and Anthropic-compatible endpoints."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for Kimi CLI:", "links": [{"label": "MoonshotAI/kimi-cli (GitHub)", "href": "https://github.com/MoonshotAI/kimi-cli", "source": "GitHub · Moonshot AI"}, {"label": "Kimi CLI documentation — Getting started", "href": "https://moonshotai.github.io/kimi-cli/en/guides/getting-started.html", "source": "Docs · Moonshot AI"}, {"label": "Kimi K2 (GitHub)", "href": "https://github.com/MoonshotAI/Kimi-K2", "source": "GitHub · Moonshot AI"}], "withOdTitle": "Kimi CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Kimi CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Kimi CLI as your agent.", "Authenticate with your Moonshot API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Kimi CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Moonshot AI?", "text": "No. Kimi CLI is a Moonshot AI product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "You bring your own credentials — an OAuth login or a Moonshot API key (BYOK), billed by Moonshot. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Moonshot AI?", "text": "No. Open Design is independent; Kimi is a trademark of Moonshot AI."}], "ctaTitle": "Design with Kimi CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  deepseek: {"title": "DeepSeek TUI for design — Open Design", "description": "How people use a DeepSeek-powered terminal coding agent for UI and web design — its strong coding models, 1M-token context, cost-efficiency, context files and MCP — and how Open Design turns the DeepSeek TUI into a local-first, open-source design agent.", "breadcrumb": "DeepSeek TUI", "label": "Agent · DeepSeek TUI", "heading": "DeepSeek TUI for design.", "lead": "DeepSeek TUI is a terminal coding agent driven by DeepSeek’s models. Its strong, cost-efficient coding models and 1M-token context can hold a whole design system and codebase at once, which makes it a real design tool — once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your DeepSeek API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "DeepSeek TUI turns described layouts and reference conventions into responsive UI with strong coding models, a huge context window, and very low per-token cost — bring your own DeepSeek API key. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is DeepSeek TUI", "Designing with DeepSeek TUI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns the DeepSeek TUI into a local-first, open-source design agent — your DeepSeek API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use DeepSeek TUI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI is a terminal-based AI coding agent powered by DeepSeek’s models. Two things make it interesting for design specifically: its coding models are strong and unusually cost-efficient, so you can iterate aggressively without watching a meter; and its context window reaches up to 1M tokens, large enough to hold an entire design system and codebase at once instead of summarizing them away. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using a DeepSeek-powered terminal agent for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what the DeepSeek TUI actually is, why strong coding models, a huge context, and low cost fit design, how to set it up from zero, the reference-to-UI loop, how context files and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open and run on your own machine."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "DeepSeek TUI design feedback loop: a terminal agent reading references and conventions, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: DeepSeek TUI reads your references and conventions in the terminal, builds and verifies the UI in a real browser, and iterates against them — with a whole design system in context."}, "tocLabel": "On this page", "toc": [{"id": "what-is-deepseek", "label": "What DeepSeek TUI actually is"}, {"id": "why-design", "label": "Why strong coding models + huge context fit design"}, {"id": "setup", "label": "Set up DeepSeek TUI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "Context files, MCP, and tools"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with DeepSeek TUI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-deepseek", "heading": "What DeepSeek TUI actually is", "blocks": [{"kind": "p", "text": "A DeepSeek TUI is a keyboard-driven terminal AI agent that runs DeepSeek’s models. It reads your repository, edits files, runs shell commands, manages git, and can search the web — planning and verifying work from natural-language tasks rather than just completing lines. DeepSeek itself is the model provider: an OpenAI-compatible API (it also exposes an Anthropic-format endpoint), so a wide range of community terminal agents can be pointed at DeepSeek by setting a base URL and key. Several open-source TUIs ship DeepSeek as a first-class provider."}, {"kind": "p", "text": "For design work, three properties stand out. DeepSeek’s coding models are strong, so the agent reasons about layout, structure, and component hierarchy from a clear description. Its context window reaches up to 1M tokens, large enough to hold your whole design system and component library at once. And its pricing is very low per token, with prefix context-caching on top — so iterating on a design costs little."}, {"kind": "steps", "items": [{"label": "Context files", "body": "Terminal agents read a project context file (an AGENTS.md-style file, or the agent’s own convention) for persistent rules — the natural place to encode your design conventions, tokens, and review checklists."}, {"label": "Tools + MCP", "body": "Most DeepSeek TUIs ship file, shell, git, and web tools, and support MCP servers to add external context like a live Figma file — DeepSeek’s API supports tool calling, which these agents rely on."}, {"label": "Bring your own key", "body": "You authenticate with a DeepSeek API key from the DeepSeek platform. Because the API is OpenAI-compatible, pointing an agent at DeepSeek is usually two lines: base URL and key."}]}, {"kind": "ul", "items": ["Vendor: DeepSeek (model and API provider)", "Credential: DeepSeek API key (BYOK) from the DeepSeek platform", "Models: deepseek-v4-flash and deepseek-v4-pro (text-only; no native image input)"]}]}, {"id": "why-design", "heading": "Why strong coding models and a huge context fit design", "blocks": [{"kind": "p", "text": "DeepSeek TUI’s design edge comes from the model and its economics — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Strong, cost-efficient coding", "body": "DeepSeek’s coding models are capable and inexpensive, so the agent reasons well about layout and structure and you can iterate many times without cost being the constraint."}, {"label": "A 1M-token context window", "body": "A large context means the whole design system, tokens, and many reference states fit at once, so the agent reuses your real primitives rather than inventing one-off styles — and context caching keeps repeated prompts cheap."}, {"label": "Conventions in a context file", "body": "A project context file (plus the Figma MCP server) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real references."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: DeepSeek TUI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up DeepSeek TUI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a DeepSeek TUI that can build and verify UI. Exact install and command names vary by which terminal agent you pick, so the steps below stay at the level that holds across them."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Five-step setup flow: get key, install agent, configure context file, add a skill, verify", "caption": "The setup sequence: get a key → point the agent at DeepSeek → configure a context file → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in the agent’s context file and point it at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so the agent renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "DeepSeek’s models are text-only — they do not read images natively — so the highest-leverage design loop is turning clear references and described layouts into working, responsive UI, then verifying the result in a real browser rather than asking the model to look at a screenshot."}, {"kind": "ol", "items": ["Start from the clearest references you have — and describe multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model. Spell out spacing, hierarchy, and the components to reuse.", "Keep your design system and conventions in the context file, and tell the agent where the tokens and canonical primitives live.", "Run a dev server and have the agent render in a real browser, resizing to breakpoints to check the result — this is where verification happens, since the model cannot see the image itself.", "Iterate by having the agent compare the rendered DOM and computed styles back to your described spec — not merely confirm it builds."]}, {"kind": "p", "text": "Describe the target precisely and give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling the agent when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Context files, MCP, and tools", "blocks": [{"kind": "p", "text": "Three extension points make a DeepSeek TUI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Project context file", "body": "Project rules live in a context file at the repo root (with global and team layers). It is the durable home for your design conventions, read on every run."}, {"label": "MCP servers", "body": "Configure MCP servers in the agent — the portable way to bring in design context and external tools, most relevantly the Figma MCP server, that work across agents, not just one. DeepSeek’s API supports the tool calling these servers rely on."}, {"label": "Built-in tools", "body": "DeepSeek TUIs ship file, shell, git, and web tools so the agent can gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["DeepSeek TUI", "Strong, very cost-efficient coding models with open weights and a 1M-token context; text-only (no native vision)", "High-volume iteration on a budget and holding a whole design system in context"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Native multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work where the agent reads references directly"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to DeepSeek TUI; they are what happens when any agent runs without a curated design context. Because DeepSeek is text-only, it is especially important to verify in a real browser rather than trusting the model to “look” at the result."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints with a browser tool — essential here, since the model cannot read a screenshot itself — so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and concrete, described references are the single biggest lever on output quality."}, {"label": "Encode rules in the context file", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with DeepSeek TUI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats the DeepSeek agent as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes DeepSeek good is there from the first run, not assembled by hand each time. Both are open and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select the DeepSeek TUI as your agent.", "Authenticate with your own DeepSeek API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same DeepSeek agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can DeepSeek TUI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and concrete references in context, a DeepSeek-powered terminal agent produces production-quality, responsive UI, and you verify the output in a real browser. DeepSeek’s models are text-only, so the verification loop replaces native image reading. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "How much does it cost to design with DeepSeek TUI?", "text": "Little — DeepSeek’s API is among the cheapest per token, and prefix context-caching cuts the cost of repeated prompts further, so you can iterate aggressively. You bring your own DeepSeek API key (BYOK); Open Design never proxies your credentials."}, {"name": "What makes DeepSeek good for design specifically?", "text": "Strong, cost-efficient coding models, open weights, and a 1M-token context that holds an entire design system and reference set at once. DeepSeek is text-only — it does not read images natively — so taste still comes from the design system, skill, and described references you supply, verified in a browser."}, {"name": "DeepSeek TUI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; DeepSeek TUI’s edge is open weights, very low cost, and a huge context for high-volume iteration. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect DeepSeek TUI to Figma?", "text": "Add the Figma MCP server in your terminal agent’s MCP configuration. The agent can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it. DeepSeek’s API supports the tool calling MCP relies on."}, {"name": "Is Open Design affiliated with DeepSeek?", "text": "No. DeepSeek is the model and API provider; Open Design is an independent open-source project that supports DeepSeek-powered terminal agents as a first-party adapter. DeepSeek is a trademark of DeepSeek."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your DeepSeek API key is used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with DeepSeek TUI, the open way.", "ctaBody": "Bring your own DeepSeek API key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use DeepSeek TUI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is DeepSeek TUI", "aboutBody": ["DeepSeek TUI is a terminal AI coding agent driven by DeepSeek’s models. It reads your codebase, edits files, runs commands, manages git, and searches the web. DeepSeek is the model provider, exposing an OpenAI-compatible API (and an Anthropic-format endpoint).", "Its coding models are strong and very cost-efficient, and its context window reaches 1M tokens, so it holds a whole design system at once. The models are text-only, so design references are described and verified in a browser rather than read as images.", "Open Design treats the DeepSeek agent as a first-party adapter, so it slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "DeepSeek", "credentialLabel": "Credential", "credential": "DeepSeek API key (BYOK)", "designTitle": "Designing with DeepSeek TUI", "designLead": "DeepSeek TUI’s design strengths cluster around its model and economics:", "designPoints": [{"label": "Strong, cheap coding", "body": "Capable coding models at very low per-token cost turn described layouts into responsive markup and let you iterate freely."}, {"label": "1M-token context", "body": "A whole design system, component library, and reference set fit at once, so output reuses your real primitives — with context caching on repeats."}, {"label": "Context file + MCP", "body": "Context files carry your conventions; the Figma MCP server brings real design context into code via DeepSeek’s tool calling."}, {"label": "Open weights, BYOK", "body": "DeepSeek ships open weights, and you bring your own DeepSeek API key — text-only, so verify visuals in a real browser."}], "linksTitle": "Real-world resources", "linksLead": "Official docs for the DeepSeek API and platform:", "links": [{"label": "DeepSeek API documentation", "href": "https://api-docs.deepseek.com/", "source": "Docs · DeepSeek"}, {"label": "Models & pricing", "href": "https://api-docs.deepseek.com/quick_start/pricing", "source": "Docs · DeepSeek"}, {"label": "Anthropic API compatibility", "href": "https://api-docs.deepseek.com/guides/anthropic_api", "source": "Docs · DeepSeek"}], "withOdTitle": "DeepSeek TUI + Open Design", "withOdLead": "Open Design is the open-source design layer around the DeepSeek TUI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select the DeepSeek TUI as your agent.", "Authenticate with your own DeepSeek API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same DeepSeek agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by DeepSeek?", "text": "No. DeepSeek is the model and API provider; Open Design is an independent open-source project that integrates DeepSeek-powered terminal agents as a first-party adapter."}, {"name": "Do I need to pay?", "text": "You bring your own DeepSeek API key (BYOK). DeepSeek’s API is very low-cost per token, and Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with DeepSeek?", "text": "No. Open Design is independent; DeepSeek is a trademark of DeepSeek."}], "ctaTitle": "Design with DeepSeek TUI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  'trae-cli': {"title": "Trae CLI for design — Open Design", "description": "How people use ByteDance’s Trae CLI (trae-agent) for UI and web design — its open-source, model-agnostic CLI agent, bring-your-own LLM provider, and config-driven workflow — and how Open Design turns Trae CLI into a local-first, open-source design agent over ACP.", "breadcrumb": "Trae CLI", "label": "Agent · Trae CLI", "heading": "Trae CLI for design.", "lead": "Trae CLI is ByteDance’s open-source terminal agent (trae-agent). It is model-agnostic — you point it at the LLM provider you trust — and it reads your repo, edits files, and runs commands from natural-language tasks, which makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow over ACP: your own provider key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Trae CLI is a free, open-source, model-agnostic coding agent: bring your own LLM provider key and it builds UI from natural-language tasks. Open Design drives it over ACP and gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Trae CLI", "Designing with Trae CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Trae CLI into a local-first, open-source design agent — your own LLM provider key, your files, a curated skill and design-system library around it, driven over ACP.", "heroCtaActions": [{"label": "Use Trae CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI is ByteDance’s open-source AI agent for the terminal, shipped as the trae-agent project. Two things make it interesting for design specifically: it is model-agnostic, so you can bring whichever LLM provider you trust rather than being locked to one vendor; and it is a transparent, MIT-licensed agent that reads your codebase, edits files, and runs shell commands from natural-language tasks. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and it is free and open to start, you only supply a provider key. This is a practical, end-to-end guide to using Trae CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Trae CLI actually is, why an open, model-agnostic agent fits design, how to set it up from zero, the screenshot-to-UI loop, how its config file and tools extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine, with Open Design driving Trae CLI over the Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Trae CLI design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Trae CLI reads your references and conventions in the terminal, builds and verifies the UI in a real browser, and iterates against them."}, "tocLabel": "On this page", "toc": [{"id": "what-is-trae-cli", "label": "What Trae CLI actually is"}, {"id": "why-design", "label": "Why an open, model-agnostic agent fits design"}, {"id": "setup", "label": "Set up Trae CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Config, tools, and providers"}, {"id": "vs", "label": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Trae CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-trae-cli", "heading": "What Trae CLI actually is", "blocks": [{"kind": "p", "text": "Trae CLI is the command-line agent from ByteDance’s open-source trae-agent project. It reads your repository, views, creates, and edits files, and runs shell commands in a persistent environment — planning and verifying work from natural-language tasks rather than just completing lines. It is MIT-licensed and built around a transparent, modular architecture so it is easy to inspect and extend. It is distinct from the separate Trae IDE, ByteDance’s VS Code-based AI editor, though both come from the same vendor."}, {"kind": "p", "text": "For design work, two properties stand out. It is model-agnostic — you choose the LLM provider, so you are never tied to a single model’s strengths or limits. And it is fully open and config-driven, so its behavior, tools, and provider can be pinned down in version control alongside your project rather than hidden behind a hosted service."}, {"kind": "steps", "items": [{"label": "Run and interactive modes", "body": "Trae CLI runs a single task with `trae-cli run \"...\"` or holds a continuous session with `trae-cli interactive` — the natural place to iterate on a UI against your design conventions."}, {"label": "Built-in tools", "body": "It ships file-editing, bash/shell execution, and structured reasoning tools out of the box, so it can build, run a dev server, and inspect runtime errors without leaving the terminal."}, {"label": "Bring your own provider", "body": "You supply an API key for the provider you trust — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, or a local Ollama model — via environment variables or a config file."}]}, {"kind": "ul", "items": ["Vendor: ByteDance (open-source trae-agent project)", "Credential: an LLM provider API key (BYOK) — e.g. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, or a local Ollama model", "License: MIT, open source"]}]}, {"id": "why-design", "heading": "Why an open, model-agnostic agent fits design", "blocks": [{"kind": "p", "text": "Trae CLI’s design edge comes from being open and provider-flexible — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Model-agnostic by design", "body": "Because you choose the provider, you can route design work to whichever model reasons best about layout and frontend code today, and swap it later without changing your workflow."}, {"label": "Open and config-driven", "body": "The agent, its tools, and its provider are pinned in a config file you can commit, so a team gets the same agent behavior on every machine instead of drifting per-developer."}, {"label": "Conventions in your repo", "body": "Point the agent at your tokens, components, and real specs — kept in your project — so it works against a brand instead of defaulting to a generic look."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Trae CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs and feeds them to Trae CLI over ACP, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Trae CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Trae CLI that can build and verify UI. Trae CLI is installed from source with uv, then configured with the LLM provider you want to use."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure conventions, add a skill, verify", "caption": "The setup sequence: install → authenticate with a provider key → configure your design conventions → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Keep your tokens, primitives, and conventions in the repo and point Trae CLI at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Have Trae CLI run a dev server and render in a real browser so it checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Trae CLI is turning a reference image into working, responsive UI and iterating until it matches. Because Trae CLI is model-agnostic, point it at a provider whose model handles your references well, and lean on a real browser to check the result."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and describe multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in the repo, and tell Trae CLI where the tokens and canonical primitives live.", "Run a dev server and have Trae CLI render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Trae CLI compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Run an interactive session and give concrete constraints rather than a one-line ask:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Trae CLI when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Config, tools, and providers", "blocks": [{"kind": "p", "text": "Three extension points make Trae CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Config file", "body": "Trae CLI reads a trae_config.yaml that pins your provider, model, and settings — the durable, version-controllable home for how the agent runs on a project."}, {"label": "Provider choice", "body": "Because it supports many providers (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), you route design work to the model you trust and swap it without rewiring your workflow."}, {"label": "Built-in tools", "body": "Its file-editing, shell, and structured-reasoning tools let it gather context, build, run a dev server, and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, agent-level capabilities — exactly the kind of thing Open Design is built to orchestrate over ACP, rather than re-create per project."}]}, {"id": "vs", "heading": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Trae CLI", "Open-source (MIT) and model-agnostic; bring your own provider key, config-driven and transparent", "Teams that want a free, inspectable agent and the freedom to choose or swap LLM providers"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Trae CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have Trae CLI render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in your repo", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Trae CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Trae CLI as a first-party adapter — driving it over the Agent Client Protocol (ACP) via its trae-cli binary — and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI, so the design context that makes Trae CLI good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Trae CLI as your agent.", "Authenticate with your own LLM provider key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Trae CLI agent, same provider key — plus a real, portable, open-source design workflow around it. It is local-first and open-source, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Trae CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference context, Trae CLI produces production-quality, responsive UI, and because it is model-agnostic you can route the work to the provider that reasons best about your frontend. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Trae CLI?", "text": "Trae CLI itself is free and open-source (MIT). You bring your own LLM provider key, so your only cost is whatever that provider charges — or nothing if you run a local model via Ollama. Open Design never proxies your credentials either way."}, {"name": "What makes Trae CLI good for design specifically?", "text": "Two things: it is model-agnostic, so you choose the LLM provider best suited to frontend work, and it is fully open and config-driven, so its behavior is transparent and reproducible across a team. But taste still comes from the design system, skill, and references you supply."}, {"name": "Trae CLI or Claude Code for frontend design?", "text": "Both are capable. Claude Code is known for specific, codebase-aware design decisions; Trae CLI’s edge is being open-source and provider-flexible, so you are never locked to one model. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "What does Open Design need to run Trae CLI?", "text": "Open Design drives Trae CLI’s trae-cli binary over the Agent Client Protocol (ACP) and uses your configured LLM provider key. You select Trae CLI as your agent, point it at a provider, and Open Design supplies the curated design context around it."}, {"name": "Is Open Design affiliated with ByteDance or Trae?", "text": "No. Trae CLI (trae-agent) is a product of ByteDance; Open Design is an independent open-source project that supports it as a first-party adapter. Trae is a trademark of ByteDance."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and open-source. Your files, artifacts, and DESIGN.md stay in your own repo, and your LLM provider credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Trae CLI, the open way.", "ctaBody": "Bring your own LLM provider key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Trae CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Trae CLI", "aboutBody": ["Trae CLI is ByteDance’s open-source (MIT) terminal AI agent, shipped as the trae-agent project. It reads your codebase, edits files, and runs shell commands from natural-language tasks.", "It is model-agnostic — you bring your own LLM provider key (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, or a local Ollama model) — and its behavior is pinned in a config file you can commit.", "Open Design treats Trae CLI as a first-party adapter and drives it over the Agent Client Protocol (ACP), so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "ByteDance", "credentialLabel": "Credential", "credential": "Your own LLM provider API key (BYOK) — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, or local Ollama", "designTitle": "Designing with Trae CLI", "designLead": "Trae CLI’s design strengths cluster around its open, model-agnostic nature:", "designPoints": [{"label": "Bring your own model", "body": "Model-agnostic by design, so you route UI work to whichever LLM provider reasons best about your frontend — and swap it later."}, {"label": "Open and config-driven", "body": "MIT-licensed and pinned in a trae_config.yaml, so agent behavior is transparent and reproducible across a team."}, {"label": "Real browser loop", "body": "File, shell, and reasoning tools let it build, run a dev server, and verify the UI across breakpoints."}, {"label": "Free to start", "body": "The agent itself is free; your only cost is your chosen provider — or nothing with a local Ollama model."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and product pages for Trae CLI:", "links": [{"label": "bytedance/trae-agent (GitHub)", "href": "https://github.com/bytedance/trae-agent", "source": "GitHub · ByteDance"}, {"label": "Trae — Collaborate with Intelligence", "href": "https://www.trae.ai/", "source": "Official site · ByteDance"}, {"label": "Trae documentation", "href": "https://docs.trae.ai/ide/agent", "source": "Docs · ByteDance"}], "withOdTitle": "Trae CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Trae CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI, driven over ACP.", "withOdSteps": ["Install Open Design and select Trae CLI as your agent.", "Authenticate with your own LLM provider key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Trae CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by ByteDance?", "text": "No. Trae CLI (trae-agent) is a ByteDance product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "Trae CLI is free and open-source; you bring your own LLM provider key (BYOK), so your only cost is your chosen provider. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with ByteDance?", "text": "No. Open Design is independent; Trae is a trademark of ByteDance."}], "ctaTitle": "Design with Trae CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  aider: {"title": "Aider for design — Open Design", "description": "How people use Aider — the open-source, model-agnostic AI pair-programmer in your terminal — for UI and web design, with git-native edits, a CONVENTIONS.md file, image support, and BYOK, and how Open Design turns Aider into a local-first, open-source design agent.", "breadcrumb": "Aider", "label": "Agent · Aider", "heading": "Aider for design.", "lead": "Aider is the open-source AI pair-programmer that lives in your terminal and works directly on your git repo. It is model-agnostic — point it at Claude, GPT-4o, DeepSeek, or Gemini with your own key — and it edits files, auto-commits, and reads images on vision-capable models. That makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your provider keys, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Aider turns reference images and prompts into working UI, editing your git repo and committing each change — with whichever model you bring (BYOK). Open Design gives it a curated design-system and skill library plus a desktop workflow — keep your keys and everything local.", "toc": ["What is Aider", "Designing with Aider", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Aider into a local-first, open-source design agent — your own provider API keys, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Aider inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider is an open-source AI pair-programming tool that runs in your terminal and works on the code in your git repository. Two things make it interesting for design specifically: it is model-agnostic, so you bring your own key for almost any LLM — Claude, GPT-4o, DeepSeek, Gemini, or a local model — and it is git-native, editing files in place and committing each change with a sensible message so every iteration is reviewable and reversible. On vision-capable models it can also read images, so a screenshot becomes part of the prompt. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Aider for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Aider actually is, why a model-agnostic, git-native tool fits design, how to set it up from zero, the screenshot-to-UI loop, how CONVENTIONS.md and Aider's commands extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Aider design feedback loop: a terminal agent reading a reference image, a git repo with commits, a browser rendering the UI, with a feedback arrow looping back", "caption": "The core loop: Aider reads your references in the terminal, edits and commits the UI in your git repo, and iterates against them — with whichever model you bring."}, "tocLabel": "On this page", "toc": [{"id": "what-is-aider", "label": "What Aider actually is"}, {"id": "why-design", "label": "Why model-agnostic + git-native fit design"}, {"id": "setup", "label": "Set up Aider for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "CONVENTIONS.md, images, and commands"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Aider in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-aider", "heading": "What Aider actually is", "blocks": [{"kind": "p", "text": "Aider is an open-source (Apache-2.0) AI pair-programming tool that runs in your terminal. It reads your existing codebase, maps the whole repository for context, edits files in place, and automatically commits each change with a sensible message — so you can diff, manage, and undo the AI's work with the git tools you already use. It works with 100+ programming languages and starts new projects or builds on existing ones."}, {"kind": "p", "text": "For design work, two properties stand out. Aider is model-agnostic: you bring your own key and connect it to almost any LLM — Claude, GPT-4o, DeepSeek, Gemini, or a local model — so you are never locked to one provider. And on vision-capable models like GPT-4o and Claude, it can read image files, turning a reference screenshot into part of the prompt."}, {"kind": "steps", "items": [{"label": "Conventions file", "body": "Aider reads a CONVENTIONS.md file you load with /read CONVENTIONS.md (or aider --read CONVENTIONS.md) — the natural place to encode your design conventions, tokens, and review checklists as read-only context."}, {"label": "Git-native edits", "body": "Every change is applied to files in your repo and committed automatically, so each design iteration is reviewable and reversible with familiar git tools."}, {"label": "Bring your own model", "body": "Connect OpenAI, Anthropic, DeepSeek, Gemini, or a local model with your own API key; Aider is not tied to a single vendor or a hosted backend."}]}, {"kind": "ul", "items": ["Vendor: Aider (Aider-AI, open source) — model-agnostic", "Credential: your own provider API key — BYOK (OpenAI, Anthropic, DeepSeek, Gemini, or a local model)", "License: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Why a model-agnostic, git-native tool fits design", "blocks": [{"kind": "p", "text": "Aider's design edge comes from how it works with your repo and your choice of model — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Model-agnostic, BYOK", "body": "Pick the model that designs best for your task and budget — Claude, GPT-4o, DeepSeek, Gemini — and switch freely without changing your workflow, all on your own key."}, {"label": "Git-native iteration", "body": "Auto-commits make every design pass a reviewable diff you can revert, so you iterate against a clean base instead of an untracked pile of edits."}, {"label": "Conventions in CONVENTIONS.md", "body": "A CONVENTIONS.md (loaded read-only) points the agent at your tokens, components, and rules, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Aider does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Aider for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to an Aider that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Five-step setup flow: install, bring your own key, load CONVENTIONS.md, add a reference, verify", "caption": "The setup sequence: install → bring your own key → load CONVENTIONS.md → add a reference → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in CONVENTIONS.md and load it read-only, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Run a dev server and have Aider render in a real browser, checking its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Aider is turning a reference image into working, responsive UI and iterating until it matches — using a vision-capable model to compare output back to the reference, with each pass committed to git."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in CONVENTIONS.md, and tell Aider where the tokens and canonical primitives live.", "Run a dev server and check the rendered result in a real browser, resizing to breakpoints.", "Iterate by having Aider compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Add an image with /add (or /paste from the clipboard) on a vision-capable model, then give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused. Because Aider commits each change, you keep good iterations and use git (or /undo) to revert bad ones — so every pass builds on a clean base."}]}, {"id": "extend", "heading": "CONVENTIONS.md, images, and commands", "blocks": [{"kind": "p", "text": "Three capabilities make Aider practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "CONVENTIONS.md context", "body": "Load coding and design conventions with /read CONVENTIONS.md or aider --read CONVENTIONS.md, or set read: CONVENTIONS.md in .aider.conf.yml to load it every run. It is the durable home for your tokens, primitives, and rules."}, {"label": "Images and web pages", "body": "On vision-capable models, /add an image file or /paste from the clipboard to give Aider a real reference; /web <url> scrapes a page's text into the chat for additional context."}, {"label": "In-chat commands", "body": "Commands like /add to bring files into context, /read for read-only references, and /undo to roll back the last commit let it gather references and run the verification loop without leaving the terminal."}]}, {"kind": "p", "text": "These are portable, repo-native capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Aider", "Open-source, model-agnostic (BYOK), and git-native; auto-commits make every iteration reviewable and reversible", "Repo-native iteration on your existing codebase with whatever model designs best"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Aider; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints so layouts do not silently break on mobile — on a vision-capable model, feed the screenshots back in."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in CONVENTIONS.md", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Aider inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Aider as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Aider good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Aider as your agent.", "Authenticate with your own provider API key (BYOK) — OpenAI, Anthropic, DeepSeek, or Gemini; credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own git repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Aider agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and open-source, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Aider really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Aider produces production-quality, responsive UI, and on vision-capable models it reads screenshots to verify output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Which models can I use with Aider for design?", "text": "Aider is model-agnostic. You bring your own API key and connect almost any LLM — Claude, GPT-4o, DeepSeek, Gemini, or a local model. For image-based design work, use a vision-capable model like GPT-4o or Claude. Open Design never proxies your credentials."}, {"name": "What makes Aider good for design specifically?", "text": "Two things: it is model-agnostic, so you pick the model that designs best for your task, and it is git-native, committing every change so each design iteration is reviewable and reversible. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Does Aider edit my files and commit to git?", "text": "Yes. Aider edits files directly in your repository and automatically commits each change with a sensible message, so you can diff, manage, and undo the AI's work with the git tools you already use."}, {"name": "How do I give Aider my design conventions?", "text": "Create a CONVENTIONS.md with your tokens, primitives, and rules, then load it read-only with /read CONVENTIONS.md or aider --read CONVENTIONS.md (or set read: CONVENTIONS.md in .aider.conf.yml to load it every run). Aider then works against your brand instead of a default look."}, {"name": "Is Open Design affiliated with Aider?", "text": "No. Aider is an independent open-source project (Aider-AI); Open Design is a separate independent open-source project that supports Aider as a first-party adapter. The two are not affiliated."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and open-source. Your files, artifacts, and DESIGN.md stay in your own git repo, and your provider API keys are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Aider, the open way.", "ctaBody": "Bring your own provider API key, keep every file local in your git repo, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Aider inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Aider", "aboutBody": ["Aider is an open-source (Apache-2.0) AI pair-programming tool that runs in your terminal. It maps your codebase, edits files in place, and automatically commits each change with a sensible message.", "It is model-agnostic — bring your own key for Claude, GPT-4o, DeepSeek, Gemini, or a local model — and on vision-capable models it reads reference images.", "Open Design treats Aider as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Aider (Aider-AI, open source) — model-agnostic", "credentialLabel": "Credential", "credential": "Your own provider API key — BYOK (OpenAI, Anthropic, DeepSeek, Gemini, or local)", "designTitle": "Designing with Aider", "designLead": "Aider's design strengths cluster around its model freedom and git workflow:", "designPoints": [{"label": "Model-agnostic, BYOK", "body": "Connect almost any LLM with your own key, and use a vision-capable model to turn a reference image into responsive markup."}, {"label": "Git-native iteration", "body": "Auto-commits make every design pass a reviewable diff you can undo, so output stays clean and traceable."}, {"label": "CONVENTIONS.md context", "body": "A read-only conventions file carries your tokens, primitives, and design rules into every run."}, {"label": "Open source", "body": "Apache-2.0 and local-first, working directly on the code in your own repository."}], "linksTitle": "Real-world resources", "linksLead": "Official site and repo for Aider:", "links": [{"label": "Aider — AI pair programming in your terminal", "href": "https://aider.chat/", "source": "Docs · Aider"}, {"label": "Aider-AI/aider (GitHub)", "href": "https://github.com/Aider-AI/aider", "source": "GitHub · Aider-AI"}, {"label": "Aider installation guide", "href": "https://aider.chat/docs/install.html", "source": "Docs · Aider"}], "withOdTitle": "Aider + Open Design", "withOdLead": "Open Design is the open-source design layer around Aider: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Aider as your agent.", "Authenticate with your own provider API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own git repo, not a hosted cloud."], "withOdClosing": "The same Aider agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Aider?", "text": "No. Aider is an independent open-source project (Aider-AI); Open Design is a separate open-source project that integrates it as a first-party adapter."}, {"name": "Do I need a specific model?", "text": "No — Aider is model-agnostic. Bring your own key for OpenAI, Anthropic, DeepSeek, Gemini, or a local model. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Aider?", "text": "No. Open Design is independent and not affiliated with Aider."}], "ctaTitle": "Design with Aider, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  antigravity: {"title": "Antigravity for design — Open Design", "description": "How people use Google Antigravity — Google's agent-first development platform powered by multimodal Gemini 3.x models, with its Editor View, Manager Surface, integrated browser control, and Artifacts — for UI and web design, and how Open Design turns Antigravity into a local-first, open-source design agent.", "breadcrumb": "Antigravity", "label": "Agent · Antigravity", "heading": "Antigravity for design.", "lead": "Antigravity is Google's agent-first development platform. Its Gemini 3.x models read screenshots and reason about layout, its integrated browser lets agents verify what they build, and its Artifacts turn agent work into reviewable deliverables — which makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your Google account, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Antigravity turns reference images into responsive UI with multimodal Gemini 3.x models, an integrated browser for self-verification, and Artifacts you can review, free to start with a Google account. Open Design gives it a curated design-system and skill library plus a desktop workflow — keep everything local.", "toc": ["What is Antigravity", "Designing with Antigravity", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Antigravity into a local-first, open-source design agent — your Google account, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Antigravity inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity is Google's agent-first development platform, launched alongside Gemini 3. Three things make it interesting for design specifically: its agents run on natively multimodal Gemini 3.x models, so they read a screenshot and reason about layout, spacing, and hierarchy; it ships an integrated browser the agent can drive, so it renders and checks its own UI instead of guessing; and it produces Artifacts — task lists, implementation plans, screenshots, and browser recordings — that turn agent work into something you can actually review. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI — and it is free to start with a Google account. This is a practical, end-to-end guide to using Antigravity for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Antigravity actually is, why multimodal Gemini and an integrated browser fit design, how to set it up from zero, the screenshot-to-UI loop, how its agent context and tooling extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since Open Design is open-source and runs on your own machine."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Antigravity design feedback loop: an agent-first IDE reading a reference image, an integrated browser rendering the UI, and a Manager surface, with a feedback arrow looping back", "caption": "The core loop: an Antigravity agent reads your references, builds and verifies the UI in its integrated browser, and iterates against them — surfacing the work as reviewable Artifacts."}, "tocLabel": "On this page", "toc": [{"id": "what-is-antigravity", "label": "What Antigravity actually is"}, {"id": "why-design", "label": "Why multimodal Gemini + a built-in browser fit design"}, {"id": "setup", "label": "Set up Antigravity for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Agent context, tools, and Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Antigravity in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-antigravity", "heading": "What Antigravity actually is", "blocks": [{"kind": "p", "text": "Antigravity is Google's agent-first development platform — an AI-powered IDE built so autonomous agents, not sidebar chatbots, do the work. Announced on November 18, 2025 alongside Gemini 3 and available in public preview at no cost for individuals, it lets you delegate complex, multi-tool software tasks to an agent that operates across the editor, terminal, and an integrated browser. Its agents run primarily on Google's multimodal Gemini 3.x models."}, {"kind": "p", "text": "For design work, three properties stand out. Its agents read screenshots and reason about the actual layout, because Gemini 3.x is natively multimodal. It can drive a real browser, so it renders and verifies what it builds. And it surfaces Artifacts — task lists, plans, screenshots, and browser recordings — so you review tangible output instead of raw tool logs."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "The Editor View is a familiar AI IDE with tab completions and inline commands; the Manager Surface lets you spawn, orchestrate, and observe multiple agents working asynchronously across workspaces — the natural place to run a long design task."}, {"label": "Integrated browser + Artifacts", "body": "Agents can act in a built-in browser and emit Artifacts (screenshots, browser recordings, task lists, plans) you can leave feedback on — a verification loop built into the platform rather than bolted on."}, {"label": "Free to start", "body": "Signing in with a personal Google account gives generous rate limits on Gemini 3.x; the platform runs on macOS, Windows, and Linux."}]}, {"kind": "ul", "items": ["Vendor: Google", "Credential: Google account (personal Gmail), free during the public preview", "Binary: launch with agy; runs on macOS, Windows, and Linux"]}]}, {"id": "why-design", "heading": "Why multimodal Gemini and a built-in browser fit design", "blocks": [{"kind": "p", "text": "Antigravity's design edge comes from the model and the platform together — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Strong multimodal understanding", "body": "Because Gemini 3.x is natively multimodal, the agent reads reference screenshots well — comparing its rendered output back to an image instead of guessing from a prose description."}, {"label": "An integrated browser to verify", "body": "The agent drives a real browser, so it renders the UI, checks it across states, and catches broken layouts — and captures the result as a browser-recording Artifact you can review."}, {"label": "Conventions the agent reads", "body": "Encode your tokens, components, and review rules in the agent's project context so it works against your brand instead of a default look."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Antigravity does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Antigravity for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to an Antigravity agent that can build and verify UI. The exact in-app menus may shift during the preview, so this stays at the level you can rely on."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Five-step setup flow: download, sign in with Google, open project, add design rules and a skill, enable browser verification", "caption": "The setup sequence: download → sign in with Google → open your project → add design rules and a skill → use the integrated browser to verify."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in the agent's project context so output matches a brand instead of defaulting to a generic look."}, {"label": "Use the integrated browser", "body": "Have the agent render in Antigravity's built-in browser and check its output across breakpoints — verifying the UI looks right, not just that the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Antigravity is turning a reference image into working, responsive UI and iterating until it matches — leaning on the multimodal model to compare output back to the reference, and on the integrated browser to verify it."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in the agent's project context, and tell it where the tokens and canonical primitives live.", "Let the agent render in Antigravity's integrated browser, resizing to breakpoints to check the result.", "Iterate by having the agent compare its implementation back to the screenshots — not merely confirm it builds — and review the browser-recording and screenshot Artifacts it produces."]}, {"kind": "p", "text": "Attach your reference images and give concrete constraints, then let the agent verify in the browser:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling the agent when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Agent context, tools, and Artifacts", "blocks": [{"kind": "p", "text": "Three extension points make Antigravity practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Project context", "body": "Persistent project rules are the durable home for your design conventions — tokens, primitives, and review checklists the agent reads on every task, so output stays on-brand."}, {"label": "Integrated browser + terminal", "body": "Agents act across the editor, terminal, and a built-in browser, so they can gather references, run a dev server, and verify rendered UI without leaving the platform."}, {"label": "Artifacts you review", "body": "Task lists, implementation plans, screenshots, and browser recordings make agent work legible; you leave feedback on the Artifact and the agent incorporates corrections."}]}, {"kind": "p", "text": "These are the capabilities a serious design loop needs — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Antigravity", "Agent-first IDE with multimodal Gemini 3.x, an integrated browser for self-verification, and reviewable Artifacts; free in preview", "Async multi-agent builds with built-in browser verification of UI"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Open-source terminal agent on multimodal Gemini with a 1M-token context and free tier", "Screenshot-heavy terminal work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Antigravity; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in the integrated browser", "body": "Use the multimodal model and Antigravity's built-in browser to render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in project context", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them on every task."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Antigravity inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Antigravity as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Antigravity good is there from the first run, not assembled by hand each time. Open Design is open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Antigravity as your agent.", "Authenticate with your Google account — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Antigravity agent, same Google account — plus a real, portable, open-source design workflow around it. Open Design is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Antigravity really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Antigravity produces production-quality, responsive UI, and its multimodal Gemini 3.x agents verify output in the integrated browser. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Antigravity?", "text": "Antigravity is available in public preview at no cost for individuals, with generous rate limits on Gemini 3.x when you sign in with a personal Google account. Open Design never proxies your credentials either way."}, {"name": "What makes Antigravity good for design specifically?", "text": "Three things: its agents run on natively multimodal Gemini 3.x models that read reference screenshots well, it ships an integrated browser the agent can drive to verify UI, and it surfaces Artifacts — screenshots and browser recordings — you can review. Taste still comes from the design system, skill, and references you supply."}, {"name": "Antigravity or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Antigravity's edge is its agent-first platform — multimodal Gemini 3.x, an integrated browser for verification, and reviewable Artifacts. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I verify what Antigravity builds?", "text": "Antigravity ships an integrated browser its agents can drive, so they render the UI, check it across breakpoints, and capture screenshots and browser recordings as Artifacts. Reviewing those Artifacts — and having the agent compare its output back to your references — is how you keep the result on-spec."}, {"name": "Is Open Design affiliated with Google?", "text": "No. Antigravity is a product of Google; Open Design is an independent open-source project that supports it as a first-party adapter. Antigravity and Gemini are trademarks of Google."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Google credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Antigravity, the open way.", "ctaBody": "Bring your own Google account, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Antigravity inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Antigravity", "aboutBody": ["Antigravity is Google's agent-first development platform — an AI-powered IDE where autonomous agents work across the editor, terminal, and an integrated browser. It launched in public preview alongside Gemini 3.", "Its agents run on natively multimodal Gemini 3.x models, so they read reference screenshots, verify UI in a real browser, and surface Artifacts — task lists, plans, screenshots, and browser recordings — you can review.", "Open Design treats Antigravity as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Google", "credentialLabel": "Credential", "credential": "Google account (personal Gmail), free in public preview", "designTitle": "Designing with Antigravity", "designLead": "Antigravity's design strengths cluster around its agents, browser, and Artifacts:", "designPoints": [{"label": "Multimodal screenshot → UI", "body": "Gemini 3.x image understanding turns a reference image into responsive markup and checks the result against it."}, {"label": "Integrated browser verification", "body": "Agents drive a built-in browser to render UI and check it across breakpoints, capturing the result as Artifacts."}, {"label": "Editor View + Manager Surface", "body": "Code hands-on in the Editor View, or orchestrate multiple agents asynchronously from the Manager Surface."}, {"label": "Free to start", "body": "Public preview at no cost for individuals, with generous Gemini 3.x rate limits via a Google account."}], "linksTitle": "Real-world resources", "linksLead": "Official site and docs for Google Antigravity:", "links": [{"label": "Google Antigravity", "href": "https://antigravity.google/", "source": "Google"}, {"label": "Build with Google Antigravity, our new agentic development platform", "href": "https://developers.googleblog.com/build-with-google-antigravity-our-new-agentic-development-platform/", "source": "Blog · Google"}, {"label": "Getting Started with Google Antigravity", "href": "https://codelabs.developers.google.com/getting-started-google-antigravity", "source": "Codelabs · Google"}], "withOdTitle": "Antigravity + Open Design", "withOdLead": "Open Design is the open-source design layer around Antigravity: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Antigravity as your agent.", "Authenticate with your Google account — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Antigravity agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Google?", "text": "No. Antigravity is a Google product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "Antigravity is free for individuals in public preview via a Google account. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Google?", "text": "No. Open Design is independent; Antigravity and Gemini are trademarks of Google."}], "ctaTitle": "Design with Antigravity, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  reasonix: {"title": "DeepSeek Reasonix for design — Open Design", "description": "How people use DeepSeek Reasonix — the community-built, DeepSeek-native terminal coding agent — for UI and web design, and how Open Design turns it into a local-first, open-source design agent. BYOK with your own DeepSeek API key.", "breadcrumb": "DeepSeek Reasonix", "label": "Agent · DeepSeek Reasonix", "heading": "DeepSeek Reasonix for design.", "lead": "DeepSeek Reasonix is an open-source, community-built terminal coding agent powered by DeepSeek models. It reads your repo, edits files, and runs your verification loop cheaply — its whole design is built around DeepSeek's prefix cache to keep long sessions affordable. With references, conventions, and a browser check, it becomes a real design tool. Open Design wires it into an open-source design workflow: your own DeepSeek API key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "DeepSeek Reasonix is a community-built terminal agent that runs on DeepSeek's deepseek-v4-pro and deepseek-v4-flash models — cost-efficient, MIT-licensed, and BYOK with your own DeepSeek API key. It edits files in your repo and runs a verification loop. Open Design gives it a curated design-system and skill library plus a desktop workflow — keep everything local.", "toc": ["What is DeepSeek Reasonix", "Designing with DeepSeek Reasonix", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns DeepSeek Reasonix into a local-first, open-source design agent — your own DeepSeek API key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use DeepSeek Reasonix inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix is an open-source, community-built AI coding agent for the terminal, powered by DeepSeek's models. It is not an official DeepSeek product — it is maintained by the esengine GitHub author and the community, and it is built specifically around DeepSeek's prefix-cache mechanics so long, iterative sessions stay cheap. It reads your repository, edits files, runs commands, and works from natural-language tasks rather than just completing lines. You bring your own DeepSeek API key (BYOK), and the agent runs on DeepSeek models such as deepseek-v4-pro and deepseek-v4-flash. This is a practical, end-to-end guide to using DeepSeek Reasonix for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what DeepSeek Reasonix actually is, why a cost-efficient DeepSeek-powered agent fits iterative design, how to set it up from zero with your own key, the reference-to-UI loop, how skills and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "DeepSeek Reasonix design feedback loop: a terminal agent reading design references, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: DeepSeek Reasonix works in the terminal against your references and conventions, you verify the UI in a real browser, and it iterates — cheaply, thanks to DeepSeek prefix caching."}, "tocLabel": "On this page", "toc": [{"id": "what-is-reasonix", "label": "What DeepSeek Reasonix actually is"}, {"id": "why-design", "label": "Why a cost-efficient DeepSeek agent fits design"}, {"id": "setup", "label": "Set up DeepSeek Reasonix for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "Skills, MCP, and config"}, {"id": "vs", "label": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with DeepSeek Reasonix in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-reasonix", "heading": "What DeepSeek Reasonix actually is", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix is an open-source (MIT) AI coding agent for the terminal, built by the esengine GitHub author and the community. It is DeepSeek-native: engineered around DeepSeek's prefix-cache mechanics so that long, iterative sessions stay cheap. It reads your repository, edits files with a review-gated SEARCH/REPLACE editor, runs shell commands, and works from natural-language tasks — planning and verifying rather than just completing lines. It is important to be clear that this is a community project, not an official product from DeepSeek the company."}, {"kind": "p", "text": "For design work, what matters is that it is a capable, repo-aware coding agent that runs on strong DeepSeek models at low cost. The DeepSeek models it uses are text-only — they do not natively read images — so the practical design loop is reference-driven and verified in a real browser, rather than the agent “seeing” a screenshot directly. The cost efficiency is the design-relevant edge: you can iterate on UI many times without the bill that usually discourages tight loops."}, {"kind": "steps", "items": [{"label": "DeepSeek-native, BYOK", "body": "Reasonix runs on DeepSeek models such as deepseek-v4-pro and deepseek-v4-flash. You bring your own DeepSeek API key — the credential lives in your environment, not in the agent's config."}, {"label": "Repo-aware editing", "body": "It reads and edits files in your project with a review-gated editor and runs shell commands, so it can build and iterate on real UI code in your own repository."}, {"label": "Skills + MCP", "body": "It supports Markdown-authored skills and MCP servers, so you can give it durable conventions and connect external context like a design source."}]}, {"kind": "ul", "items": ["Vendor: community / the esengine GitHub author (not DeepSeek the company)", "Credential: your own DeepSeek API key (BYOK), supplied via environment", "License: MIT, open source"]}]}, {"id": "why-design", "heading": "Why a cost-efficient DeepSeek agent fits design", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix's design edge is less about a single flashy capability and more about making iterative UI work cheap and repeatable — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Cheap, tight iteration", "body": "Because it is engineered around DeepSeek's prefix cache, long design sessions stay affordable — so you can run the build-verify-refine loop many times instead of rationing it."}, {"label": "Repo-aware reuse", "body": "It edits files directly in your repo, so it can reuse your existing components and tokens rather than inventing one-off styles, when you point it at them."}, {"label": "Conventions in skills", "body": "Markdown skills and project config let you encode tokens, components, and review rules, so the agent works against your brand instead of a default look."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: DeepSeek Reasonix does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references described to it — and a browser to verify against. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up DeepSeek Reasonix for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the path from a clean machine to a DeepSeek Reasonix that can build and verify UI. Because it is a community project, always follow the install instructions in the repo's README; the outline below is the general shape."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Five-step setup flow: install, add your DeepSeek key, configure conventions, add a skill, verify in a browser", "caption": "The setup sequence: install → add your DeepSeek API key → encode conventions → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions into a skill or project config and point Reasonix at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Since DeepSeek models are text-only, wire a Playwright or browser MCP so the agent renders in a real browser and checks its output across breakpoints rather than only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with DeepSeek Reasonix is turning clear references into working, responsive UI and iterating until it matches. Because the DeepSeek models are text-only, the references are fed as detailed descriptions and specs — not read natively as images — and the match is confirmed by rendering in a real browser."}, {"kind": "ol", "items": ["Translate your references into concrete specs — describe layout, spacing, hierarchy, and states (desktop and mobile, hover, empty, loading) in words, since the model reads text, not pixels.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in a skill or project config, and tell Reasonix where the tokens and canonical primitives live.", "Run a dev server and verify the result in a real browser, resizing to breakpoints — wire a browser MCP so the agent can self-check.", "Iterate by comparing the rendered UI back to your references in the browser — not merely confirming it builds."]}, {"kind": "p", "text": "Give the agent concrete constraints in the prompt rather than a vague brief:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Reasonix when you revert), so each pass builds on a clean base — and so the cheap, cache-friendly loop stays productive."}]}, {"id": "extend", "heading": "Skills, MCP, and config", "blocks": [{"kind": "p", "text": "A few extension points make DeepSeek Reasonix practical for sustained design work, and they map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Markdown skills", "body": "Reasonix supports skills authored in Markdown — the durable home for your design conventions, tokens, and review checklists, applied on every run."}, {"label": "MCP servers", "body": "It integrates MCP servers, the portable way to bring in design context and external tools — most relevantly a design source like a Figma MCP server — that work across agents, not just Reasonix."}, {"label": "Project config and built-in tools", "body": "Per-project config plus built-in file, shell, and web tools let it gather context and run the verification loop without leaving the terminal. Check the repo README for exact config paths."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["DeepSeek Reasonix", "Open-source and DeepSeek-powered; cost-efficient via prefix caching, BYOK with your own DeepSeek key (community-built, text-only models)", "Cheap, high-volume iteration on UI in your own repo"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to DeepSeek Reasonix; they are what happens when any agent runs without a curated design context — and because its models are text-only, describing references precisely matters even more."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Since the model cannot see, render and self-check across breakpoints in a real browser so layouts do not silently break on mobile."}, {"label": "Supply tokens and described references", "body": "Real design tokens and precisely described reference states are the single biggest lever on output quality for a text-only agent."}, {"label": "Encode rules in a skill or config", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with DeepSeek Reasonix inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats DeepSeek Reasonix as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Reasonix good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select DeepSeek Reasonix as your agent.", "Authenticate with your own DeepSeek API key (BYOK) — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same DeepSeek Reasonix agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and open-source, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can DeepSeek Reasonix really do design work?", "text": "Yes — with an aesthetic skill, a design system, and precisely described references in context, DeepSeek Reasonix produces production-quality, responsive UI in your own repo, and you verify output in a real browser. Its DeepSeek models are text-only, so the loop is reference-described-and-verified rather than image-reading. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with DeepSeek Reasonix?", "text": "You bring your own DeepSeek API key, so you pay DeepSeek for usage (BYOK) — but the agent is built around DeepSeek's prefix cache to keep that cost low across long sessions. Reasonix itself is free and MIT-licensed. Open Design never proxies your credentials."}, {"name": "Is DeepSeek Reasonix an official DeepSeek product?", "text": "No. DeepSeek Reasonix is a community-built, open-source project from the esengine GitHub author — it runs on DeepSeek's models and uses a DeepSeek API key, but it is not made or endorsed by DeepSeek the company. DeepSeek is a trademark of its respective owner."}, {"name": "DeepSeek Reasonix or Claude Code for frontend design?", "text": "Both can do real design work. Claude Code is known for specific, codebase-aware design decisions; DeepSeek Reasonix's edge is being open-source and cost-efficient, running cheap, high-volume iteration on DeepSeek models with your own key. Many teams use more than one — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect DeepSeek Reasonix to a design source like Figma?", "text": "Reasonix supports MCP servers, so you can add a design-source MCP (such as a Figma MCP server) per the repo's docs. The agent can then pull real design context — components, variables, layout data — as text it can act on, so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with DeepSeek?", "text": "No. DeepSeek Reasonix is a community project that runs on DeepSeek's models; Open Design is an independent open-source project that supports it as a first-party adapter. It is affiliated with neither DeepSeek the company nor the Reasonix maintainers. DeepSeek is a trademark of its respective owner."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and open-source. Your files, artifacts, and DESIGN.md stay in your own repo, and your DeepSeek API key is used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with DeepSeek Reasonix, the open way.", "ctaBody": "Bring your own DeepSeek API key, keep every file local, and get a curated design library around the open-source agent you already use.", "ctaActions": [{"label": "Use DeepSeek Reasonix inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is DeepSeek Reasonix", "aboutBody": ["DeepSeek Reasonix is an open-source (MIT) terminal AI coding agent powered by DeepSeek models. It is community-built by the esengine GitHub author — not an official DeepSeek product — and engineered around DeepSeek's prefix cache so long sessions stay cheap.", "It reads your codebase, edits files with a review-gated editor, runs commands, and supports Markdown skills and MCP. Its DeepSeek models (such as deepseek-v4-pro and deepseek-v4-flash) are text-only, so the design loop is reference-described and verified in a browser.", "Open Design treats DeepSeek Reasonix as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Community / esengine (DeepSeek-powered, not DeepSeek the company)", "credentialLabel": "Credential", "credential": "Your own DeepSeek API key (BYOK)", "designTitle": "Designing with DeepSeek Reasonix", "designLead": "DeepSeek Reasonix's design strengths cluster around cost-efficient, repo-aware iteration:", "designPoints": [{"label": "Cheap, tight iteration", "body": "Built around DeepSeek's prefix cache, so the build-verify-refine loop stays affordable across long design sessions."}, {"label": "Repo-aware editing", "body": "Edits files directly in your repo with a review-gated editor, so it reuses your real components and tokens."}, {"label": "Skills + MCP", "body": "Markdown skills carry your conventions; MCP servers bring in design context like a Figma source as text."}, {"label": "Open and BYOK", "body": "MIT-licensed and open-source, running on DeepSeek models with your own DeepSeek API key."}], "linksTitle": "Real-world resources", "linksLead": "Official repo for DeepSeek Reasonix:", "links": [{"label": "esengine/DeepSeek-Reasonix (GitHub)", "href": "https://github.com/esengine/DeepSeek-Reasonix", "source": "GitHub · esengine (community)"}], "withOdTitle": "DeepSeek Reasonix + Open Design", "withOdLead": "Open Design is the open-source design layer around DeepSeek Reasonix: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select DeepSeek Reasonix as your agent.", "Authenticate with your own DeepSeek API key (BYOK) — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same DeepSeek Reasonix agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by DeepSeek?", "text": "No. DeepSeek Reasonix is a community project that runs on DeepSeek's models; Open Design is an independent open-source project that integrates it as a first-party adapter. Neither is made by DeepSeek the company."}, {"name": "Do I need to pay?", "text": "You bring your own DeepSeek API key (BYOK), so you pay DeepSeek for usage — kept low by prefix caching. Reasonix and Open Design are both free and open-source, and Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with DeepSeek or Reasonix?", "text": "No. Open Design is independent of both DeepSeek the company and the Reasonix maintainers. DeepSeek is a trademark of its respective owner."}], "ctaTitle": "Design with DeepSeek Reasonix, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  hermes: {"title": "Hermes for design — Open Design", "description": "How people use Nous Research’s Hermes — the autonomous, multi-provider terminal coding agent — for UI and web design, and how Open Design turns it into a local-first, open-source design agent with your own xAI, OpenAI, or Anthropic key.", "breadcrumb": "Hermes", "label": "Agent · Hermes", "heading": "Hermes for design.", "lead": "Hermes is Nous Research’s open-source, autonomous terminal agent. It plans, executes, and delegates work on its own machine — and it is provider-agnostic, so you bring your own xAI, OpenAI, or Anthropic key. That autonomy makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your key, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Hermes is an autonomous agent that plans and delegates UI work across the provider you choose — xAI Grok by default, but OpenAI or Anthropic via BYOK. Open Design gives it a curated design-system and skill library plus a desktop workflow — bring your own key and keep everything local.", "toc": ["What is Hermes", "Designing with Hermes", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Hermes into a local-first, open-source design agent — your own xAI, OpenAI, or Anthropic key, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Hermes inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes is Nous Research’s open-source autonomous AI agent. Two things make it interesting for design specifically: it is genuinely agentic, so it plans a task, executes it, and delegates parts to isolated subagents rather than just completing lines; and it is provider-agnostic, so you point it at whichever model you trust — xAI Grok by default, or OpenAI and Anthropic via bring-your-own-key. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI on your own machine. This is a practical, end-to-end guide to using Hermes for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Hermes actually is, why an autonomous, multi-provider agent fits design, how to set it up from zero, the screenshot-to-UI loop, how skills and subagents extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Hermes design feedback loop: an autonomous terminal agent reading a reference image, delegating to subagents, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Hermes reads your references in the terminal, plans and delegates the build, verifies the UI in a real browser, and iterates against them — on whichever model you bring."}, "tocLabel": "On this page", "toc": [{"id": "what-is-hermes", "label": "What Hermes actually is"}, {"id": "why-design", "label": "Why an autonomous, multi-provider agent fits design"}, {"id": "setup", "label": "Set up Hermes for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Skills, subagents, and providers"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Hermes in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-hermes", "heading": "What Hermes actually is", "blocks": [{"kind": "p", "text": "Hermes is an open-source (MIT) autonomous AI agent from Nous Research. It runs persistently on your own machine or server, reads your repository, edits files, runs shell commands, searches the web, and — crucially — plans and executes multi-step work on its own, delegating parts to isolated subagents. It is an autonomous agent, not a copilot tethered to an IDE."}, {"kind": "p", "text": "For design work, two properties stand out. It is genuinely agentic, so you can hand it a goal and it plans, builds, and verifies rather than waiting for line-by-line direction. And it is provider-agnostic: you bring your own key, defaulting to xAI Grok but free to point it at OpenAI, Anthropic, or any other supported endpoint — so you control which model reasons over your design."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes builds and reuses skills — procedural memory it creates from experience — the natural place to capture your design conventions, tokens, and review checklists so they persist across runs."}, {"label": "Subagents + tools", "body": "It spawns isolated subagents for parallel workstreams and ships file, shell, web, and browser tooling, so it can gather references and run a build-and-verify loop without leaving the terminal."}, {"label": "Bring your own key", "body": "Hermes defaults to xAI Grok and supports OpenAI, Anthropic, OpenRouter, and many other providers via BYOK — set a key or run an OAuth flow and pick your model."}]}, {"kind": "ul", "items": ["Vendor: Nous Research", "Credential: provider key via BYOK — xAI (Grok, default), OpenAI, or Anthropic — added with hermes auth add", "License: MIT, open source"]}]}, {"id": "why-design", "heading": "Why an autonomous, multi-provider agent fits design", "blocks": [{"kind": "p", "text": "Hermes’s design edge comes from two properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Autonomous plan-and-execute", "body": "Because Hermes plans, executes, and delegates on its own, it can take a design goal — match this reference, make it responsive — and iterate toward it instead of needing every step spelled out."}, {"label": "Bring the model you trust", "body": "Provider-agnostic BYOK means you pick the reasoning model for the job: xAI Grok by default, or OpenAI and Anthropic models when you want their strengths — no lock-in to one vendor’s aesthetics."}, {"label": "Conventions in skills", "body": "Skills (plus an MCP server like Figma) point the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Hermes does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Hermes for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Hermes that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure a skill, add a design system, verify", "caption": "The setup sequence: install → add a provider key → capture design rules in a skill → add a design system → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Capture your tokens, primitives, and conventions in a Hermes skill and point the agent at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Hermes renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Hermes is turning a reference image into working, responsive UI and iterating until it matches — letting the autonomous agent plan the build and compare its output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in a skill, and tell Hermes where the tokens and canonical primitives live.", "Run a dev server and have Hermes render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Hermes compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Point Hermes at your references and give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Hermes when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Skills, subagents, and providers", "blocks": [{"kind": "p", "text": "Three extension points make Hermes practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes builds and reuses skills — procedural memory created from experience. They are the durable home for your design conventions, applied on later runs instead of re-explained each time."}, {"label": "Subagents and MCP", "body": "It delegates work to isolated subagents and supports MCP servers — the portable way to bring in design context and external tools, most relevantly a Figma MCP server, that work across agents, not just Hermes."}, {"label": "Provider choice", "body": "Because Hermes is provider-agnostic (xAI Grok by default, OpenAI and Anthropic via BYOK), you can match the model to the task without rebuilding your workflow."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Hermes", "Autonomous plan-execute-delegate agent; provider-agnostic BYOK (xAI Grok default, OpenAI/Anthropic too); open-source and self-hosted", "Hands-off autonomous builds on whichever model you trust, kept local"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Hermes; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have Hermes render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in a skill", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules into a skill the agent applies every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Hermes inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Hermes as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Hermes good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Hermes as your agent.", "Authenticate with your own provider key (BYOK) — xAI Grok by default, or OpenAI or Anthropic — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Hermes agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Hermes really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Hermes produces production-quality, responsive UI, and as an autonomous agent it can render and verify output against references on its own. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Which models and keys does Hermes use?", "text": "Hermes is provider-agnostic and bring-your-own-key. It defaults to xAI Grok (for example grok-4.3) and also supports OpenAI, Anthropic, OpenRouter, and many other providers — you add a provider key (or run its OAuth flow) with hermes auth add and pick a model with hermes model. Open Design never proxies your credentials."}, {"name": "What makes Hermes good for design specifically?", "text": "Two things: it is genuinely autonomous, so it plans, builds, and verifies UI rather than waiting for line-by-line direction; and it is provider-agnostic, so you can run the reasoning model you trust. Both help — but taste still comes from the design system, skill, and references you supply."}, {"name": "Hermes or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Hermes’s edge is autonomous plan-and-execute plus provider choice — and you can even point Hermes at an Anthropic key. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Hermes to Figma?", "text": "Add a Figma MCP server in Hermes’s tool configuration. Hermes can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Nous Research?", "text": "No. Hermes is a product of Nous Research; Open Design is an independent open-source project that supports it as a first-party adapter. Hermes and Nous Research are trademarks of their respective owner."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your provider credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Hermes, the open way.", "ctaBody": "Bring your own xAI, OpenAI, or Anthropic key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Hermes inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Hermes", "aboutBody": ["Hermes is Nous Research’s open-source (MIT) autonomous terminal agent. It runs persistently on your own machine, reads your codebase, edits files, runs commands, and plans and delegates multi-step work to isolated subagents.", "It is provider-agnostic and bring-your-own-key: xAI Grok by default, with OpenAI, Anthropic, and many other providers supported, so you control which model reasons over your design.", "Open Design treats Hermes as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Nous Research", "credentialLabel": "Credential", "credential": "Provider key via BYOK — xAI (Grok, default), OpenAI, or Anthropic", "designTitle": "Designing with Hermes", "designLead": "Hermes’s design strengths cluster around its autonomy and provider choice:", "designPoints": [{"label": "Autonomous plan-and-execute", "body": "It plans, builds, and delegates UI work to subagents, turning a design goal into working, responsive markup and checking the result."}, {"label": "Provider-agnostic BYOK", "body": "xAI Grok by default, plus OpenAI, Anthropic, and many others — match the reasoning model to the task without lock-in."}, {"label": "Skills + MCP", "body": "Reusable skills carry your conventions; a Figma MCP server brings real design context into code."}, {"label": "Open and self-hosted", "body": "MIT-licensed and runs on your own machine, with no telemetry and no cloud dependency."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for Hermes:", "links": [{"label": "NousResearch/hermes-agent (GitHub)", "href": "https://github.com/NousResearch/hermes-agent", "source": "GitHub · Nous Research"}, {"label": "Hermes Agent", "href": "https://hermes-agent.nousresearch.com/", "source": "Nous Research"}, {"label": "Connect xAI Grok to Hermes (OAuth)", "href": "https://hermes-agent.nousresearch.com/docs/guides/xai-grok-oauth", "source": "Docs · Nous Research"}], "withOdTitle": "Hermes + Open Design", "withOdLead": "Open Design is the open-source design layer around Hermes: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Hermes as your agent.", "Authenticate with your own provider key (BYOK) — xAI Grok by default, or OpenAI or Anthropic — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Hermes agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Nous Research?", "text": "No. Hermes is a Nous Research product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need a specific provider?", "text": "No — Hermes is bring-your-own-key and provider-agnostic. It defaults to xAI Grok and also supports OpenAI, Anthropic, and others. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Nous Research?", "text": "No. Open Design is independent; Hermes and Nous Research are trademarks of their respective owner."}], "ctaTitle": "Design with Hermes, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  devin: {"title": "Devin for Terminal for design — Open Design", "description": "How people use Devin for Terminal — Cognition’s autonomous AI software engineer in the command line — for UI and web design, and how Open Design turns it into a local-first, open-source design agent with a curated skill and design-system library.", "breadcrumb": "Devin for Terminal", "label": "Agent · Devin", "heading": "Devin for Terminal for design.", "lead": "Devin for Terminal is Cognition’s autonomous AI software engineer, running in your terminal. It plans and executes multi-step tasks on its own and can hand a session off to a sandboxed cloud agent — which makes it a real way to ship front-end work, once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your Devin account, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Devin for Terminal runs Cognition’s autonomous AI software engineer in the command line — it plans, builds, and verifies multi-step front-end work and can hand off to a sandboxed cloud agent. Open Design gives it a curated design-system and skill library plus a desktop workflow, and keeps everything local on your own machine.", "toc": ["What is Devin for Terminal", "Designing with Devin", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Devin for Terminal into a local-first, open-source design agent — your Devin account, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Devin inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal is Cognition’s autonomous AI software engineer, brought into the local command line. Two things make it interesting for design specifically: it is genuinely agentic, so it plans and executes a multi-step task end to end rather than just completing lines; and it can hand a session off to a sandboxed cloud agent with its own computer, so longer builds keep running after you close your laptop. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Devin for Terminal for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Devin for Terminal actually is, why an autonomous software engineer fits design work, how to set it up from zero, the screenshot-to-UI loop, how project rules and external tools extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing for any agent that can plan and ship front-end work."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Devin for Terminal design feedback loop: an autonomous terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Devin reads your references in the terminal, plans and builds the UI, verifies it in a real browser, and iterates against them — handing longer runs off to the cloud when needed."}, "tocLabel": "On this page", "toc": [{"id": "what-is-devin", "label": "What Devin for Terminal actually is"}, {"id": "why-design", "label": "Why an autonomous software engineer fits design"}, {"id": "setup", "label": "Set up Devin for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Project rules, tools, and cloud handoff"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Devin in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-devin", "heading": "What Devin for Terminal actually is", "blocks": [{"kind": "p", "text": "Devin for Terminal is the command-line version of Devin, Cognition’s autonomous AI software engineer. It runs as a local coding agent with access to your codebase, tools, and environment — reading your repository, editing files, running shell commands, and planning and verifying work from a natural-language task rather than just completing lines. Cognition built a custom terminal rendering library in Rust to keep the interface fast and responsive."}, {"kind": "p", "text": "For design work, two properties stand out. It is genuinely autonomous, so you can describe an outcome and it executes the multi-step path to get there. And when a build outgrows your laptop, you can hand the session off to a cloud agent that runs in its own sandboxed environment and keeps working asynchronously — so you can come back to a finished pull request."}, {"kind": "steps", "items": [{"label": "Autonomous, agentic execution", "body": "Devin plans and executes a multi-step task on its own — implementing a feature, building UI, running and testing it — guided by clear prompts with explicit completion criteria."}, {"label": "Local agent, cloud handoff", "body": "It runs locally in your terminal, and can escalate a session to a sandboxed cloud agent that has its own computer and continues the work after you step away."}, {"label": "Account-based, model choice", "body": "You sign in with a Devin (Cognition) account; Devin runs on frontier models — you can choose between options such as Cognition’s own SWE-1.6 and other frontier models."}]}, {"kind": "ul", "items": ["Vendor: Cognition", "Credential: Devin (Cognition) account — subscription/account-based sign-in, not bring-your-own-key", "Form factor: local terminal agent with optional sandboxed cloud handoff"]}]}, {"id": "why-design", "heading": "Why an autonomous software engineer fits design", "blocks": [{"kind": "p", "text": "Devin’s design edge comes from how it works — autonomous, end-to-end execution — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "End-to-end, multi-step builds", "body": "Because Devin plans and executes whole tasks, it can scaffold a page, wire components, run a dev server, and test the result in one go instead of stopping at a snippet."}, {"label": "Sandboxed cloud runs", "body": "Longer front-end work — a full landing page, a multi-screen flow — can hand off to a sandboxed cloud agent and keep building, so iteration is not blocked by your laptop."}, {"label": "Conventions in project rules", "body": "Point the agent at your tokens, components, and real specs through your project’s rules and docs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Devin does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Devin for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Devin for Terminal that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Five-step setup flow: install, sign in, encode design rules, add references, verify in a browser", "caption": "The setup sequence: install → sign in → encode your design rules → supply references → verify in a real browser."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions where the agent reads them — in your project’s rules and docs — so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Have Devin render in a real browser and check its output across breakpoints, so it verifies against the design instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Devin is turning a reference image into working, responsive UI and iterating until it matches — letting the autonomous agent build, run, and compare its output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt and give explicit completion criteria; vague prompts produce generic UI even with a strong agent.", "Keep your design system and conventions in your project rules, and tell Devin where the tokens and canonical primitives live.", "Run a dev server and have Devin render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Devin compare its implementation back to the references — not merely confirm it builds — and hand off to the cloud for longer passes."]}, {"kind": "p", "text": "Give Devin the references and concrete constraints, with a clear definition of done:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Keep prompts focused, commit good iterations and revert bad ones (telling Devin when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Project rules, tools, and cloud handoff", "blocks": [{"kind": "p", "text": "Three extension points make Devin for Terminal practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Project rules and context", "body": "Keep your design conventions, tokens, and review checklists in your project’s rules and docs, so the agent reads them on every run and works against your brand."}, {"label": "Codebase, tools, and environment", "body": "Devin runs as a local agent with access to your codebase, tools, and environment — it can run a dev server, execute the build, and verify output without leaving the terminal."}, {"label": "Sandboxed cloud handoff", "body": "Hand a session off to a cloud agent in its own sandbox to run longer builds, tests, and PR creation asynchronously, then come back to a finished pull request."}]}, {"kind": "p", "text": "These are exactly the kind of portable, agent-shaped capabilities Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Devin", "Fully autonomous software engineer; plans and executes multi-step builds and hands off to a sandboxed cloud agent", "Delegating end-to-end front-end builds that keep running after you step away"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Devin; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have Devin render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in project context", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run, with explicit completion criteria."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Devin inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Devin for Terminal as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Devin good is there from the first run, not assembled by hand each time. Open Design is open-source and local-first, which makes the pairing a natural fit for an agent you already run in your terminal."}, {"kind": "ol", "items": ["Install Open Design and select Devin for Terminal as your agent.", "Authenticate with your Devin (Cognition) account — credentials are used directly by your agent and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Devin agent, same account — plus a real, portable, open-source design workflow around it. Open Design is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine through us."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Devin for Terminal really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Devin produces production-quality, responsive UI, and as an autonomous agent it can build, run, and verify the result against your references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "How do I sign in to Devin?", "text": "Devin is account-based: you sign in with a Devin (Cognition) account rather than bringing your own model key. Install Devin for Terminal, run it in your project, and authenticate on first run. Open Design never proxies your credentials — your agent uses them directly."}, {"name": "What makes Devin good for design specifically?", "text": "It is a fully autonomous software engineer: it plans and executes multi-step front-end builds end to end, and can hand a session off to a sandboxed cloud agent that keeps working after you step away. Taste still comes from the design system, skill, and references you supply."}, {"name": "Devin or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Devin’s edge is fully autonomous, end-to-end execution with a sandboxed cloud handoff. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "Does Devin run in a sandbox?", "text": "Devin for Terminal runs locally with access to your codebase and environment, and it can hand a session off to a cloud agent that runs in its own sandboxed environment — useful for longer builds, tests, and PR creation that continue asynchronously."}, {"name": "Is Open Design affiliated with Cognition?", "text": "No. Devin for Terminal is a product of Cognition; Open Design is an independent open-source project that supports it as a first-party adapter. Devin is a trademark of Cognition."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Devin credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Devin, the open way.", "ctaBody": "Sign in with your Devin account, keep every file local, and get a curated design library around the autonomous agent you already use.", "ctaActions": [{"label": "Use Devin inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Devin for Terminal", "aboutBody": ["Devin for Terminal is the command-line version of Devin, Cognition’s autonomous AI software engineer. It runs as a local coding agent with access to your codebase, tools, and environment, planning and executing multi-step tasks on its own.", "It can hand a session off to a sandboxed cloud agent that keeps working asynchronously, so longer builds finish after you close your laptop.", "Open Design treats Devin for Terminal as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Cognition", "credentialLabel": "Credential", "credential": "Devin (Cognition) account — account-based sign-in, not BYOK", "designTitle": "Designing with Devin", "designLead": "Devin’s design strengths cluster around its autonomy and execution:", "designPoints": [{"label": "Autonomous multi-step builds", "body": "Devin plans and executes whole front-end tasks — scaffolding, wiring components, running and testing — instead of stopping at a snippet."}, {"label": "Sandboxed cloud handoff", "body": "Longer builds can hand off to a cloud agent with its own computer and keep running after you step away."}, {"label": "Project rules + browser verification", "body": "Project context carries your conventions; a real-browser render checks output across breakpoints against your references."}, {"label": "Account-based, model choice", "body": "Sign in with a Devin account; Devin runs on frontier models, including Cognition’s own SWE-1.6."}], "linksTitle": "Real-world resources", "linksLead": "Official site, launch post, and docs for Devin:", "links": [{"label": "Devin — The AI software engineer", "href": "https://devin.ai/", "source": "Cognition"}, {"label": "Devin CLI: Start Local, Hand Off to the Cloud", "href": "https://cognition.ai/blog/devin-for-terminal", "source": "Blog · Cognition"}, {"label": "Devin documentation", "href": "https://docs.devin.ai/", "source": "Docs · Cognition"}], "withOdTitle": "Devin + Open Design", "withOdLead": "Open Design is the open-source design layer around Devin for Terminal: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Devin for Terminal as your agent.", "Authenticate with your Devin (Cognition) account — credentials stay with your agent on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Devin agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Cognition?", "text": "No. Devin for Terminal is a Cognition product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "How do I sign in?", "text": "Devin is account-based — sign in with your Devin (Cognition) account, not your own model key. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Cognition?", "text": "No. Open Design is independent; Devin is a trademark of Cognition."}], "ctaTitle": "Design with Devin, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  pi: {"title": "Pi for design — Open Design", "description": "How people use Pi, the open-source multi-provider terminal coding agent, for UI and web design — its any-model routing, BYOK provider keys, Skills and Extensions — and how Open Design turns Pi into a local-first, open-source design agent.", "breadcrumb": "Pi", "label": "Agent · Pi", "heading": "Pi for design.", "lead": "Pi is an open-source terminal coding agent that routes to any model — Anthropic, OpenAI, Google and 20+ providers — on your own API keys. That provider-agnostic core makes it a flexible design tool: pick the model that reads screenshots best today, switch tomorrow, keep your workflow. Open Design wires it into an open-source design workflow: your provider keys, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Pi is a BYOK terminal agent that edits files in your repo and routes to any provider, so you choose the model per task. Open Design gives it a curated design-system and skill library plus a desktop workflow — bring your own keys and keep everything local.", "toc": ["What is Pi", "Designing with Pi", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Pi into a local-first, open-source design agent — your own provider API keys, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Pi inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi is an open-source (MIT) AI coding agent for the terminal. What makes it interesting for design specifically is that it is provider-agnostic: it normalizes across Anthropic, OpenAI, Google and 20-plus other providers behind one interface, so you authenticate with your own API keys (BYOK) and pick the model that suits the task — and you can switch models mid-session without re-learning the tool. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Pi for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Pi actually is, why a multi-provider BYOK agent fits design, how to set it up from zero, the screenshot-to-UI loop, how Skills and Extensions extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Pi design feedback loop: a terminal agent reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Pi reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — on whichever provider you point it at."}, "tocLabel": "On this page", "toc": [{"id": "what-is-pi", "label": "What Pi actually is"}, {"id": "why-design", "label": "Why a multi-provider BYOK agent fits design"}, {"id": "setup", "label": "Set up Pi for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Skills, Extensions, and themes"}, {"id": "vs", "label": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Pi in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-pi", "heading": "What Pi actually is", "blocks": [{"kind": "p", "text": "Pi is an open-source (MIT) AI coding agent for the terminal, part of the earendil-works pi toolkit. It reads your repository, edits files, and runs shell commands — planning and verifying work from natural-language tasks rather than just completing lines. Its core is deliberately small: four default tools — read, write, edit, and bash — plus built-in grep, find, and ls."}, {"kind": "p", "text": "For design work, the standout property is that Pi is provider-agnostic. It normalizes across Anthropic, OpenAI, Google and many other providers behind one unified API, so you bring your own keys and choose the model per task — for example a strong multimodal model to read reference screenshots — and switch with /model or Ctrl+L mid-session without changing your workflow."}, {"kind": "steps", "items": [{"label": "Any model, your keys", "body": "Pi routes to 20+ providers including Anthropic and OpenAI. You authenticate with your own API keys (BYOK), or sign in to a Claude Pro/Max, ChatGPT Plus/Pro, or GitHub Copilot subscription with /login."}, {"label": "Skills + Extensions", "body": "Pi loads Skills (Markdown capability packages following the Agent Skills standard) and TypeScript Extensions — the natural place to encode your design conventions and add custom tools."}, {"label": "Branching sessions", "body": "Sessions are stored as JSONL trees, so you can branch an exploration and navigate history in a single file without losing earlier passes."}]}, {"kind": "ul", "items": ["Vendor: earendil-works (open-source community project)", "Credential: your own provider API key (BYOK — Anthropic, OpenAI, Google, etc.) or a subscription login via /login; stored locally in ~/.pi/agent/auth.json (0600)", "License: MIT, open source"]}]}, {"id": "why-design", "heading": "Why a multi-provider, BYOK agent fits design", "blocks": [{"kind": "p", "text": "Pi’s design edge is flexibility, not a single built-in model — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Pick the right model per task", "body": "Because Pi routes to any provider, you can reach for a strong multimodal model to read reference screenshots, then switch to another for refactoring — without leaving the agent."}, {"label": "Your keys, no lock-in", "body": "BYOK means you are not tied to one vendor’s pricing or context limits; choose the model whose strengths fit the design job in front of you."}, {"label": "Conventions in Skills", "body": "A Skill (plus an MCP source like a Figma server) points the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Pi does not have taste by default, and no model choice supplies it. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Pi for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Pi that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, encode design rules, add a skill, verify", "caption": "The setup sequence: install → authenticate (BYOK) → encode design rules in a Skill → choose a model → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in a Skill and point Pi at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Pi renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Pi is turning a reference image into working, responsive UI and iterating until it matches — leaning on a multimodal model to compare output back to the reference. Because Pi is provider-agnostic, point it at whichever model reads images best for this pass."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Pick a strong multimodal model for the pass with /model, since image understanding is what drives screenshot-to-UI quality.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in a Skill, and tell Pi where the tokens and canonical primitives live.", "Run a dev server and have Pi render in a real browser, resizing to breakpoints, then iterate by comparing its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Give the agent the references and concrete constraints up front:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Pi when you revert), so each pass builds on a clean base. Pi’s branching JSONL sessions also let you explore an alternative without losing the original thread."}]}, {"id": "extend", "heading": "Skills, Extensions, and themes", "blocks": [{"kind": "p", "text": "Pi self-extends at runtime through a few layers, and they map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Markdown capability packages following the Agent Skills standard — the durable, portable home for your design conventions, tokens, and review checklists. The same Skill works across compatible agents, not just Pi."}, {"label": "Extensions and prompt templates", "body": "TypeScript Extensions add custom tools, commands, and UI; reusable prompt templates run via /name. Both let you script the verification loop without leaving the terminal."}, {"label": "MCP and themes", "body": "Pi connects to MCP servers to bring in external design context (most relevantly a Figma MCP server), and themes hot-reload so the terminal UI stays readable while you work."}]}, {"kind": "p", "text": "These are portable capabilities — Skills and MCP especially — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Pi", "Provider-agnostic and BYOK — route to any model (Anthropic, OpenAI, Google…) and switch mid-session; MIT, self-extensible", "Choosing the best model per task without vendor lock-in"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "Pi’s angle is orthogonal to the others: it is the agent that lets you use any of those underlying models on your own keys. The recurring community verdict still holds — taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve, and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Pi or to any one model; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look — and since it is a portable Skill, it travels with you across models."}, {"label": "Verify in a real browser", "body": "Pick a multimodal model and have Pi render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules where Pi reads them", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules in a Skill the agent loads every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context — independent of which provider you route to. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Pi inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Pi as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Pi good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Pi as your agent.", "Authenticate with your own provider API key (BYOK) or a subscription login — credentials stay on your machine in ~/.pi/agent/auth.json and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Pi agent, same keys, same freedom to switch models — plus a real, portable, open-source design workflow around it. It is local-first and MIT, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Pi really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Pi produces production-quality, responsive UI, and you can route it to a strong multimodal model to verify output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Pi?", "text": "Pi itself is free and open source (MIT). You pay only for the underlying model — bring your own provider API key (BYOK), or use a Claude Pro/Max, ChatGPT Plus/Pro, or GitHub Copilot subscription via /login. Open Design never proxies your credentials either way."}, {"name": "What makes Pi good for design specifically?", "text": "It is provider-agnostic: you bring your own keys and route to any of 20+ providers, picking the model whose strengths fit the task and switching mid-session. But taste still comes from the design system, skill, and references you supply, not from the model."}, {"name": "Which model should I use with Pi for frontend design?", "text": "Pi routes to many providers, so choose per task — a strong multimodal model reads reference screenshots well, while others may suit refactoring. The advantage of Pi is that you can switch without changing your workflow. Open Design lets you keep the same design context across whichever model you pick."}, {"name": "How do I connect Pi to Figma?", "text": "Pi supports MCP servers, so you can add a Figma MCP server and pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Pi?", "text": "No. Pi is an independent open-source project from earendil-works; Open Design is a separate independent open-source project that supports Pi as a first-party adapter."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and open source. Your files, artifacts, and DESIGN.md stay in your own repo, and your provider keys are used directly by Pi (stored locally in ~/.pi/agent/auth.json), never routed through Open Design servers."}], "ctaTitle": "Design with Pi, the open way.", "ctaBody": "Bring your own provider keys, route to any model, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Pi inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Pi", "aboutBody": ["Pi is an open-source (MIT) terminal AI coding agent from earendil-works. It reads your codebase, edits files, and runs commands from a small four-tool core — read, write, edit, bash.", "It is provider-agnostic: it normalizes across Anthropic, OpenAI, Google and 20+ providers, so you bring your own keys and switch models mid-session.", "Open Design treats Pi as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "community", "credentialLabel": "Credential", "credential": "Your own provider API key (BYOK) or subscription login via /login", "designTitle": "Designing with Pi", "designLead": "Pi’s design strengths cluster around flexibility and openness:", "designPoints": [{"label": "Any model, your keys", "body": "Route to Anthropic, OpenAI, Google and more on your own keys; pick a strong multimodal model for screenshot-to-UI and switch with /model."}, {"label": "Portable Skills", "body": "Encode your design conventions as Agent-Skills-standard Skills that travel across compatible agents, not just Pi."}, {"label": "MCP + Extensions", "body": "Bring real design context via a Figma MCP server, and script the verification loop with TypeScript Extensions."}, {"label": "Open and BYOK", "body": "MIT-licensed and local-first; you pay only for the underlying model and your credentials stay on your machine."}], "linksTitle": "Real-world resources", "linksLead": "Official repo and docs for Pi:", "links": [{"label": "earendil-works/pi (GitHub)", "href": "https://github.com/earendil-works/pi", "source": "GitHub · earendil-works"}, {"label": "Pi providers & authentication docs", "href": "https://pi.dev/docs/latest/providers", "source": "Docs · pi.dev"}], "withOdTitle": "Pi + Open Design", "withOdLead": "Open Design is the open-source design layer around Pi: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Pi as your agent.", "Authenticate with your own provider API key (BYOK) or a subscription login — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Pi agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by the Pi team?", "text": "No. Pi is an independent open-source project from earendil-works; Open Design is a separate independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "Pi is free and open source (MIT). You bring your own provider key (BYOK) or a subscription login, and pay only the underlying model. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Pi?", "text": "No. Open Design is independent and integrates Pi as a community-supported adapter."}], "ctaTitle": "Design with Pi, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  kiro: {"title": "Kiro CLI for design — Open Design", "description": "How people use Amazon's Kiro CLI for UI and web design — its spec-driven development, agent hooks, steering files, and MCP — and how Open Design turns Kiro CLI into a local-first, open-source design agent.", "breadcrumb": "Kiro CLI", "label": "Agent · Kiro CLI", "heading": "Kiro CLI for design.", "lead": "Kiro CLI is Amazon's terminal agent for spec-driven development — it turns a prompt into a requirements spec, a design document, and a task list before it writes code. That structure is exactly what design work needs: intent first, then build. Open Design wires it into an open-source design workflow: your Builder ID or sign-in, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Kiro CLI brings Amazon's spec-driven agent to the terminal — specs, agent hooks, and steering files keep a build aligned to stated intent. Open Design gives it a curated design-system and skill library plus a desktop workflow, so the structure produces on-brand UI instead of a generic look — BYO sign-in and keep everything local. Kiro is in preview.", "toc": ["What is Kiro CLI", "Designing with Kiro CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Kiro CLI into a local-first, open-source design agent — your AWS Builder ID or sign-in, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Kiro CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI is Amazon's terminal agent for spec-driven development. What makes it distinct is the workflow: instead of jumping straight from a prompt to code, Kiro formalizes requirements into a spec, produces a design document and a sequenced task list, and only then implements — keeping the build accountable to stated intent. It also ships agent hooks that fire on events like a file save, steering files that carry your standards and conventions into every run, and Model Context Protocol support for external tools. Kiro is in preview, available as an IDE, a CLI, and a web interface, and you can start for free. This is a practical, end-to-end guide to using Kiro CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Kiro CLI actually is, why a spec-driven workflow fits design, how to set it up from zero, the screenshot-to-UI loop, how steering, hooks, and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer around it."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Kiro CLI design feedback loop: a terminal agent turning a spec into a design, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Kiro CLI turns your intent into a spec and a task list in the terminal, builds and verifies the UI in a real browser, and iterates against your references."}, "tocLabel": "On this page", "toc": [{"id": "what-is-kiro", "label": "What Kiro CLI actually is"}, {"id": "why-design", "label": "Why spec-driven development fits design"}, {"id": "setup", "label": "Set up Kiro CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Specs, steering, hooks, and MCP"}, {"id": "vs", "label": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Kiro CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kiro", "heading": "What Kiro CLI actually is", "blocks": [{"kind": "p", "text": "Kiro is an agentic AI from Amazon that ships as an IDE, a command-line interface, and a web interface, built to take you from prototype to production with spec-driven development. The Kiro CLI brings that agent to your terminal: you can start an interactive chat session, create and manage agents, and run Model Context Protocol servers — all from the command line. Kiro is in preview."}, {"kind": "p", "text": "For design work, the defining property is the workflow. Rather than turning a prompt straight into code, Kiro first writes a spec — requirements, a design document, and a sequenced task list — and implements against it. That makes the agent's plan visible and reviewable before any UI is built, which maps cleanly onto how design decisions should be made: intent first, then execution."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Kiro turns a prompt into a structured spec — requirements, a design document, and discrete tasks — before it writes code, so the plan is reviewable up front."}, {"label": "Steering + hooks", "body": "Steering files carry your standards, conventions, and preferred tools into every run; agent hooks fire on events like a file save to run background tasks automatically."}, {"label": "Free to start, MCP-ready", "body": "Sign in with a Builder ID, Google, GitHub, or your organization and start for free; Kiro CLI also manages MCP servers to bring in external context."}]}, {"kind": "ul", "items": ["Vendor: Amazon (AWS)", "Credential: AWS Builder ID, Google, GitHub, or AWS IAM Identity Center via kiro-cli login (no AWS account required)", "Status: In preview; available as IDE, CLI, and web interface"]}]}, {"id": "why-design", "heading": "Why spec-driven development fits design", "blocks": [{"kind": "p", "text": "Kiro CLI's design edge comes from its workflow — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Intent before pixels", "body": "Because Kiro writes a spec and a design document first, you can correct layout, hierarchy, and scope at the planning stage — before the agent has committed to a generic implementation."}, {"label": "Steering carries your brand", "body": "Steering files keep your tokens, components, and conventions in front of the agent on every run, so output works against a brand instead of a default look."}, {"label": "Hooks enforce the loop", "body": "Agent hooks can run checks automatically on save — a place to wire in a verification or review step rather than relying on the agent to remember it."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Kiro CLI does not have taste by default. A spec keeps a build honest, but it produces good design only when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Kiro CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Kiro CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, add steering, add a skill, verify", "caption": "The setup sequence: install → authenticate → add steering and a design spec → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions into steering files so the agent reads them on every run, and output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP server so Kiro renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Kiro CLI is turning a reference image into working, responsive UI and iterating until it matches — letting the spec capture intent first, then building against it."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Let Kiro write a spec and design document from your prompt, and review the plan before it builds — this is where you catch layout and scope problems early.", "Keep your design system and conventions in steering files, and tell Kiro where the tokens and canonical primitives live.", "Run a dev server and have Kiro render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Kiro compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Open an interactive session and give concrete constraints up front, so the spec it writes reflects your real intent:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep tasks small and focused, commit good iterations and revert bad ones (telling Kiro when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Specs, steering, hooks, and MCP", "blocks": [{"kind": "p", "text": "Four extension points make Kiro CLI practical for sustained design work, and all four map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Requirements, a design document, and a sequenced task list — the durable record of what a feature is meant to be, reviewable before and during the build."}, {"label": "Steering files", "body": "Add context, coding standards, and preferred workflows or tools that the agent reads on every run — the natural home for your design conventions and tokens."}, {"label": "Agent hooks", "body": "Automations that trigger on events such as a file save, running background tasks like checks or docs — a place to enforce a verification step automatically."}, {"label": "MCP servers", "body": "Kiro CLI manages Model Context Protocol servers, the portable way to bring in external design context and tools that work across agents, not just Kiro."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Kiro CLI", "Spec-driven workflow — requirements, design doc, and task list before code; steering files and hooks keep builds on-brand", "Structured, reviewable builds where intent and scope are locked before implementation"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a very large context; open-source with a free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Kiro CLI; they are what happens when any agent runs without a curated design context — a spec keeps a build on-task, but it does not supply taste."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints — wire it as a hook if you can — so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in steering files", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Kiro CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Kiro CLI as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Kiro good is there from the first run, not assembled by hand each time. Open Design is local-first, which keeps the pairing simple: your files and your sign-in stay on your machine."}, {"kind": "ol", "items": ["Install Open Design and select Kiro CLI as your agent.", "Authenticate with your AWS Builder ID or other sign-in — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Kiro CLI agent, same sign-in — plus a real, portable, open-source design workflow around it. Open Design is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Kiro CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Kiro CLI produces production-quality, responsive UI, and its spec-driven workflow keeps the build accountable to stated intent. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need an AWS account to use Kiro CLI?", "text": "No — Kiro lets you sign in with an AWS Builder ID, Google, GitHub, or your organization (AWS IAM Identity Center), and you do not need an AWS account to use it. Kiro is in preview and free to start. Open Design never proxies your credentials either way."}, {"name": "What makes Kiro CLI good for design specifically?", "text": "Its spec-driven workflow: Kiro writes requirements, a design document, and a task list before it codes, so you correct layout and scope before the build commits. Steering files carry your conventions and hooks can enforce checks — but taste still comes from the design system, skill, and references you supply."}, {"name": "Kiro CLI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Kiro CLI's edge is its spec-driven, reviewable workflow with steering and hooks. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Kiro CLI to external design tools?", "text": "Kiro CLI manages Model Context Protocol (MCP) servers — use kiro-cli mcp to add them. An MCP server can bring real design context and tools into the agent so generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Amazon or AWS?", "text": "No. Kiro is a product of Amazon (AWS); Open Design is an independent open-source project that supports it as a first-party adapter. Kiro is a trademark of Amazon."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Kiro sign-in is used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Kiro CLI, the open way.", "ctaBody": "Bring your own AWS Builder ID or sign-in, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Kiro CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Kiro CLI", "aboutBody": ["Kiro is an agentic AI from Amazon (AWS) that ships as an IDE, a CLI, and a web interface, built for spec-driven development from prototype to production. It is in preview.", "The Kiro CLI brings the agent to your terminal — an interactive chat session, custom agents, steering files, agent hooks, and Model Context Protocol servers.", "Open Design treats Kiro CLI as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Amazon (AWS)", "credentialLabel": "Credential", "credential": "AWS Builder ID, Google, GitHub, or AWS IAM Identity Center (no AWS account required)", "designTitle": "Designing with Kiro CLI", "designLead": "Kiro CLI's design strengths cluster around its spec-driven workflow:", "designPoints": [{"label": "Spec before code", "body": "Kiro writes requirements, a design document, and a task list first, so you correct layout and scope before the build commits."}, {"label": "Steering files", "body": "Your standards, conventions, and tokens travel into every run, so output works against a brand instead of a default look."}, {"label": "Agent hooks", "body": "Automations fire on events like a file save — a place to enforce a verification or review step without relying on memory."}, {"label": "MCP and free to start", "body": "Kiro CLI manages MCP servers for external context, signs in with a Builder ID, Google, GitHub, or your organization, and is free to start in preview."}], "linksTitle": "Real-world resources", "linksLead": "Official site and docs for Kiro CLI:", "links": [{"label": "Kiro — agentic IDE and CLI", "href": "https://kiro.dev/", "source": "Amazon · kiro.dev"}, {"label": "Kiro CLI documentation", "href": "https://kiro.dev/docs/cli/", "source": "Docs · Kiro"}, {"label": "kirodotdev/Kiro (GitHub)", "href": "https://github.com/kirodotdev/Kiro", "source": "GitHub · Kiro"}], "withOdTitle": "Kiro CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Kiro CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Kiro CLI as your agent.", "Authenticate with your AWS Builder ID or other sign-in — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Kiro CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Amazon?", "text": "No. Kiro is an Amazon (AWS) product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need an AWS account?", "text": "No — Kiro signs in with an AWS Builder ID, Google, GitHub, or your organization, and no AWS account is required. It is in preview and free to start. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Amazon or AWS?", "text": "No. Open Design is independent; Kiro is a trademark of Amazon."}], "ctaTitle": "Design with Kiro CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  kilo: {"title": "Kilo Code for design — Open Design", "description": "How people use Kilo Code — the open-source, model-agnostic AI coding agent — for UI and web design: its Architect/Code modes, MCP support, BYOK across many providers, and how Open Design turns Kilo into a local-first, open-source design agent.", "breadcrumb": "Kilo", "label": "Agent · Kilo", "heading": "Kilo Code for design.", "lead": "Kilo Code is an open-source, model-agnostic AI coding agent for your IDE and CLI. Because you can point it at almost any model and bring your own provider keys, it becomes a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your provider keys, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Kilo Code turns reference images and clear constraints into responsive UI, with Architect/Code modes, MCP support, and your choice of 500+ models via BYOK or Kilo's own gateway. Open Design gives it a curated design-system and skill library plus a desktop workflow — bring your own keys and keep everything local.", "toc": ["What is Kilo Code", "Designing with Kilo Code", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Kilo Code into a local-first, open-source design agent — your provider keys, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Kilo Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code is an open-source AI coding agent that runs in VS Code, JetBrains IDEs, and the terminal. Two things make it interesting for design specifically: it is model-agnostic, so you can drive it with whichever frontier vision-capable model best reads a screenshot; and it is BYOK across many providers, so you keep control of cost and credentials. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Kilo Code for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Kilo Code actually is, why a model-agnostic, open agent fits design, how to set it up from zero, the screenshot-to-UI loop, how custom rules and MCP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Kilo Code design feedback loop: an agent in the IDE and terminal reading a reference image, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Kilo Code reads your references in the IDE or CLI, builds and verifies the UI in a real browser, and iterates against them — with the model you choose."}, "tocLabel": "On this page", "toc": [{"id": "what-is-kilo", "label": "What Kilo Code actually is"}, {"id": "why-design", "label": "Why an open, model-agnostic agent fits design"}, {"id": "setup", "label": "Set up Kilo Code for design (from zero)"}, {"id": "screenshot-workflow", "label": "The screenshot-to-UI workflow"}, {"id": "extend", "label": "Modes, custom rules, and MCP"}, {"id": "vs", "label": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Kilo Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kilo", "heading": "What Kilo Code actually is", "blocks": [{"kind": "p", "text": "Kilo Code is an open-source AI coding agent built by Kilo Code, Inc. It runs as a VS Code extension, in JetBrains IDEs, and as a command-line interface — reading your repository, editing files, running commands, and planning and verifying work from natural-language tasks rather than just completing lines. Its defining trait is that it is model-agnostic: you choose which model drives it, and you bring your own provider keys."}, {"kind": "p", "text": "For design work, two properties stand out. Because it is model-agnostic, you can point it at whichever strong vision-capable model best reads a reference screenshot and reasons about layout. And because it is open-source and BYOK, you can inspect exactly what context is sent and keep credentials and cost under your own control."}, {"kind": "steps", "items": [{"label": "Agent modes", "body": "Kilo ships specialized modes — Architect for planning, Code for building, Debug for fixing, and Ask for questions — plus custom modes, so you can plan a design and then implement it in separate, focused passes."}, {"label": "Custom rules + MCP", "body": "It reads project-level custom rules for persistent context and supports MCP servers (with an MCP marketplace), so you can add external context like a live Figma file or design tooling."}, {"label": "Bring your own keys", "body": "Kilo is BYOK across many providers — Anthropic, OpenAI, Google, OpenRouter, and more — or you can use Kilo's own gateway, which exposes 500+ models at provider cost."}]}, {"kind": "ul", "items": ["Vendor: Kilo Code, Inc. (open source)", "Credential: your own provider API key (BYOK — Anthropic, OpenAI, Google, OpenRouter, and more) or Kilo's own gateway", "License: open source"]}]}, {"id": "why-design", "heading": "Why an open, model-agnostic agent fits design", "blocks": [{"kind": "p", "text": "Kilo Code’s design edge comes from openness and model choice — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Model-agnostic by design", "body": "Because you choose the model, you can drive Kilo with whichever vision-capable model reads reference screenshots best — and switch when a better one appears, without changing your workflow."}, {"label": "Open and inspectable", "body": "Kilo is open-source, so you can see exactly what context and prompts are sent — useful when you want the agent to reuse your real design primitives rather than invent one-off styles."}, {"label": "Conventions in custom rules", "body": "Project custom rules (plus an MCP server for Figma) point the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Kilo Code does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Kilo Code for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Kilo Code that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, add custom rules, add a skill, verify", "caption": "The setup sequence: install → connect a provider → add custom rules → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions in Kilo's custom rules and point the agent at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Kilo renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The screenshot-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Kilo Code is turning a reference image into working, responsive UI and iterating until it matches — leaning on a vision-capable model to compare output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions in Kilo's custom rules, and tell the agent where the tokens and canonical primitives live.", "Run a dev server and have Kilo render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Kilo compare its implementation back to the screenshots — not merely confirm it builds."]}, {"kind": "p", "text": "Use Architect mode to plan the build, then switch to Code mode and attach your references with concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Kilo when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Modes, custom rules, and MCP", "blocks": [{"kind": "p", "text": "Three extension points make Kilo Code practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Modes (Architect → Code)", "body": "Plan the structure of a screen in Architect mode, then implement it in Code mode and fix issues in Debug mode — separating design intent from implementation. Custom modes let you encode a design-review pass of your own."}, {"label": "Custom rules", "body": "Project custom rules are the durable home for your design conventions — tokens, primitives, and review checklists — read on every run so the agent works against your brand."}, {"label": "MCP servers", "body": "Kilo supports MCP servers via its marketplace — the portable way to bring in design context and external tools, most relevantly a Figma MCP server, that work across agents, not just Kilo."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Kilo Code", "Open-source and model-agnostic with BYOK across many providers; Architect/Code modes and MCP", "Choosing your own model per task and keeping cost and credentials under your control"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Kilo Code; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Use a vision-capable model to render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in custom rules", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Kilo Code inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Kilo Code as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Kilo good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Kilo Code as your agent.", "Authenticate with your own provider key (BYOK) or Kilo's gateway — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Kilo Code agent, same keys — plus a real, portable, open-source design workflow around it. It is local-first and open-source, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Kilo Code really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Kilo Code produces production-quality, responsive UI, and a vision-capable model verifies output against references. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "Do I need to pay to design with Kilo Code?", "text": "Kilo Code is open-source and free to install. You bring your own provider API key (BYOK) and pay that provider directly, or use Kilo's own gateway at provider cost. Open Design never proxies your credentials either way."}, {"name": "What makes Kilo Code good for design specifically?", "text": "It is model-agnostic and open-source, so you can drive it with whichever vision-capable model reads reference screenshots best, inspect exactly what context is sent, and keep cost and credentials under your control. Taste still comes from the design system, skill, and references you supply."}, {"name": "Kilo Code or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Kilo Code's edge is being open-source and model-agnostic with BYOK, so you choose the model. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Kilo Code to Figma?", "text": "Add a Figma MCP server from Kilo's MCP marketplace or MCP settings. Kilo can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Kilo Code?", "text": "No. Kilo Code is a product of Kilo Code, Inc.; Open Design is an independent open-source project that supports it as a first-party adapter. Both happen to be open-source, but they are separate projects."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and open-source. Your files, artifacts, and DESIGN.md stay in your own repo, and your provider credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Kilo Code, the open way.", "ctaBody": "Bring your own provider key, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Kilo Code inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Kilo Code", "aboutBody": ["Kilo Code is an open-source AI coding agent from Kilo Code, Inc. It runs in VS Code, JetBrains IDEs, and the terminal, reading your codebase, editing files, and running commands.", "It is model-agnostic and BYOK across many providers, with Architect/Code/Debug/Ask modes and MCP support, so you choose the model and keep credentials under your control.", "Open Design treats Kilo Code as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Kilo Code, Inc.", "credentialLabel": "Credential", "credential": "Your own provider API key (BYOK) or Kilo's gateway", "designTitle": "Designing with Kilo Code", "designLead": "Kilo Code’s design strengths cluster around openness and model choice:", "designPoints": [{"label": "Model-agnostic screenshot → UI", "body": "Drive it with the vision-capable model that best turns a reference image into responsive markup, and check the result against it."}, {"label": "BYOK across providers", "body": "Bring your own keys for Anthropic, OpenAI, Google, OpenRouter, and more — or use Kilo's gateway — so cost and credentials stay yours."}, {"label": "Modes + custom rules + MCP", "body": "Plan in Architect mode, build in Code mode, carry conventions in custom rules, and bring real design context via the Figma MCP server."}, {"label": "Open source", "body": "Inspect every prompt and context payload; nothing is hidden, and the agent runs in your IDE or CLI."}], "linksTitle": "Real-world resources", "linksLead": "Official site, repo, and docs for Kilo Code:", "links": [{"label": "Kilo — Open Source AI Coding Agent", "href": "https://kilo.ai/", "source": "Site · Kilo Code"}, {"label": "Kilo-Org/kilocode (GitHub)", "href": "https://github.com/Kilo-Org/kilocode", "source": "GitHub · Kilo Code"}, {"label": "Kilo Code documentation", "href": "https://kilo.ai/docs", "source": "Docs · Kilo Code"}], "withOdTitle": "Kilo Code + Open Design", "withOdLead": "Open Design is the open-source design layer around Kilo Code: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Kilo Code as your agent.", "Authenticate with your own provider key (BYOK) or Kilo's gateway — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Kilo Code agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Kilo Code?", "text": "No. Kilo Code is a product of Kilo Code, Inc.; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "Do I need to pay?", "text": "Kilo Code is free to install and open-source; you bring your own provider key (BYOK) and pay that provider, or use Kilo's gateway. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Kilo Code?", "text": "No. Open Design is an independent project; both are open-source, but they are separate."}], "ctaTitle": "Design with Kilo Code, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  vibe: {"title": "Mistral Vibe CLI for design — Open Design", "description": "How people use Mistral's Vibe CLI for UI and web design — its open-weights Devstral coding models, agentic multi-file editing, config.toml, MCP and ACP — and how Open Design turns Vibe CLI into a local-first, open-source design agent.", "breadcrumb": "Mistral Vibe CLI", "label": "Agent · Mistral Vibe CLI", "heading": "Mistral Vibe CLI for design.", "lead": "Mistral Vibe CLI is Mistral AI's open-source terminal coding agent, powered by the Devstral model family. It edits files, runs commands, and works over the Agent Client Protocol — which makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your Mistral API key (BYOK) or local models, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Vibe CLI is Mistral's Apache-2.0 terminal agent that turns prompts and references into responsive UI using Devstral coding models — bring your Mistral API key, or run open-weights models locally. Open Design gives it a curated design-system and skill library plus a desktop workflow — BYOK and keep everything local.", "toc": ["What is Mistral Vibe CLI", "Designing with Vibe CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Mistral Vibe CLI into a local-first, open-source design agent — your Mistral API key or local Devstral models, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Vibe CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI is Mistral AI's open-source (Apache-2.0) coding agent for the terminal. It scans your project's file structure and Git status for context, then explores, edits, and runs changes across your codebase from natural-language tasks. Two things make it interesting for design specifically: it is powered by Mistral's Devstral coding models, part of an open-weights ecosystem you can run locally or in the cloud; and it speaks the Agent Client Protocol (ACP), so it slots into editors and tools rather than living only in one terminal. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Vibe CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Vibe CLI actually is, why an open-weights coding agent fits design, how to set it up from zero, the reference-to-UI loop, how config.toml, MCP, and ACP extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer — a natural pairing, since both are open-source and run on your own machine."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Mistral Vibe CLI design feedback loop: a terminal agent reading a reference, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Vibe CLI reads your references in the terminal, builds and verifies the UI in a real browser, and iterates against them — driven by Mistral's Devstral coding models."}, "tocLabel": "On this page", "toc": [{"id": "what-is-vibe", "label": "What Mistral Vibe CLI actually is"}, {"id": "why-design", "label": "Why an open-weights coding agent fits design"}, {"id": "setup", "label": "Set up Vibe CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "config.toml, MCP, and ACP"}, {"id": "vs", "label": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Vibe CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-vibe", "heading": "What Mistral Vibe CLI actually is", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI is an open-source (Apache-2.0) coding agent that Mistral AI ships for the terminal. It provides an interactive chat interface with tools for file manipulation, code searching, version control, and command execution, and it automatically scans your project's file structure and Git status to give the agent relevant context. It is powered by Mistral's Devstral coding models — planning and verifying work from natural-language tasks rather than just completing lines."}, {"kind": "p", "text": "For design work, two properties stand out. It runs on Mistral's open-weights Devstral family (Devstral 2 and the smaller Devstral Small 2), so you can run the agent against the Mistral API in the cloud or against local models — useful for privacy-sensitive or offline design work. And it speaks the Agent Client Protocol, so the same agent can drive editors and tools, not just one terminal session."}, {"kind": "steps", "items": [{"label": "Config files", "body": "Vibe CLI is configured through a config.toml file (project-level ./.vibe/config.toml, with a fallback at ~/.vibe/config.toml). It is a practical place to encode your providers, model choice, and project settings."}, {"label": "Built-in tools + MCP", "body": "It ships file, search, version-control, and command-execution tools, and supports MCP servers (configured under an [[mcp_servers]] section) to add external context like a live Figma file."}, {"label": "BYOK or local", "body": "Authenticate with a Mistral API key from the Mistral console, or point it at local/compatible models so it works fully offline."}]}, {"kind": "ul", "items": ["Vendor: Mistral AI", "Credential: Mistral API key (BYOK) from the Mistral console, or local / compatible models", "License: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Why an open-weights coding agent fits design", "blocks": [{"kind": "p", "text": "Vibe CLI's design edge comes from its open-weights model family and its protocol reach — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Devstral coding models", "body": "Vibe runs on Mistral's Devstral family, coding-tuned models built for agentic, multi-file work — so the agent edits across a real frontend codebase rather than emitting isolated snippets."}, {"label": "Open-weights and local-friendly", "body": "Devstral Small 2 is small enough to run on consumer hardware, so design work can stay fully local and offline — references and code never have to leave your machine."}, {"label": "Conventions in config.toml + context", "body": "Project config and your own instructions point the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Vibe CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Vibe CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Vibe CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure config.toml, add a skill, verify", "caption": "The setup sequence: install → authenticate → configure config.toml → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Keep your tokens, primitives, and conventions where the agent reads them and point Vibe at them, so output matches a brand instead of defaulting to a generic look."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Vibe renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Vibe CLI is turning a clear reference into working, responsive UI and iterating until it matches — leaning on the agent's tools to render, inspect, and correct its own output."}, {"kind": "ol", "items": ["Start from the clearest references you have — and describe multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a strong model.", "Keep your design system and conventions where Vibe reads them, and tell it where the tokens and canonical primitives live.", "Run a dev server and have Vibe render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Vibe compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Reference files with @ (Vibe autocompletes file paths) and drive slash commands with /, then give concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Vibe when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "config.toml, MCP, and ACP", "blocks": [{"kind": "p", "text": "Three extension points make Vibe CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Project rules and provider/model settings live in a config.toml (project-level, with a ~/.vibe fallback). It is the durable home for how the agent is wired into your project, read on every run."}, {"label": "MCP servers", "body": "Configure MCP servers in your config.toml ([[mcp_servers]], with HTTP, streamable-HTTP, and stdio transports) — the portable way to bring in design context and external tools, most relevantly the Figma MCP server, that work across agents, not just Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe speaks ACP, so the same agent can be driven from editors and other ACP clients. This is exactly how Open Design integrates it — over ACP via the vibe-acp binary."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Mistral Vibe CLI", "Open-weights Devstral coding models you can run locally; Apache-2.0 and ACP-native", "Privacy-sensitive or offline design work and an open-weights stack"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a very large context window", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Vibe CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Have Vibe render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules in config and context", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Vibe CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Mistral Vibe CLI as a first-party adapter — driving it over ACP via the vibe-acp binary — and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI. So the design context that makes Vibe good is there from the first run, not assembled by hand each time. Both are open-source and local-first, which makes the pairing a natural fit."}, {"kind": "ol", "items": ["Install Open Design and select Mistral Vibe CLI as your agent.", "Authenticate with your Mistral API key (BYOK) or point Vibe at local models — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Vibe CLI agent, same key — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Mistral Vibe CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real references in context, Vibe CLI produces production-quality, responsive UI, and its Devstral models edit across a real frontend codebase. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "How do I authenticate Vibe CLI?", "text": "Run the setup wizard with vibe --setup to register a Mistral API key (from the Mistral console), or set MISTRAL_API_KEY in your environment. It can also run against local or compatible models, fully offline. Open Design never proxies your credentials either way."}, {"name": "What makes Vibe CLI good for design specifically?", "text": "It is an Apache-2.0, ACP-native agent powered by Mistral's open-weights Devstral coding models — so you can run it locally for privacy-sensitive work and edit across a real codebase. But taste still comes from the design system, skill, and references you supply."}, {"name": "Vibe CLI or Claude Code for frontend design?", "text": "Both are strong. Claude Code is known for specific, codebase-aware design decisions; Vibe CLI's edge is an open-weights Devstral stack you can run locally and an Apache-2.0 license. Many teams use both — Open Design lets you switch agents without changing your design workflow."}, {"name": "How do I connect Vibe CLI to Figma?", "text": "Add the Figma MCP server as an [[mcp_servers]] entry in your config.toml. Vibe can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Mistral AI?", "text": "No. Mistral Vibe CLI is a product of Mistral AI; Open Design is an independent open-source project that supports it as a first-party adapter, driven over ACP. Mistral is a trademark of Mistral AI."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Mistral credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Mistral Vibe CLI, the open way.", "ctaBody": "Bring your own Mistral API key or local models, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Vibe CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Mistral Vibe CLI", "aboutBody": ["Mistral Vibe CLI is Mistral AI's open-source (Apache-2.0) terminal coding agent. It scans your project's files and Git status, edits code, searches, runs commands, and handles version control from natural-language tasks.", "It is powered by Mistral's Devstral coding models — an open-weights family you can run in the cloud or locally — and it speaks the Agent Client Protocol (ACP).", "Open Design treats Vibe CLI as a first-party adapter, driving it over ACP via the vibe-acp binary, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Mistral AI", "credentialLabel": "Credential", "credential": "Mistral API key (BYOK) or local models", "designTitle": "Designing with Mistral Vibe CLI", "designLead": "Vibe CLI's design strengths cluster around its open-weights stack and protocol reach:", "designPoints": [{"label": "Devstral coding models", "body": "Coding-tuned, agentic models edit across a real frontend codebase rather than emitting isolated snippets."}, {"label": "Open-weights and local-friendly", "body": "Devstral Small 2 can run on consumer hardware, so design work can stay fully local and offline."}, {"label": "config.toml + MCP", "body": "Project config carries how the agent is wired; the Figma MCP server brings real design context into code."}, {"label": "Open and ACP-native", "body": "Apache-2.0 and built on the Agent Client Protocol, with BYOK via the Mistral API."}], "linksTitle": "Real-world resources", "linksLead": "Official repo, announcement, and docs for Mistral Vibe CLI:", "links": [{"label": "mistralai/mistral-vibe (GitHub)", "href": "https://github.com/mistralai/mistral-vibe", "source": "GitHub · Mistral AI"}, {"label": "Introducing Devstral 2 and Mistral Vibe CLI", "href": "https://mistral.ai/news/devstral-2-vibe-cli/", "source": "News · Mistral AI"}, {"label": "Mistral Vibe documentation", "href": "https://mistral.ai/products/vibe/code/", "source": "Docs · Mistral AI"}], "withOdTitle": "Mistral Vibe CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Vibe CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Mistral Vibe CLI as your agent.", "Authenticate with your Mistral API key (BYOK) or local models — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Vibe CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Mistral AI?", "text": "No. Mistral Vibe CLI is a Mistral AI product; Open Design is an independent open-source project that integrates it as a first-party adapter over ACP."}, {"name": "Do I need a Mistral API key?", "text": "You can bring a Mistral API key (BYOK), or run Vibe against local models fully offline. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Mistral AI?", "text": "No. Open Design is independent; Mistral is a trademark of Mistral AI."}], "ctaTitle": "Design with Mistral Vibe CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
  qoder: {"title": "Qoder CLI for design — Open Design", "description": "How people use Qoder CLI — Alibaba's agentic coding platform — for UI and web design: its agent and quest modes, deep repository understanding and repo wiki, and Lite/Efficient/Auto model tiers — and how Open Design turns Qoder CLI into a local-first, open-source design agent.", "breadcrumb": "Qoder CLI", "label": "Agent · Qoder CLI", "heading": "Qoder CLI for design.", "lead": "Qoder CLI is the terminal agent of Qoder, Alibaba's agentic coding platform. It understands a whole repository — architecture, patterns, and the conventions captured in its repo wiki — and runs spec-driven, autonomous work, which makes it a real design tool once you give it references, conventions, and a verification loop. Open Design wires it into an open-source design workflow: your Qoder account, your files, local-first.", "tldrTitle": "TL;DR", "tldrBody": "Qoder CLI brings Qoder's agentic, repo-aware engine to the terminal — spec-driven quests, deep codebase understanding, and Lite/Efficient/Auto model tiers, signed in with a Qoder account. Open Design gives it a curated design-system and skill library plus a desktop workflow — keep everything local.", "toc": ["What is Qoder CLI", "Designing with Qoder CLI", "Resources", "With Open Design", "FAQ"], "rich": {"heroCtaLead": "Open Design turns Qoder CLI into a local-first, open-source design agent — your Qoder account, your files, a curated skill and design-system library around it.", "heroCtaActions": [{"label": "Use Qoder CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI is the terminal agent of Qoder, Alibaba's agentic coding platform. Two things make it interesting for design specifically: it builds deep context on your repository — architecture, design patterns, and the conventions it distills into a repository wiki — so it reuses your real primitives instead of inventing one-off styles; and it runs spec-driven, autonomous quests that plan, implement, and verify a task end to end rather than just completing lines. Paired with the right references, conventions, and a verification loop, it builds real, responsive UI. This is a practical, end-to-end guide to using Qoder CLI for UI, frontend, and design-system work, and to wiring it into a structured design workflow with Open Design.", "It covers what Qoder CLI actually is, why its repo understanding and agentic quests fit design, how to set it up from zero, the reference-to-UI loop, how rules, MCP, and the repo wiki extend it, how it compares to Codex, Claude Code, Cursor, and Gemini CLI, the pitfalls that make AI output look generic, and how Open Design closes the gap as an open, local-first design layer around the agent you already use."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Qoder CLI design feedback loop: a terminal agent reading a reference image with repo-wiki context, a browser rendering the UI, and a workspace, with a feedback arrow looping back", "caption": "The core loop: Qoder CLI reads your references and repo context in the terminal, builds and verifies the UI in a real browser, and iterates against them."}, "tocLabel": "On this page", "toc": [{"id": "what-is-qoder", "label": "What Qoder CLI actually is"}, {"id": "why-design", "label": "Why agentic + repo context fit design"}, {"id": "setup", "label": "Set up Qoder CLI for design (from zero)"}, {"id": "screenshot-workflow", "label": "The reference-to-UI workflow"}, {"id": "extend", "label": "Rules, MCP, and the repo wiki"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pitfalls and the “AI slop” look"}, {"id": "open-design", "label": "Designing with Qoder CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qoder", "heading": "What Qoder CLI actually is", "blocks": [{"kind": "p", "text": "Qoder is an agentic coding platform from Alibaba — an AI development environment, available as a desktop app and a CLI, that understands real codebases and handles development tasks end to end. Qoder CLI brings that engine to the terminal: it reads your repository, edits files, runs shell commands, and works through tasks from natural language rather than just completing lines. It signs in with a Qoder account."}, {"kind": "p", "text": "For design work, two properties stand out. Qoder builds deep context on your repository — architecture, design patterns, and conventions distilled into a repository wiki — so it grounds output in your real primitives. And it runs an agentic, specification-driven workflow: you outline what you want and it plans, implements, and verifies the work, including across multiple steps."}, {"kind": "steps", "items": [{"label": "Agent and Quest modes", "body": "Agent mode is conversational pair programming with human-in-the-loop checkpoints; Quest mode delegates longer, multi-step work to an autonomous agent that plans, implements, and self-verifies — the natural place to hand off a spec-driven design task."}, {"label": "Repo wiki + MCP", "body": "Qoder distills your codebase into a repository wiki of architecture and conventions, and supports MCP servers to bring in external context like a live Figma file."}, {"label": "Model tiers", "body": "Qoder CLI exposes Lite, Efficient, and Auto tiers; Auto lets its scheduler pick a model per task, so you do not manage model selection by hand."}]}, {"kind": "ul", "items": ["Vendor: Alibaba", "Credential: Qoder account (sign in via browser, or a Qoder personal access token for non-interactive use)", "Model tiers: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Why an agentic, repo-aware agent fits design", "blocks": [{"kind": "p", "text": "Qoder CLI's design edge comes from two properties — but, as with every agent, taste still has to be supplied."}, {"kind": "steps", "items": [{"label": "Deep repository understanding", "body": "Because Qoder builds context on your whole codebase and distills it into a repo wiki, the agent reuses your existing components and tokens instead of inventing one-off styles for every screen."}, {"label": "Spec-driven, autonomous quests", "body": "Quest mode turns a written specification into a planned, implemented, and self-verified result, so a design task runs end to end rather than stopping at a first draft."}, {"label": "Conventions the agent reads", "body": "Project rules (plus the Figma MCP server) point the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagram showing design system, skill, and reference image converging into good design output", "caption": "Taste comes from three inputs you provide: a design system, a skill, and real reference images."}, {"kind": "p", "text": "The lesson is the same one every agent teaches: Qoder CLI does not have taste by default. It produces good design when you give it constraints — a design system, an aesthetic skill, and concrete references. Open Design packages exactly those inputs, which is why the two fit together (more below)."}]}, {"id": "setup", "heading": "Set up Qoder CLI for design work, from zero", "blocks": [{"kind": "p", "text": "Here is the full path from a clean machine to a Qoder CLI that can build and verify UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Five-step setup flow: install, authenticate, configure rules, add a skill, verify", "caption": "The setup sequence: install → sign in → configure project rules → add a skill → enable browser verification."}, {"kind": "steps", "items": [{"label": "Encode your design rules", "body": "Put your tokens, primitives, and conventions where the agent reads them, so output matches a brand instead of defaulting to a generic look. Qoder's repo wiki helps keep that context current."}, {"label": "Add browser verification", "body": "Wire a Playwright or browser MCP so Qoder renders in a real browser and checks its output across breakpoints instead of only confirming the build passes."}]}]}, {"id": "screenshot-workflow", "heading": "The reference-to-UI workflow", "blocks": [{"kind": "p", "text": "The highest-leverage design loop with Qoder CLI is turning a reference into working, responsive UI and iterating until it matches — leaning on the agent's repo context and a real verification loop to compare output back to the reference."}, {"kind": "ol", "items": ["Start from the clearest visual references you have — and include multiple states (desktop and mobile, hover, empty, loading), not just one hero shot.", "Be specific in the prompt; vague prompts produce generic UI even with a capable agent.", "Point Qoder at your design system and conventions, and tell it where the tokens and canonical primitives live.", "Run a dev server and have Qoder render in a real browser, resizing to breakpoints to check the result.", "Iterate by having Qoder compare its implementation back to the references — not merely confirm it builds."]}, {"kind": "p", "text": "Write the task as a clear spec and let a quest carry it through, giving concrete constraints:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Keep prompts small and focused, commit good iterations and revert bad ones (telling Qoder when you revert), so each pass builds on a clean base."}]}, {"id": "extend", "heading": "Rules, MCP, and the repo wiki", "blocks": [{"kind": "p", "text": "Three extension points make Qoder CLI practical for sustained design work, and all three map cleanly onto an open design workflow."}, {"kind": "steps", "items": [{"label": "Project rules", "body": "Encode your design conventions as durable project rules the agent reads on every run — the home for tokens, primitives, and review checklists."}, {"label": "MCP servers", "body": "MCP is the portable way to bring in design context and external tools, most relevantly the Figma MCP server, and it works across agents, not just Qoder."}, {"label": "The repo wiki", "body": "Qoder's repository wiki distills architecture and conventions automatically, so the agent keeps reusing your real components instead of relearning the codebase each task."}]}, {"kind": "p", "text": "These are portable, multi-agent capabilities — exactly the kind of thing Open Design is built to orchestrate, rather than re-create per project."}]}, {"id": "vs", "heading": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI for design", "blocks": [{"kind": "p", "text": "There is no single winner for design work — each agent has a different strength, and experienced teams stack them. A fair summary:"}, {"kind": "table", "columns": ["Agent", "Design strength", "Best for"], "rows": [["Qoder CLI", "Deep repository understanding with a repo wiki and spec-driven, autonomous quests; Lite/Efficient/Auto tiers", "Repo-context-heavy work and delegating multi-step, spec-driven builds"], ["Codex", "Strong visual polish with a frontend skill; sandboxed async builds", "Delegated async builds and portable AGENTS.md rules"], ["Claude Code", "Specific design decisions (hex, spacing, type) and codebase-aware UX", "Frontend reasoning and large-context refactors"], ["Cursor", "Visual build-and-see loop with live preview and inline edits", "Tight iterate-and-watch UI work inside an IDE"], ["Gemini CLI", "Strong multimodal image understanding and a 1M-token context; free tier", "Screenshot-heavy work and holding a whole design system in context"]]}, {"kind": "p", "text": "The recurring community verdict is that taste comes from humans: all of them default to a generic aesthetic without skills, references, and constraints. That is the real problem to solve — and it is design-tool-shaped, not model-shaped."}]}, {"id": "pitfalls", "heading": "Pitfalls, and how to avoid the “AI slop” look", "blocks": [{"kind": "p", "text": "The most common complaint about AI-generated design is that it looks generic — soft gradients, floating panels, oversized rounded corners, dramatic shadows, an Inter-and-purple vibe that “screams an AI made this.” Other reported issues include broken mobile layouts and instructions leaking into UI copy. None of these are unique to Qoder CLI; they are what happens when any agent runs without a curated design context."}, {"kind": "steps", "items": [{"label": "Add an aesthetic skill", "body": "A curated design skill forces the agent to commit to a real direction instead of the default look."}, {"label": "Verify in a real browser", "body": "Render and self-check across breakpoints so layouts do not silently break on mobile."}, {"label": "Supply tokens and references", "body": "Real design tokens and reference screenshots are the single biggest lever on output quality."}, {"label": "Encode rules the agent reads", "body": "Put “no hero cards, max two typefaces, brand-first hierarchy” style rules in project rules and the repo wiki, where the agent reads them every run."}]}, {"kind": "p", "text": "Notice that every mitigation is about giving the agent a curated design context. Maintaining that context by hand, per project, is the toil Open Design removes."}]}, {"id": "open-design", "heading": "Designing with Qoder CLI inside Open Design", "blocks": [{"kind": "p", "text": "Open Design is the open-source design layer the workflow above keeps asking for. It treats Qoder CLI as a first-party adapter and wraps it in a curated skill and design-system library, a structured render pipeline, and a local desktop UI — so the design context that makes Qoder good is there from the first run, not assembled by hand each time. Open Design is local-first, so your work stays on your own machine."}, {"kind": "ol", "items": ["Install Open Design and select Qoder CLI as your agent.", "Authenticate with your Qoder account — credentials stay on your machine and are never proxied through us.", "Pick a design system and a skill, then generate decks, prototypes, and landing pages with consistent taste.", "Every artifact and DESIGN.md file lives in your own repo, not a hosted cloud."]}, {"kind": "p", "text": "Same Qoder CLI agent, same account — plus a real, portable, open-source design workflow around it. It is local-first and Apache-2.0, so nothing about your work or your credentials leaves your machine."}]}], "faqTitle": "Frequently asked questions", "faq": [{"name": "Can Qoder CLI really do design work?", "text": "Yes — with an aesthetic skill, a design system, and real reference images in context, Qoder CLI produces production-quality, responsive UI, and its deep repository understanding helps it reuse your real components. Without that context it tends to default to a generic look, which is the gap Open Design fills."}, {"name": "How do I authenticate Qoder CLI?", "text": "Run qodercli and use /login to sign in with your Qoder account via the browser, or supply a Qoder personal access token for non-interactive environments. Open Design never proxies your credentials — the agent uses them directly."}, {"name": "What makes Qoder CLI good for design specifically?", "text": "Two things: it builds deep context on your repository — architecture, conventions, and a repo wiki — so it reuses your real primitives, and its spec-driven quests run a design task end to end. Both help, but taste still comes from the design system, skill, and references you supply."}, {"name": "What are the Lite, Efficient, and Auto model tiers?", "text": "Qoder CLI lets you pick a model tier: Lite, Efficient, or Auto. Auto lets Qoder's scheduler choose a model per task, so you do not manage model selection by hand. Pick the tier that fits the job; Auto is a sensible default."}, {"name": "How do I connect Qoder CLI to Figma?", "text": "Add the Figma MCP server to Qoder's MCP configuration. Qoder can then pull real design context — components, variables, layout data — so the generated code matches the source instead of approximating it."}, {"name": "Is Open Design affiliated with Qoder or Alibaba?", "text": "No. Qoder is a product of Alibaba; Open Design is an independent open-source project that supports it as a first-party adapter. Qoder is a trademark of its respective owner."}, {"name": "Are my files and credentials safe?", "text": "Yes — Open Design is local-first and Apache-2.0. Your files, artifacts, and DESIGN.md stay in your own repo, and your Qoder credentials are used directly by your agent, never routed through Open Design servers."}], "ctaTitle": "Design with Qoder CLI, the open way.", "ctaBody": "Bring your own Qoder account, keep every file local, and get a curated design library around the agent you already use.", "ctaActions": [{"label": "Use Qoder CLI inside Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star on GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download the desktop app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "What is Qoder CLI", "aboutBody": ["Qoder is Alibaba's agentic coding platform — an AI development environment available as a desktop app and a CLI. Qoder CLI brings that engine to the terminal: it reads your codebase, edits files, runs commands, and works through tasks from natural language.", "It builds deep context on your repository — distilled into a repo wiki — and runs spec-driven, autonomous quests, with Lite/Efficient/Auto model tiers.", "Open Design treats Qoder CLI as a first-party adapter, so the agent slots into a structured, open-source design pipeline."], "vendorLabel": "Vendor", "vendor": "Alibaba", "credentialLabel": "Credential", "credential": "Qoder account", "designTitle": "Designing with Qoder CLI", "designLead": "Qoder CLI's design strengths cluster around its repo context and agentic workflow:", "designPoints": [{"label": "Deep repository understanding", "body": "Context on architecture and conventions — distilled into a repo wiki — so output reuses your real components and tokens."}, {"label": "Spec-driven quests", "body": "Quest mode turns a written spec into a planned, implemented, and self-verified result, end to end."}, {"label": "Rules + MCP", "body": "Project rules carry your conventions; the Figma MCP server brings real design context into code."}, {"label": "Lite / Efficient / Auto", "body": "Pick a model tier per session; Auto lets Qoder's scheduler choose a model per task."}], "linksTitle": "Real-world resources", "linksLead": "Official site and docs for Qoder and Qoder CLI:", "links": [{"label": "Qoder — agentic coding platform", "href": "https://qoder.com", "source": "Qoder · Alibaba"}, {"label": "Qoder documentation", "href": "https://docs.qoder.com", "source": "Docs · Qoder"}, {"label": "Qoder CLI — Quick Start", "href": "https://docs.qoder.com/en/cli/quick-start", "source": "Docs · Qoder"}], "withOdTitle": "Qoder CLI + Open Design", "withOdLead": "Open Design is the open-source design layer around Qoder CLI: a curated skill and design-system library, a structured render pipeline, and a local desktop UI.", "withOdSteps": ["Install Open Design and select Qoder CLI as your agent.", "Authenticate with your Qoder account — credentials stay on your machine.", "Choose a design system and skill, then generate decks, prototypes, and landing pages with consistent taste.", "Artifacts and DESIGN.md files live in your own repo, not a hosted cloud."], "withOdClosing": "The same Qoder CLI agent — with a real, portable design workflow around it.", "faqTitle": "FAQ", "faq": [{"name": "Is Open Design made by Alibaba?", "text": "No. Qoder is an Alibaba product; Open Design is an independent open-source project that integrates it as a first-party adapter."}, {"name": "What do I need to sign in?", "text": "A Qoder account — sign in via browser or a Qoder access token. Open Design never proxies your credentials."}, {"name": "Is Open Design affiliated with Qoder?", "text": "No. Open Design is independent; Qoder is a trademark of its respective owner."}], "ctaTitle": "Design with Qoder CLI, the open way.", "ctaBody": "Star the repo, download the desktop app, or join the community to request an adapter."},
};
